import { BaseContainer, HeaderBase, Text, Button } from 'tradewize-component';
import { styles } from './styles';
import React, { useCallback, useEffect, useMemo, useRef } from 'react';
import { NavigationService } from '../../services/NavigationService';
import { View } from 'react-native';
import { useDispatch, useSelector } from 'react-redux';
import { SCREEN_ENUM } from '../../types/global';
import StarsRating from '../../components/StarRating';
import RatingDistribution from '../../components/RatingDistribute';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { ReviewStats, UserReview } from './types';
import { logger } from '../../utils';
import InputReview, { BottomSheetRef } from './components/InputReview';
import { RouteProp, useRoute } from '@react-navigation/native';

const ReviewScreen = () => {
  const { searchText = '' } =
    useRoute<RouteProp<{ ReviewScreen: { searchText: string } }>>().params;
  const inputReviewRef = useRef<BottomSheetRef>(null);

  const dispatch = useDispatch();
  const { t } = useAppTranslation();
  const reviewsData = useSelector(
    (state: any) => state.network.reviews.data || [],
  );
  const user: UserReview | null = useSelector(
    (state: any) => state.network.userSelected,
  );

  const fetchReviews = useCallback(async () => {
    try {
      const redux = await import('auth/redux');
      dispatch(redux.actionContainer.getReviewsAsync({ userId: user?.id }));
    } catch (error) {
      logger('error', error);
    }
  }, [dispatch, user?.id]);

  useEffect(() => {
    fetchReviews();
  }, [fetchReviews]);

  // Calculate review statistics
  const stats: ReviewStats = useMemo(() => {
    if (!reviewsData || reviewsData.length === 0) {
      return {
        averageRating: 0,
        totalReviews: 0,
      };
    }

    let totalRating = 0;

    reviewsData.forEach((review: any) => {
      totalRating += review.rating;
    });

    const averageRating = totalRating / reviewsData.length;

    return {
      averageRating,
      totalReviews: reviewsData.length,
    };
  }, [reviewsData]);

  const handleWriteReview = async () => {
    try {
      const redux = await import('auth/redux');
      if (!reviewsData?.isCrewMember) {
        dispatch(
          redux.actionContainer.showAlertAsync({
            type: 'warning',
            title: t('ERROR'),
            message: t('YOU_CAN_ONLY_REVIEW_COLLEAGUE_YOU_HAVE_WORKED_WITH'),
          }),
        );
        return;
      }
      inputReviewRef?.current?.open();
    } catch (error) {
      logger('error handleWriteReview', error);
    }
  };

  return (
    <BaseContainer style={styles.container}>
      <HeaderBase
        title={t('REVIEW')}
        onPressBack={() => {
          NavigationService.goBack();
        }}
      />
      {/* Review Summary Section */}
      <View style={styles.scrollView}>
        <View style={styles.summaryCard}>
          <View style={styles.summaryLeft}>
            <Text style={styles.averageRating}>
              {stats.averageRating.toFixed(1)}
            </Text>
            <StarsRating
              numberStars={5}
              rating={Math.round(stats.averageRating)}
              size={20}
            />
            {stats?.totalReviews && stats?.totalReviews > 0 ? (
              <Button
                onPress={() =>
                  NavigationService.navigate(SCREEN_ENUM.ReviewHistoryScreen)
                }
                variant="ghost"
                title={`${stats?.totalReviews} ${
                  stats?.totalReviews === 1 ? t('REVIEW') : t('REVIEWS')
                }`}
                textStyle={styles.reviewCount}
              />
            ) : null}
          </View>

          <View style={styles.summaryRight}>
            <RatingDistribution
              distribution={5}
              data={reviewsData.map((review: any) => review.rating)}
            />
          </View>
        </View>
      </View>

      <View style={styles.bottomButtonContainer}>
        <Button
          onPress={handleWriteReview}
          style={styles.writeReviewButton}
          fullWidth
          title={t('WRITE_A_REVIEW')}
          textStyle={styles.writeReviewButtonText}
        />
      </View>

      <InputReview
        ref={inputReviewRef}
        userId={user?.id || ''}
        searchText={searchText}
      />
    </BaseContainer>
  );
};

export default ReviewScreen;
