import {
  GET_NOTIFICATION_SUCCESS,
  GET_NOTIFICATION_FAILURE,
  GET_NOTIFICATION_PROCESSING,
  GET_NOTIFICATION_CLEAR,
  LOAD_MORE_NOTIFICATION_SUCCESS,
  LOAD_MORE_NOTIFICATION_LOADING,
  MARK_ALL_READ_SUCCESS,
  MARK_ALL_READ_FAILURE,
  MARK_ALL_READ_PROCESSING,
  MARK_AS_READ_NOTIFICATION_BY_ID_SUCCESS,
  MARK_AS_READ_NOTIFICATION_BY_ID_FAILURE,
  MARK_AS_READ_NOTIFICATION_BY_ID_PROCESSING,
  GET_NOTIFICATIONS_UNREAD_SUCCESS,
  GET_NOTIFICATIONS_UNREAD_PROCESSING,
  GET_NOTIFICATIONS_UNREAD_FAILURE,
} from './contants';
import { NotificationAction } from './actions';
import { Notification } from './types';

// Helper function to lowercase first character: JobsTab -> jobsTab
const lowercaseFirst = (str: string): string => {
  if (!str) return str;
  return str.charAt(0).toLowerCase() + str.slice(1);
};

export const initialState: Notification = {};

// Map tab name to category: Jobs = 1, Payments = 2, Others = 0
const TAB_CATEGORY_MAP: Record<string, number> = {
  JobsTab: 1,
  PaymentsTab: 2,
  OthersTab: 0,
};

export default function notificationReducer(
  state = initialState,
  action: NotificationAction,
): Notification {
  switch (action.type) {
    case GET_NOTIFICATION_SUCCESS:
      return setStateNotification(state, action.payload);
    case GET_NOTIFICATION_FAILURE:
      return setStateNotificationFailure(state, action.payload);
    case GET_NOTIFICATION_PROCESSING:
      return setStateNotificationProcessing(state, action.payload);
    case GET_NOTIFICATION_CLEAR:
      return setStateNotificationClear(state);
    case LOAD_MORE_NOTIFICATION_SUCCESS:
      return setStateLoadMoreNotification(state, action.payload);
    case LOAD_MORE_NOTIFICATION_LOADING:
      return setStateLoadMoreLoading(state, action.payload);
    case MARK_ALL_READ_SUCCESS:
      return setStateMarkAllReadSuccess(state, action.payload);
    case MARK_ALL_READ_FAILURE:
      return setStateMarkAllReadFailure(state, action.payload);
    case MARK_ALL_READ_PROCESSING:
      return setStateMarkAllReadProcessing(state, action.payload);
    case MARK_AS_READ_NOTIFICATION_BY_ID_SUCCESS:
      return setStateMarkAsReadByIdSuccess(state, action.payload);
    case MARK_AS_READ_NOTIFICATION_BY_ID_FAILURE:
      return setStateMarkAsReadByIdFailure(state, action.payload);
    case MARK_AS_READ_NOTIFICATION_BY_ID_PROCESSING:
      return setStateMarkAsReadByIdProcessing(state, action.payload);
    case GET_NOTIFICATIONS_UNREAD_SUCCESS:
      return setStateNotificationsUnread(state, action.payload);
    case GET_NOTIFICATIONS_UNREAD_FAILURE:
      return {
        ...state,
        unreadCounts: {
          ...state.unreadCounts,
          error: action.payload,
        },
      };
    case GET_NOTIFICATIONS_UNREAD_PROCESSING:
      return {
        ...state,
        unreadCounts: {
          ...state.unreadCounts,
          isLoading: action.payload,
        },
      };
    default:
      return state;
  }
}

const setStateNotification = (state: Notification, payload: any) => {
  const { categoryName, data } = payload;
  const key = lowercaseFirst(categoryName);

  return {
    ...state,
    [key]: {
      data: data,
      isLoading: false,
      isLoadingMore: false,
      isMarkingAllRead: false,
      markingAsReadId: null,
      error: null,
      currentPage: 1,
      hasMore: data?.notifications?.items?.length >= 20,
    },
  };
};

const setStateNotificationFailure = (state: Notification, payload: any) => {
  const { categoryName, error } = payload;
  const key = lowercaseFirst(categoryName);
  const categoryState = state[key] || {
    data: null,
    isLoading: false,
    isLoadingMore: false,
    isMarkingAllRead: false,
    markingAsReadId: null,
    error: null,
    currentPage: 1,
    hasMore: false,
  };
  return {
    ...state,
    [key]: {
      ...categoryState,
      isLoading: false,
      error: error,
    },
  };
};

const setStateNotificationProcessing = (state: Notification, payload: any) => {
  const { categoryName, isLoading } = payload;
  const key = lowercaseFirst(categoryName);
  const categoryState = state[key] || {
    data: null,
    isLoading: false,
    isLoadingMore: false,
    isMarkingAllRead: false,
    markingAsReadId: null,
    error: null,
    currentPage: 1,
    hasMore: false,
  };
  return {
    ...state,
    [key]: {
      ...categoryState,
      isLoading: isLoading,
    },
  };
};

const setStateLoadMoreNotification = (state: Notification, payload: any) => {
  const { categoryName, data, page } = payload;
  const key = lowercaseFirst(categoryName);
  const categoryState = state[key] || {
    data: null,
    isLoading: false,
    isLoadingMore: false,
    isMarkingAllRead: false,
    markingAsReadId: null,
    error: null,
    currentPage: 1,
    hasMore: false,
  };

  const existingItems = categoryState.data?.notifications?.items || [];
  const newItems = data?.notifications?.items || [];
  const mergedItems = [...existingItems, ...newItems];

  return {
    ...state,
    [key]: {
      ...categoryState,
      data: {
        ...data,
        notifications: {
          ...data?.notifications,
          items: mergedItems,
        },
      },
      isLoadingMore: false,
      currentPage: page,
      hasMore: newItems.length >= 20,
    },
  };
};

