// Mark single item as read
const setStateMarkAsReadByIdSuccess = (state: Notification, payload: any) => {
  const { id, categoryName } = payload;
  const key = lowercaseFirst(categoryName);
  const categoryState = state[key];

  if (!categoryState) {
    return state;
  }

  // Find and update only the specific item
  const items = categoryState.data?.notifications?.items || [];
  const targetItem = items.find((item: any) => item.id === id);
  const wasUnread = targetItem && !targetItem.isRead;
  const updatedItems = items.map((item: any) =>
    item.id === id ? { ...item, isRead: true } : item,
  );

  const currentUnread = categoryState.data?.totalUnread || 0;

  // Update unRead array: decrease unreadCount by 1 for this category
  const category = TAB_CATEGORY_MAP[categoryName];
  const updatedUnRead = (categoryState.data?.unRead || []).map((item: any) =>
    item.category === category && wasUnread
      ? { ...item, unreadCount: Math.max(0, item.unreadCount - 1) }
      : item,
  );

  return {
    ...state,
    [key]: {
      ...categoryState,
      data: {
        ...categoryState.data,
        totalUnread: wasUnread ? Math.max(0, currentUnread - 1) : currentUnread,
        unRead: updatedUnRead,
        notifications: {
          ...categoryState.data?.notifications,
          items: updatedItems,
        },
      },
      markingAsReadId: null,
      error: null,
    },
  };
};

