const setStateMarkAsReadByIdProcessing = (
  state: Notification,
  payload: any,
) => {
  const { categoryName, id } = payload;
  const key = lowercaseFirst(categoryName);
  const categoryState = state[key] || {
    data: null,
    isLoading: false,
    isLoadingMore: false,
    isMarkingAllRead: false,
    markingAsReadId: null,
    error: null,
    currentPage: 1,
    hasMore: false,
  };
  return {
    ...state,
    [key]: {
      ...categoryState,
      markingAsReadId: id,
    },
  };
};

const setStateNotificationClear = (state: Notification) => {
  return initialState;
};

// Save unread counts from API into a top-level state key
const setStateNotificationsUnread = (state: Notification, payload: any) => {
  return {
    ...state,
    unreadCounts: {
      ...state.unreadCounts,
      data: payload || null,
    },
  };
};
