import React from 'react';
import Toast from 'react-native-toast-message';
import { ScrollView, View } from 'react-native';

import {
  BaseContainer,
  HeaderBase,
  Text,
  Button,
  BottomSelector,
  SCREEN_WIDTH,
} from 'tradewize-component';
import type { BottomSelectorOption } from 'tradewize-component';
import { colors } from '../../theme';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { useJobStartChecklist } from '../../hooks/useJobStartChecklist';
import { styles } from './styles';

// Components
import MaterialSection from './components/MaterialSection';
import Checklist from '../../components/Checklist';
import OptionsSection from './components/OptionsSection';
import CommentChecklist from '../../components/CommentChecklist';
import { ChecklistMode } from '../../types/jobDetail.type';

// Types
import {
  DELIVERY_STATUS_MAP,
  MaterialStatusOption,
} from '../../types/jobStart.type';
import { SCREEN_ENUM } from '../../types/global';

const JobStartChecklistScreen: React.FC = () => {
  const { t } = useAppTranslation();

  const {
    isLoading,
    isSubmitting,
    deliveryStatus,
    groupedMaterials,
    jobStartChecklist,
    selectedOption,
    otherReason,
    isShowChecklist,
    isShowJobStartChecklist,
    isIncomplete,
    isDisabled,
    isVerifyMaterial,
    scrollViewRef,
    isSelectorVisible,
    quantityOptions,
    validationErrors,
    setIsSelectorVisible,
    setSelectedOption,
    setOtherReason,
    openQuantitySelector,
    handleSelectQuantity,
    handleSubmit,
    handleGoBack,
    handleOptionsSectionLayout,
    handleMaterialSectionLayout,
    handleChecklistSectionLayout,
    handleMaterialItemRef,
    handleClearChecklistInvalid,
    materialSectionRef,
    handleMaterialCommentPress,
  } = useJobStartChecklist();

  // Get delivery status display text
  const deliveryStatusKey =
    DELIVERY_STATUS_MAP[deliveryStatus] || 'DELIVERY_STATUS_UNDELIVERED';

  // Handle blocked option press when delivery is pending (original behavior)
  const handleDisabledOptionPress = React.useCallback(
    (option: MaterialStatusOption) => {
      if (option === MaterialStatusOption.CANT_START_MISSING) {
        Toast.show({
          type: 'error',
          text1: t('CANT_SELECT_UNTIL_MATERIAL_DELIVERED'),
          position: 'top',
          visibilityTime: 3000,
        });
      } else {
        // START_JOB, START_JOB_WITH_MISSING
        Toast.show({
          type: 'error',
          text1: t('CANT_START_JOB_DELIVERY_PENDING'),
          position: 'top',
          visibilityTime: 3000,
        });
      }
    },
    [t],
  );

  return (
    <BaseContainer>
      <HeaderBase
        title={t('JOB_START')}
        onPressBack={handleGoBack}
        backgroundColor={colors.white}
        colorIconLeft={colors.grayScale100}
        titleStyle={styles.headerTitle}
      />

      {!isLoading && (
        <>
          <ScrollView
            ref={scrollViewRef}
            style={styles.container}
            contentContainerStyle={styles.contentContainer}
            showsVerticalScrollIndicator={false}
          >
            {/* Delivery Status - Blue text */}
            <Text style={styles.deliveryStatusText}>
              {t('DELIVERY_STATUS')}: {t(deliveryStatusKey)}
            </Text>

            {/* Material + Checklist - hidden when delivery pending */}
            {isShowChecklist && (
              <>
                {/* Please verify message */}
                {!isIncomplete && (
                  <Text style={styles.verifyMessage}>
                    {t('PLEASE_VERIFY_ALL_MATERIALS')}
                  </Text>
                )}

                {/* Material Section - with layout handler + ref for scroll */}
                <View
                  ref={materialSectionRef}
                  onLayout={handleMaterialSectionLayout}
                >
                  <MaterialSection
                    groupedMaterials={groupedMaterials}
                    onQuantityPress={openQuantitySelector}
                    onCommentPress={handleMaterialCommentPress}
                    isReadOnly={isIncomplete}
                    errorMaterialIds={validationErrors.materialErrors}
                    onItemRef={handleMaterialItemRef}
                  />
                </View>

                {/* Checklist Section - only show when checklist items exist */}
                {isShowJobStartChecklist && (
                  <View onLayout={handleChecklistSectionLayout}>
                    <Checklist
                      screenKey={SCREEN_ENUM.JobStartChecklistScreen}
                      mode={ChecklistMode.JOB_START}
                      invalidItemIds={validationErrors.checklistErrors}
                      onClearInvalid={handleClearChecklistInvalid}
                    />
                  </View>
                )}
              </>
            )}

            {/* Options Section - hidden in verify material mode */}
            {!isVerifyMaterial && (
              <View onLayout={handleOptionsSectionLayout}>
                <OptionsSection
                  selectedOption={selectedOption}
                  onSelectOption={setSelectedOption}
                  otherReason={otherReason}
                  onReasonChange={setOtherReason}
                  isDisabled={isDisabled}
                  hasError={validationErrors.optionError}
                  onDisabledPress={handleDisabledOptionPress}
                />
              </View>
            )}
          </ScrollView>

          {/* Submit Button */}
          <View style={styles.submitButtonContainer}>
            <Button
              style={[
                styles.submitButton,
                isSubmitting && styles.submitButtonDisabled,
              ]}
              onPress={handleSubmit}
              disabled={isSubmitting}
            >
              <Text
                style={[
                  styles.submitButtonText,
                  isSubmitting && styles.submitButtonTextDisabled,
                ]}
              >
                {isVerifyMaterial ? t('VERIFY') : t('SUBMIT')}
              </Text>
            </Button>
          </View>
        </>
      )}

      {/* Quantity Selector - Memoized to prevent re-render during animation */}
      {React.useMemo(
        () => (
          <BottomSelector
            title={t('RECEIVED_NUMBER')}
            options={quantityOptions}
            isVisible={isSelectorVisible}
            onClose={() => setIsSelectorVisible(false)}
            onSelect={(option: BottomSelectorOption) =>
              handleSelectQuantity(option)
            }
            containerStyle={styles.selectorContainer}
            enableSearch={true}
          />
        ),
        [isSelectorVisible, quantityOptions, handleSelectQuantity],
      )}

      {/* Comment Checklist Modal - for adding comments/files (noS3 pattern) */}
      <CommentChecklist />
    </BaseContainer>
  );
};

export default JobStartChecklistScreen;
