import { useEffect } from 'react';
import { Linking } from 'react-native';
import { NavigationService } from '../services/NavigationService';
import { SCREEN_ENUM } from '../types/global';

/**
 * Deep Link URL → Screen mapping
 *
 * Mỗi entry: { path: string, screen: string, paramKey?: string }
 * - path: URL path segment (sau scheme/domain)
 * - screen: tên screen trong SCREEN_ENUM
 * - paramKey: tên param nếu là dynamic route (ví dụ: 'jobId' cho 'job/:jobId')
 */

// Screens có dynamic params (có :param trong path)
const DYNAMIC_ROUTES: {
  pattern: RegExp;
  screen: string;
  paramKey: string;
}[] = [
  {
    pattern: /^job\/(.+)$/,
    screen: SCREEN_ENUM.JobDetailScreen,
    paramKey: 'jobId',
  },
  {
    pattern: /^feedback\/(.+)$/,
    screen: SCREEN_ENUM.FeedbackDetailScreen,
    paramKey: 'feedbackId',
  },
  {
    pattern: /^message\/(.+)$/,
    screen: SCREEN_ENUM.MessageDetailScreen,
    paramKey: 'messageId',
  },
  {
    pattern: /^job-board-members\/(.+)$/,
    screen: SCREEN_ENUM.ListMemberJobsBoardScreen,
    paramKey: 'jobId',
  },
  {
    pattern: /^referal-job\/(.+)$/,
    screen: SCREEN_ENUM.ReferalCompleteJobDetailScreen,
    paramKey: 'jobId',
  },
  {
    pattern: /^job-ready-checklist\/(.+)$/,
    screen: SCREEN_ENUM.JobReadyChecklistScreen,
    paramKey: 'jobId',
  },
  {
    pattern: /^job-start-checklist\/(.+)$/,
    screen: SCREEN_ENUM.JobStartChecklistScreen,
    paramKey: 'jobId',
  },
];

// Screens tĩnh (không có params)
const STATIC_ROUTES: Record<string, string> = {
  home: SCREEN_ENUM.HomeScreen,
  'my-jobs': SCREEN_ENUM.MyJobScreen,
  messages: SCREEN_ENUM.MessageScreen,
  account: SCREEN_ENUM.AccountScreen,
  'change-password': SCREEN_ENUM.ChangePasswordScreen,
  insurance: SCREEN_ENUM.InsuranceBenefitsScreen,
  refer: SCREEN_ENUM.ReferFriendScreen,
  'payment-method': SCREEN_ENUM.PaymentMethodScreen,
  network: SCREEN_ENUM.NetworkScreen,
  review: SCREEN_ENUM.ReviewScreen,
  'review-history': SCREEN_ENUM.ReviewHistoryScreen,
  profile: SCREEN_ENUM.UserProfileScreen,
  'change-password-main': SCREEN_ENUM.ChangePasswordMainScreen,
  contract: SCREEN_ENUM.ContractScreen,
  'role-type': SCREEN_ENUM.RoleTypeScreen,
  'my-jobs-list': SCREEN_ENUM.MyJobsScreen,
  'register-company': SCREEN_ENUM.RegisterCompanyListScreen,
  'register-company-test': SCREEN_ENUM.RegisterCompanyTestScreen,
  'payment-account': SCREEN_ENUM.PaymentAccountScreen,
  'bank-info': SCREEN_ENUM.BankInfoDataScreen,
  legal: SCREEN_ENUM.LegalPolicyScreen,
  leaderboard: SCREEN_ENUM.LeaderBoardScreen,
  notification: SCREEN_ENUM.NotificationScreen,
  'quality-guide': SCREEN_ENUM.SystemQualityGuideScreen,
  'take-test': SCREEN_ENUM.TakeTheTestScreen,
  feedback: SCREEN_ENUM.FeedbackListScreen,
  'feedback-add': SCREEN_ENUM.FeedbackAddScreen,
  budget: SCREEN_ENUM.MyBudgetScreen,
  'job-board': SCREEN_ENUM.JobBoardScreen,
  materials: SCREEN_ENUM.MaterialListScreen,
  'today-jobs': SCREEN_ENUM.TodayJobsScreen,
  location: SCREEN_ENUM.YourLocationScreen,
};

const PREFIXES = [
  'tradewize://',
  'https://tradewize.biz/',
  'https://www.tradewize.biz/',
];

// Bottom tab screens cần navigate khác
const TAB_SCREENS = [
  SCREEN_ENUM.HomeScreen,
  SCREEN_ENUM.MyJobScreen,
  SCREEN_ENUM.MessageScreen,
  SCREEN_ENUM.AccountScreen,
];

/**
 * Parse deep link URL thành { screen, params }
 */
function parseDeepLink(
  url: string,
): { screen: string; params?: Record<string, string> } | null {
  // Lấy path từ URL (bỏ prefix)
  let path = url;
  for (const prefix of PREFIXES) {
    if (url.startsWith(prefix)) {
      path = url.slice(prefix.length);
      break;
    }
  }

  // Bỏ trailing slash và query string (tách query params riêng)
  const [pathPart, queryString] = path.split('?');
  const cleanPath = pathPart.replace(/\/$/, '');

  if (!cleanPath) return null;

  // Parse query params
  const queryParams: Record<string, string> = {};
  if (queryString) {
    queryString.split('&').forEach(pair => {
      const [key, value] = pair.split('=');
      if (key)
        queryParams[decodeURIComponent(key)] = decodeURIComponent(value || '');
    });
  }

  // Check static routes trước
  if (STATIC_ROUTES[cleanPath]) {
    return {
      screen: STATIC_ROUTES[cleanPath],
      params: Object.keys(queryParams).length > 0 ? queryParams : undefined,
    };
  }

  // Check dynamic routes
  for (const route of DYNAMIC_ROUTES) {
    const match = cleanPath.match(route.pattern);
    if (match) {
      return {
        screen: route.screen,
        params: { [route.paramKey]: match[1], ...queryParams },
      };
    }
  }

  return null;
}

/**
 * Kiểm tra URL có phải deep link hợp lệ không
 */
function isDeepLinkURL(url: string | null): boolean {
  if (!url) return false;
  return PREFIXES.some(prefix => url.startsWith(prefix));
}

/**
 * Navigate tới screen dựa trên parsed deep link
 */
function navigateToDeepLink(screen: string, params?: Record<string, string>) {
  console.log('[DeepLink] navigateToDeepLink:', {
    screen,
    params,
    isReady: NavigationService.isReady(),
  });
  if (!NavigationService.isReady()) {
    console.warn('[DeepLink] NavigationService not ready, skipping navigation');
    return;
  }

  // Bottom tab screens → navigate qua tab
  if (TAB_SCREENS.includes(screen)) {
    NavigationService.navigate(SCREEN_ENUM.MainBottomTabNavigator, {
      screen,
      params,
    });
    return;
  }

  // Standalone screens → navigate bình thường
  NavigationService.navigate(screen, params);
}

/**
 * Hook xử lý deep link
 *
 * Cách dùng: gọi useDeepLinking() trong component được mount khi user đã login
 *
 * Xử lý 2 case:
 * - Cold start: app mở từ deep link URL
 * - Warm start: app đang chạy, nhận deep link URL
 */
export function useDeepLinking() {
  useEffect(() => {
    // 1. Cold start: kiểm tra URL khi app mở
    const handleInitialURL = async () => {
      try {
        const url = await Linking.getInitialURL();
        console.log('[DeepLink] Initial URL:', url);
        if (isDeepLinkURL(url)) {
          const result = parseDeepLink(url!);
          console.log('[DeepLink] Parsed initial:', result);
          if (result) {
            setTimeout(() => {
              navigateToDeepLink(result.screen, result.params);
            }, 500);
          }
        }
      } catch (error) {
        console.warn('[DeepLink] Error handling initial URL:', error);
      }
    };

    handleInitialURL();

    // 2. Warm start: lắng nghe URL khi app đang chạy
    const subscription = Linking.addEventListener('url', ({ url }) => {
      console.log('[DeepLink] URL event received:', url);
      if (isDeepLinkURL(url)) {
        const result = parseDeepLink(url);
        console.log('[DeepLink] Parsed warm:', result);
        if (result) {
          navigateToDeepLink(result.screen, result.params);
        }
      }
    });

    return () => {
      subscription.remove();
    };
  }, []);
}
