import React from 'react';
import { View } from 'react-native';
import { Text, Button } from 'tradewize-component';
import FastImage from 'react-native-fast-image';
import { new_user, rating, score } from '../../../../assets/images';
import { styles } from './styles';
import { NavigationService } from '../../../../services/NavigationService';
import { logger } from '../../../../utils';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import { SCREEN_ENUM } from '../../../../types/global';
import { UserReview } from '../../../ReviewScreen/types';
import { useDispatch, useSelector } from 'react-redux';
import { EnumTypeRoomChat } from '../../../../types/message';

interface UserCardProps {
  user: UserReview;
  searchText: string;
}

export default function UserCard({ user, searchText = '' }: UserCardProps) {
  const { t } = useAppTranslation();
  const dispatch = useDispatch();
  const myProfile = useSelector((state: any) => state.auth.userProfile);
  const token = useSelector((state: any) => state.auth.token);
  const displayName = user?.fullName || user?.email || '';
  const roles =
    user?.role
      ?.filter(role => role.roleName)
      .map(role => role.roleName)
      .join(', ') || '';

  const handleContactMember = async () => {
    try {
      const redux = await import('auth/redux');
      if (!user?.roomChat) {
        dispatch(
          redux.actionContainer.createRoomChatByNetworkAsync({
            chatName: t('CHAT_WITH_NAME', { name: displayName }),
            isGroup: false,
            memberIds: [user?.id, myProfile?.accountId],
            roomType: EnumTypeRoomChat.Personal,
            searchText,
            onNavigate: (params: any) => {
              NavigationService.navigate(
                SCREEN_ENUM.MessageDetailScreen,
                params,
              );
            },
          }),
        );
      } else {
        const params = {
          chatId: user?.roomChat?.chatId,
          userId: myProfile?.accountId,
          token: token,
          chatName:
            user?.roomChat?.chatName ||
            t('CHAT_WITH_NAME', { name: displayName }),
          memberInfo: user?.roomChat?.members,
          isGroup: false,
        };
        setTimeout(() => {
          NavigationService.navigate(SCREEN_ENUM.MessageDetailScreen, params);
        }, 150);
      }
    } catch (error) {
      logger('error handleContactMember', error);
    }
  };

  return (
    <View style={styles.containerWrapper}>
      <View style={styles.container}>
        <View style={styles.avatarContainer}>
          <FastImage
            source={user?.avatar ? { uri: user?.avatar } : new_user}
            style={styles.avatar}
            resizeMode={FastImage.resizeMode.cover}
          />
        </View>
        <View style={styles.contentContainer}>
          <Text style={styles.nameText} numberOfLines={1}>
            {displayName}
          </Text>
          <Text style={styles.roleText} numberOfLines={1}>
            {roles}
          </Text>
        </View>
      </View>
      <View style={styles.scoreRatingContainer}>
        <Button
          disabled={true}
          style={[styles.scoreContainer, styles.separator]}
        >
          <FastImage source={score} style={styles.scoreIcon} />
          <Text style={styles.scoreLabel}>{t('SCORE')}</Text>
          <Text style={styles.scoreValue}>{user?.score ?? 0}</Text>
        </Button>

        <Button
          style={styles.ratingContainer}
          onPress={async () => {
            try {
              const redux = await import('auth/redux');
              dispatch(redux.actionContainer.userSelected(user));
              setTimeout(() => {
                NavigationService.navigate(SCREEN_ENUM.ReviewScreen, {
                  searchText,
                });
              }, 150);
            } catch (error) {
              logger('error handleWriteReview', error);
            }
          }}
        >
          <FastImage source={rating} style={styles.scoreIcon} />
          <Text style={styles.ratingLabel}>{t('RATING')}</Text>
          <Text style={styles.ratingValue}>
            {user?.avgRating ? user?.avgRating.toFixed(1) : '0.0'}
          </Text>
        </Button>
      </View>
      <Button
        onPress={handleContactMember}
        style={styles.contactButton}
        variant="outline"
        fullWidth
      >
        <Text style={styles.contactButtonText}>{t('CONTACT_MEMBER')}</Text>
      </Button>
    </View>
  );
}
