import { ActivityIndicator, Text, View } from 'react-native';
import { formatRelativeTime, logger } from '../../../../utils';
import { styles } from './styles';
import { NotificationItem } from '../../types';
import { ShadowedView } from 'react-native-fast-shadow';
import { shadowGlobal } from '../../../../types/global';
import { Button } from 'tradewize-component';
import { NavigationService } from '../../../../services/NavigationService';
import { useDispatch } from 'react-redux';
import { useRoute } from '@react-navigation/native';
import { colors } from '../../../../theme';

interface ListItemProps {
  item: NotificationItem;
  markingAsReadId?: string | null;
}

const ItemNotification = ({ item, markingAsReadId }: ListItemProps) => {
  const route = useRoute();
  const tabName = route.name; // e.g., "JobsTab", "PaymentsTab", "OthersTab"
  const dispatch = useDispatch();

  const onPressItem = async () => {
    // onPressMarkAsRead?.(item);
    try {
      const redux = await import('auth/redux');
      const jsonData = item?.data && JSON.parse(item?.data);
      switch (item?.type) {
        case 'YourJobChecklistIsReady':
        case 'Finish Checklist for Payment':
          NavigationService.navigate('completedJob', {
            task: {
              id: jsonData?.PurchaseOrderId,
              scheduleActivitytId: jsonData?.ScheduleActivityId,
            },
            role: {
              all: true,
            },
          });
          break;
        case 'AdminAssignJob':
          NavigationService.navigate('completedJob', {
            task: {
              id: jsonData?.purchaseOrderId,
            },
            role: {
              all: true,
            },
          });
          break;
        case 'ReInspection':
          NavigationService.navigate('completedJob', {
            task: {
              id: jsonData?.WorkOrderId,
              scheduleActivitytId: jsonData?.ScheduleActivityId,
            },
            role: {
              all: true,
            },
          });
          break;
        case 'IncompleteQIItem':
          if (jsonData?.ScheduleActivityId) {
            NavigationService.navigate('QuantityInspectionChecklist', {
              scheduleId: jsonData?.ScheduleActivityId,
            });
          }
          break;
        case 'JobAttendance':
          try {
            const jsonDataJobAttendance = item?.data && JSON.parse(item.data);
            const workOrderId = jsonDataJobAttendance?.WorkOrderId;

            if (!workOrderId) {
              logger('WorkOrderId not found in item.data');
              break;
            }

            // const res = await api.get<NotificationDetailResponse>(
            //   `${markReadNotificationDetail}/${workOrderId}`,
            // );
            // const isConfirmed = res?.data?.data?.isConfirmed;

            // if (!isConfirmed) {
            //   NavigationService.navigate('notificationDetail', {
            //     notificationItem: item,
            //   });
            // } else {
            //   // Alert.alert(t('YOU_ALREADY_CONFIRMED'));
            // }
          } catch (err) {
            logger('error fetching detail', err);
            NavigationService.navigate('notificationDetail', {
              notificationItem: item,
            });
          }
          break;
        case 'MaterialDelivered':
          const purchaseOrderId =
            jsonData?.PurchaseOrderId || jsonData?.WorkOrderId;
          if (jsonData?.ScheduleActivityId) {
            NavigationService.navigate('checkListMaterialScreen', {
              scheduleActivityId: jsonData.ScheduleActivityId,
              taskId: purchaseOrderId,
              isVerifyMaterial: false,
            });
          } else if (purchaseOrderId) {
            NavigationService.navigate('MaterialDeliveredScreen', {
              workOrderId: purchaseOrderId,
            });
          } else {
            logger('PurchaseOrderId not found in notification data');
          }
          break;

        case 'CheckInJob':
          try {
            const jsonDataCheckIn = item?.data && JSON.parse(item.data);
            const workOrderId = jsonDataCheckIn?.Id;
            logger('jsonDataCheckIn', jsonDataCheckIn);

            if (!workOrderId) {
              logger('WorkOrderId not found in item.data');
              break;
            }

            // const res = await api.get<NotificationDetailResponse>(
            //   `api/work-orders/get-my-check-in-work-order/${workOrderId}`,
            // );
            // const isCheckin = res?.data?.data?.isCheckin;

            // if (!isCheckin) {
            //   NavigationService.navigate('notificationDetail', {
            //     notificationItem: item,
            //   });
            // } else {
            //   // Alert.alert(t('YOU_ALREADY_CONFIRMED'));
            // }
          } catch (err) {
            logger('error fetching check-in detail', err);
            NavigationService.navigate('notificationDetail', {
              notificationItem: item,
            });
          }
          break;
        case 'QiComment':
          const id = jsonData?.ChecklistId;
          const CommentId = jsonData?.CommentId;
          if (id) {
            NavigationService.navigate('ChecklistDetailNoti', {
              checklistId: id,
              CommentId: CommentId,
            });
          } else {
            logger('PurchaseOrderId not found in notification data');
          }
          break;

        case 'WorkOrderCompletedAllJob':
          const Id = jsonData?.PurchaseOrderId;
          if (Id) {
            NavigationService.navigate('completedJob', {
              task: {
                id: Id,
              },
              role: { all: true },
            });
          } else {
            logger('WorkOrderId not found in notification data');
          }
          break;
        case 'LLeaderJobInProgress':
          const scheduleActivityId = jsonData?.ScheduleActivityId;
          if (scheduleActivityId) {
            NavigationService.navigate('InstallationProgressScreen', {
              scheduleActivityId: scheduleActivityId,
            });
          } else {
            logger('ScheduleActivityId not found in notification data');
          }
          break;

        case 'OverlapJobDeadline':
          NavigationService.navigate('JobOverlap');
          break;

        case 'WarrantyJobAssigned':
        case 'WarrantyNeeded':
          logger('WarrantyJobAssigned notification', item);
          NavigationService.navigate('completedJob', {
            task: {
              id: jsonData?.warrantyId,
              jobType: 2, // JOB_TYPE.WARRANTY
              scheduleActivitytId: jsonData?.scheduleActivityId,
            },
            role: {
              all: true,
            },
          });
          break;

        case 'WarrantyJobRemind':
          logger('WarrantyJobRemind notification', jsonData);
          if (jsonData?.warrantyId) {
            NavigationService.navigate('completedJob', {
              task: {
                id: jsonData?.warrantyId,
                jobType: 2, // JOB_TYPE.WARRANTY
                scheduleActivitytId: jsonData?.scheduleActivityId,
              },
              role: {
                all: true,
              },
            });
          } else {
            logger(
              'warrantyId not found in WarrantyJobRemind notification data',
              jsonData,
            );
          }
          break;

        case 'Feedback Detail':
          const feedbackId = jsonData?.feedbackId;
          if (feedbackId) {
            NavigationService.navigate('FeedbackDetail', {
              params: { feedbackId },
            });
          } else {
            logger('Feedback detail Id not found in notification data');
          }
          break;
        default:
          break;
      }
      if (!item?.isRead) {
        dispatch(
          redux.actionContainer.markAsReadAsync({
            id: item?.id,
            categoryName: tabName,
          }),
        );
      }
    } catch (error) {
      logger('error notification detail', error);
    }
  };

  return (
    <ShadowedView
      style={[
        styles.notificationCard,
        shadowGlobal,
        { opacity: item.isRead ? 0.5 : 1 },
      ]}
    >
      <Button onPress={onPressItem} style={styles.button}>
        <View style={styles.notificationHeader}>
          <Text style={styles.notificationTime}>
            {formatRelativeTime(item.sendTime)}
          </Text>
        </View>
        <Text style={styles.notificationTitle}>{item.title}</Text>
        <Text style={styles.notificationBody}>{item.body}</Text>
      </Button>

      {markingAsReadId === item.id && (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="small" color={colors.mainColorPrimary} />
        </View>
      )}
    </ShadowedView>
  );
};

export default ItemNotification;
