import i18next from 'i18next';

// Import resource mặc định
import enCommon from './locales/en/common.json';
import viCommon from './locales/vi/common.json';
import esCommon from './locales/es/common.json';
import { initReactI18next } from 'react-i18next';

// Đảm bảo i18next và initReactI18next đều tồn tại trước khi tạo instance
let i18n: ReturnType<typeof i18next.createInstance> | null;

function initializeI18n(): ReturnType<typeof i18next.createInstance> | null {
  // Kiểm tra i18next có sẵn không
  if (!i18next) {
    console.error('i18next is not available');
    return null;
  }

  // Kiểm tra initReactI18next có sẵn không
  if (!initReactI18next) {
    console.error('initReactI18next is not available');
    return null;
  }

  // Kiểm tra createInstance có sẵn không
  if (typeof i18next.createInstance !== 'function') {
    console.error('i18next.createInstance is not a function');
    return null;
  }

  try {
    // Tạo instance
    const instance = i18next.createInstance();

    if (!instance) {
      console.error('i18next.createInstance returned null or undefined');
      return null;
    }

    // Kiểm tra instance có method use không
    if (typeof instance.use !== 'function') {
      console.error('i18n instance does not have use method');
      return null;
    }

    // Khởi tạo i18n với error handling
    instance.use(initReactI18next).init({
      compatibilityJSON: 'v4',
      lng: 'en',
      fallbackLng: 'en',
      resources: {
        en: { common: enCommon },
        vi: { common: viCommon },
        es: { common: esCommon },
      },
      ns: ['common'],
      defaultNS: 'common',
      interpolation: { escapeValue: false },
    });

    return instance;
  } catch (error) {
    console.error('Error initializing i18n:', error);
    return null;
  }
}

// Khởi tạo i18n
i18n = initializeI18n();

// Nếu khởi tạo thất bại, thử sử dụng default instance của i18next
if (!i18n && i18next) {
  try {
    if (typeof i18next.use === 'function' && initReactI18next) {
      i18next.use(initReactI18next).init({
        compatibilityJSON: 'v4',
        lng: 'en',
        fallbackLng: 'en',
        resources: {
          en: { common: enCommon },
          vi: { common: viCommon },
          es: { common: esCommon },
        },
        ns: ['common'],
        defaultNS: 'common',
        interpolation: { escapeValue: false },
      });
      i18n = i18next as ReturnType<typeof i18next.createInstance>;
    }
  } catch (error) {
    console.error('Failed to initialize default i18next instance:', error);
  }
}

// Đảm bảo i18n không bao giờ là null khi export
if (!i18n) {
  // Tạo một object giả để tránh crash, nhưng sẽ log warning khi sử dụng
  i18n = {
    language: 'en',
    changeLanguage: () => {},
    t: (key: string) => key,
    options: { resources: {} },
  } as any;
}

export default i18n;
