import { useTranslation } from 'react-i18next';
import i18n from '../i18n';

export const useAppTranslation = (ns = 'common') => {
  // Đảm bảo i18n đã được khởi tạo trước khi sử dụng
  if (!i18n || typeof i18n.changeLanguage !== 'function') {
    console.warn('i18n is not properly initialized');
    // Fallback: sử dụng useTranslation không có i18n instance
    // eslint-disable-next-line react-hooks/rules-of-hooks
    return useTranslation(ns);
  }
  // eslint-disable-next-line react-hooks/rules-of-hooks
  return useTranslation(ns, { i18n });
};
