import React from 'react';
import { View } from 'react-native';
import { Text, Button } from 'tradewize-component';
import { SvgXml } from 'react-native-svg';
import { styles } from '../styles';
import { IconPdfRed } from '../../../../../assets/svg/index';
import {
  JobStartTabStatus,
  ActionData,
} from '../../../../../types/myJobs.types';
import { useAppTranslation } from '../../../../../hooks/useAppTranslation';
import { NavigationService } from '../../../../../services/NavigationService';
import { SCREEN_ENUM } from '../../../../../types/global';
import { cancelWorkOrder } from '../../../../../../../Auth/src/api/endpoint';
import Toast from 'react-native-toast-message';
import { dispatch } from '../../../../../helper';
import { useSelector } from 'react-redux';
import { RootState } from '../../../../../../../Auth/src/redux/store/types';
import {
  STATUS_MAP,
  STATUS_SORT_BY,
} from '../../../../../helper/myJob.helpter';
import CancelJobModalContent from '../../../../../components/CancelJobModalContent';

interface ActionButtonsProps {
  jumpTo?: JobStartTabStatus;
  actionData?: ActionData;
  isWarrantyJob?: boolean;
}

export default function ActionButtons({
  jumpTo,
  actionData,
  isWarrantyJob,
}: ActionButtonsProps) {
  const { t } = useAppTranslation();

  // Get filter params from Redux to refresh job list after cancel
  const lastFilterParams = useSelector(
    (state: RootState) => state.myjob?.lastFilterParams,
  );

  const handleCancelConfirm = async (cancelReason: string) => {
    try {
      const client = await import('auth/api');
      const response = await client.putRequest(cancelWorkOrder, {
        workOrderId: actionData?.workOrderId,
        cancelReason: cancelReason,
      });

      if (response.status === 200) {
        const redux = await import('auth/redux');
        dispatch(redux.actionContainer.hideCustomModal());
        Toast.show({
          type: 'success',
          text1: t('JOB_CANCELLED_SUCCESSFULLY'),
        });

        // Refresh job list after successful cancellation
        if (lastFilterParams) {
          const tabKeys = [
            JobStartTabStatus.IN_PROGRESS,
            JobStartTabStatus.NOT_STARTED,
            JobStartTabStatus.COMPLETED,
          ];
          const currentTabKey =
            tabKeys[lastFilterParams.tabIndex] ?? JobStartTabStatus.NOT_STARTED;

          dispatch(
            redux.actionContainer.getMyJobsAsync({
              Status: STATUS_MAP[currentTabKey],
              SortBy: STATUS_SORT_BY[currentTabKey],
              PageIndex: 1,
              ...(lastFilterParams.filter?.CommunityId && {
                CommunityId: lastFilterParams.filter.CommunityId,
              }),
              ...(lastFilterParams.filter?.LotNumber && {
                LotNumber: lastFilterParams.filter.LotNumber,
              }),
              ...(lastFilterParams.filter?.StartDate && {
                StartDate: lastFilterParams.filter.StartDate,
              }),
            }),
          );
        }
      } else {
        Toast.show({
          type: 'error',
          text1: (response as any).message || t('CANCEL_JOB_FAILED'),
        });
      }
    } catch (error: any) {
      Toast.show({
        type: 'error',
        text1: error?.message || t('CANCEL_JOB_FAILED'),
      });
    }
  };

  const handleCloseModal = async () => {
    const redux = await import('auth/redux');
    dispatch(redux.actionContainer.hideCustomModal());
  };

  const openCancelModal = async () => {
    const redux = await import('auth/redux');
    dispatch(
      redux.actionContainer.showCustomModal({
        visible: true,
        onClose: handleCloseModal,
        children: (
          <CancelJobModalContent
            title={t('CONFIRM')}
            description={t('ARE_YOU_SURE_YOU_WANT_TO_CANCEL_THIS_JOB?')}
            placeholder={t('ENTER_CANCEL_REASON')}
            confirmText={t('YES')}
            cancelText={t('NO')}
            errorMessage={t('REASON_CANNOT_BE_EMPTY')}
            onConfirm={handleCancelConfirm}
            onCancel={handleCloseModal}
          />
        ),
      }),
    );
  };

  const goToJobDetail = () => {
    NavigationService.navigate(SCREEN_ENUM.JobDetailScreen, {
      id: actionData?.id,
      scheduleActivityId: actionData?.scheduleActivitytId,
    });
  };

  return (
    <View style={styles.groupBtn}>
      <View style={styles.flexRow}>
        {jumpTo !== JobStartTabStatus.COMPLETED &&
          jumpTo !== JobStartTabStatus.IN_PROGRESS && (
            <Button
              variant="outline"
              style={[styles.btnDetails, styles.btnCancel, styles.equalButton]}
              onPress={openCancelModal}
            >
              <Text style={styles.btnCancelText}>{t('CANCEL')}</Text>
            </Button>
          )}

        {!isWarrantyJob && (
          <Button
            variant="outline"
            style={[styles.btnDetails, styles.btnPdf, styles.equalButton]}
            onPress={() => {}}
          >
            <Text style={styles.btnPdfText}>{t('WO')}</Text>
            <SvgXml xml={IconPdfRed()} width={18} height={18} />
          </Button>
        )}
        <Button
          variant="primary"
          style={[styles.btnDetails, styles.equalButton, styles.btnNoMargin]}
          onPress={goToJobDetail}
        >
          <Text style={styles.btnDetailsText}>{t('DETAILS')}</Text>
        </Button>
      </View>
    </View>
  );
}
