import React, { useCallback } from 'react';
import { FlatList, View } from 'react-native';
import { BaseContainer, HeaderBase } from 'tradewize-component';
import { useSelector } from 'react-redux';
import ReviewItem from './components/ReviewItem';
import { styles } from './styles';
import { Review } from '../../../../Auth/src/redux/features/network/types';
import { NavigationService } from '../../services/NavigationService';
import { useAppTranslation } from '../../hooks/useAppTranslation';

export default function ReviewHistoryScreen() {
  const { t } = useAppTranslation();
  const reviewsData = useSelector(
    (state: any) => state.network.reviews.data || [],
  );

  const keyExtractor = useCallback((item: Review) => item?.id || '', []);
  const renderReviewItem = useCallback(
    ({ item }: { item: Review }) => <ReviewItem review={item} />,
    [],
  );

  return (
    <BaseContainer style={styles.container}>
      <HeaderBase
        title={t('REVIEW_HISTORY')}
        onPressBack={() => {
          NavigationService.goBack();
        }}
      />
      <View style={styles.bodyContainer}>
        <FlatList
          data={reviewsData}
          renderItem={renderReviewItem}
          keyExtractor={keyExtractor}
          showsVerticalScrollIndicator={false}
          contentContainerStyle={styles.flatListContent}
        />
      </View>
    </BaseContainer>
  );
}
