import React, { useCallback, useEffect } from 'react';
import { BackHandler } from 'react-native';
import { BaseContainer, HeaderBase } from 'tradewize-component';
import { styles } from './styles';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { colors } from '../../theme';
import { createMaterialTopTabNavigator } from '@react-navigation/material-top-tabs';
import { useNavigation, useFocusEffect } from '@react-navigation/native';

import NotificationTabContent from './Components/NotificationTabContent';
import Tabbar from './Components/TabBar';
import { logger } from '../../utils';
import { dispatch } from '../../helper';
import { useSelector } from 'react-redux';

const Tab = createMaterialTopTabNavigator();

const lowercaseFirst = (str: string): string => {
  if (!str) return str;
  return str.charAt(0).toLowerCase() + str.slice(1);
};

// Map tab name to category: Jobs = 1, Payments = 2, Others = 0
const TAB_CATEGORY_MAP: Record<string, number> = {
  JobsTab: 1,
  PaymentsTab: 2,
  OthersTab: 0,
};

const NotificationScreen: React.FC = () => {
  const { t } = useAppTranslation();
  const navigation = useNavigation();
  const navigationState = useSelector((state: any) => state.notification);

  // Fetch data for all tabs on mount to show unread counts
  useEffect(() => {
    const fetchAllTabs = async () => {
      try {
        const redux = await import('auth/redux');
        Object.entries(TAB_CATEGORY_MAP).forEach(([tabName, category]) => {
          const key = lowercaseFirst(tabName);
          if (!navigationState?.[key]) {
            dispatch(
              redux.actionContainer.getNotificationAsync({
                page: 1,
                pageSize: 20,
                category,
                categoryName: tabName,
              }),
            );
          }
        });
      } catch (error) {
        logger('error fetchAllTabs', error);
      }
    };
    fetchAllTabs();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Handle back press - go back to parent navigator (skip nested tabs)
  const handleBackPress = useCallback(async () => {
    try {
      const redux = await import('auth/redux');
      // Get parent navigator and go back from there
      const parent = navigation.getParent();
      if (parent && parent.canGoBack()) {
        parent.goBack();
      } else if (navigation.canGoBack()) {
        navigation.goBack();
      }
      dispatch(redux.actionContainer.getNotificationClear());
    } catch (error) {
      logger('error handleBackPress', error);
    }
  }, [navigation]);

  // Handle hardware back button (Android)
  useFocusEffect(
    useCallback(() => {
      const onBackPress = () => {
        handleBackPress();
        return true; // Prevent default behavior
      };

      const subscription = BackHandler.addEventListener(
        'hardwareBackPress',
        onBackPress,
      );

      return () => subscription.remove();
    }, [handleBackPress]),
  );

  return (
    <BaseContainer
      statusBarStyle="light-content"
      backgroundColor={colors.mainColorPrimary}
      style={styles.container}
      backgroundBottomSafeAreaColor={colors.lightBlueBackground}
    >
      <HeaderBase
        title={t('NOTIFICATIONS')}
        containerStyle={styles.header}
        colorIconLeft={colors.white}
        titleStyle={styles.titleHeader}
        onPressBack={handleBackPress}
      />
      <Tab.Navigator
        screenOptions={{
          swipeEnabled: false,
          lazy: true,
        }}
        tabBar={props => <Tabbar {...props} />}
      >
        <Tab.Screen name="JobsTab" component={NotificationTabContent} />
        <Tab.Screen name="PaymentsTab" component={NotificationTabContent} />
        <Tab.Screen name="OthersTab" component={NotificationTabContent} />
      </Tab.Navigator>
    </BaseContainer>
  );
};

export default NotificationScreen;
