import { getTutorialWarning } from '../api/endpoint';
import { JobTraining, TutorialWarningType, Tutorial } from '../types/dueVideo';
import { logger } from '../utils';
import { useEffect, useState, useMemo } from 'react';

interface TutorialSection {
  title: string;
  data: Tutorial[];
}

export const useDueVideo = () => {
  const [dataTutorialWarning, setDataTutorialWarning] = useState<
    TutorialSection[]
  >([]);
  const [isLoading, setIsLoading] = useState(false);
  const [errorApi, setErrorApi] = useState<string | null>('');

  // ========== CONFIG: Thêm section mới ở đây ==========
  // Key: tên field trong data (API response)
  // Value: { jobType, titleKey } - titleKey là key dùng cho i18n translation
  const SECTION_CONFIG: Record<string, { jobType: number; titleKey: string }> =
    {
      system: { jobType: 0, titleKey: 'SYSTEM' },
      jobTraining: { jobType: 1, titleKey: 'JOB_TRAINING' },
      safetyGuid: { jobType: 2, titleKey: 'SAFETYGUID' },
      // Thêm section mới ở đây, ví dụ:
      // newField: { jobType: 3, titleKey: 'NEW_FIELD_KEY' },
    };

  // Tạo reverse map: jobType -> key
  const JOB_TYPE_TO_KEY = Object.entries(SECTION_CONFIG).reduce(
    (acc, [key, { jobType }]) => {
      acc[jobType] = key;
      return acc;
    },
    {} as Record<number, string>,
  );

  const convertDataToSectionList = (data: TutorialWarningType) => {
    try {
      // 1. Lấy tất cả keys từ data, trừ 'system' (vì system là flat array)
      const nestedFields = Object.keys(data || {}).filter(
        key => key !== 'system',
      );

      // 2. Flatten tất cả tutorials từ các trường có cấu trúc JobTraining[]
      const flatNestedTutorials = nestedFields.flatMap(field => {
        const fieldData = (data as any)?.[field] as JobTraining[] | undefined;
        return fieldData?.flatMap((i: JobTraining) => i.tutorials || []) || [];
      });

      // 2. Gom tất cả item vào chung 1 mảng (system là flat array)
      const merged = [...(data?.system || []), ...flatNestedTutorials];

      // 3. Group theo jobType (dynamic)
      const grouped = merged.reduce((acc: Record<string, any[]>, item: any) => {
        const key = JOB_TYPE_TO_KEY[item.jobType] || 'unknown';
        (acc[key] ||= []).push(item);
        return acc;
      }, {});

      // 4. Convert thành SectionList format (theo thứ tự trong config)
      const sectionList: TutorialSection[] = Object.entries(SECTION_CONFIG).map(
        ([key, { titleKey }]) => ({
          title: titleKey,
          data: grouped[key] || [],
        }),
      );

      return sectionList;
    } catch (error) {
      logger('error convertDataToSectionList', error);
      return [];
    }
  };

  useEffect(() => {
    const fetchGetTutorialWarning = async () => {
      try {
        setIsLoading(true);
        const client = await import('auth/api');
        const response = await client.getRequest(getTutorialWarning);
        if (response.status === 200) {
          const tutorialsList = convertDataToSectionList(response.data);
          setDataTutorialWarning(tutorialsList);
        } else {
          throw new Error(response.message);
        }
      } catch (e: any) {
        setDataTutorialWarning([]);
        setErrorApi(e?.message || 'Something went wrong');
        logger('error fetchGetTutorialWarning', e);
      } finally {
        setIsLoading(false);
      }
    };

    fetchGetTutorialWarning();
  }, []);

  // Tìm vị trí của item đầu tiên có jobType là 0 và 1
  const firstItemPositions = useMemo(() => {
    let positionJobType0: { sectionIndex: number; itemIndex: number } | null =
      null;
    let positionJobType1: { sectionIndex: number; itemIndex: number } | null =
      null;

    dataTutorialWarning.forEach((section, sectionIndex) => {
      if (section?.data && section.data.length > 0) {
        const firstItem = section.data[0];
        if (firstItem?.jobType === 0 && positionJobType0 === null) {
          positionJobType0 = { sectionIndex, itemIndex: 0 };
        }
        if (firstItem?.jobType === 1 && positionJobType1 === null) {
          positionJobType1 = { sectionIndex, itemIndex: 0 };
        }
      }
    });

    // Nếu không tìm thấy ở đầu section, tìm trong toàn bộ data
    if (positionJobType0 === null) {
      for (
        let sectionIndex = 0;
        sectionIndex < dataTutorialWarning.length;
        sectionIndex++
      ) {
        const section = dataTutorialWarning[sectionIndex];
        if (section?.data) {
          const itemIndex = section.data.findIndex(
            (item: Tutorial) => item?.jobType === 0,
          );
          if (itemIndex !== -1) {
            positionJobType0 = { sectionIndex, itemIndex };
            break;
          }
        }
      }
    }

    if (positionJobType1 === null) {
      for (
        let sectionIndex = 0;
        sectionIndex < dataTutorialWarning.length;
        sectionIndex++
      ) {
        const section = dataTutorialWarning[sectionIndex];
        if (section?.data) {
          const itemIndex = section.data.findIndex(
            (item: Tutorial) => item?.jobType === 1,
          );
          if (itemIndex !== -1) {
            positionJobType1 = { sectionIndex, itemIndex };
            break;
          }
        }
      }
    }

    return {
      jobType0: positionJobType0,
      jobType1: positionJobType1,
    };
  }, [dataTutorialWarning]);

  return { dataTutorialWarning, isLoading, errorApi, firstItemPositions };
};
