import React, { useState, useRef, useEffect, useMemo, ReactNode } from 'react';
import {
  View,
  TouchableOpacity,
  StyleProp,
  ViewStyle,
  Animated,
  Easing,
  PanResponder,
  Dimensions,
  Image,
  ImageSourcePropType,
  ImageStyle,
} from 'react-native';
import { SvgXml } from 'react-native-svg';
import { IconPlus, IconClose } from '../../assets/svg';
import { styles } from './styles';
import colors from '../../theme/colors';

const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');

/** Icon type - SVG string or Image source */
export type IconType = 'svg' | 'image';

export interface FABAction {
  /** Icon source - SVG string or Image require/uri */
  icon: string | ImageSourcePropType;
  /** Type of icon: 'svg' (default) or 'image' */
  iconType?: IconType;
  /** Label for the action (optional) */
  label?: string;
  /** Callback when action is pressed */
  onPress: () => void;
  /** Background color for action button */
  backgroundColor?: string;
  /** Custom style for the icon/image */
  iconStyle?: StyleProp<ImageStyle>;
  /** Custom render function for complete control over action content */
  renderContent?: (props: { iconSize: number; action: FABAction }) => ReactNode;
}

export interface FloatingActionButtonProps {
  /** Main icon when FAB is closed - SVG string or Image source */
  icon?: string | ImageSourcePropType;
  /** Type of main icon: 'svg' (default) or 'image' */
  iconType?: IconType;
  /** Icon size */
  iconSize?: number;
  /** Icon color (only for SVG) */
  iconColor?: string;
  /** Custom style for the main icon/image */
  iconStyle?: StyleProp<ImageStyle>;
  /** FAB size (width and height) */
  size?: number;
  /** Background color of the FAB */
  backgroundColor?: string;
  /** OnPress callback when FAB is pressed (used when no actions provided) */
  onPress?: () => void;
  /** Array of actions to show when FAB is expanded */
  actions?: FABAction[];
  /** Custom style for the container */
  style?: StyleProp<ViewStyle>;
  /** Shadow configuration */
  showShadow?: boolean;
  /** Disable FAB */
  disabled?: boolean;
  /** Close icon when expanded (optional) - SVG string or Image source */
  closeIcon?: string | ImageSourcePropType;
  /** Type of close icon: 'svg' (default) or 'image' */
  closeIconType?: IconType;
  /** Enable dragging like AssistiveTouch */
  draggable?: boolean;
  /** Bottom boundary offset (e.g., tab bar height) */
  bottomBoundary?: number;
  /** Top boundary offset (e.g., status bar + header height) */
  topBoundary?: number;
  /** Initial position */
  initialPosition?: { x: number; y: number };
  /** Snap to edge after drag */
  snapToEdge?: boolean;
  /** Edge padding when snapped */
  edgePadding?: number;
  /** Custom render function for main FAB content */
  renderMainContent?: (props: {
    isExpanded: boolean;
    iconSize: number;
    iconColor: string;
  }) => ReactNode;
}

const FloatingActionButton: React.FC<FloatingActionButtonProps> = ({
  icon,
  iconType = 'svg',
  iconSize = 24,
  iconColor = colors.white,
  iconStyle,
  size = 56,
  backgroundColor = colors.mainColorPrimary,
  onPress,
  actions,
  style,
  showShadow = true,
  disabled = false,
  closeIcon,
  closeIconType = 'svg',
  draggable = true,
  bottomBoundary = 100,
  topBoundary = 50,
  initialPosition,
  snapToEdge = true,
  edgePadding = 16,
  renderMainContent,
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [menuDirection, setMenuDirection] = useState<'up' | 'down'>('up');
  const rotateAnim = useRef(new Animated.Value(0)).current;
  const scaleAnim = useRef(new Animated.Value(1)).current;
  const actionsAnim = useRef<Animated.Value[]>([]).current;

  // Boundaries - ensure FAB always stays within screen with edgePadding
  // Uses useMemo to recalculate when props change
  const { minX, maxX, minY, maxY } = useMemo(() => {
    const _minX = edgePadding;
    // When size is large, maxX could be less than minX, so we use Math.max to prevent that
    const _maxX = Math.max(edgePadding, SCREEN_WIDTH - size - edgePadding);
    const _minY = topBoundary;
    const _maxY = Math.max(topBoundary, SCREEN_HEIGHT - bottomBoundary - size);
    return { minX: _minX, maxX: _maxX, minY: _minY, maxY: _maxY };
  }, [bottomBoundary, topBoundary, size, edgePadding]);

  // Use ref to store current boundaries so PanResponder can access updated values
  const boundariesRef = useRef({ minX, maxX, minY, maxY });

  // Update boundariesRef when boundaries change
  useEffect(() => {
    boundariesRef.current = { minX, maxX, minY, maxY };
  }, [minX, maxX, minY, maxY]);

  // Helper function to clamp a value between min and max
  const clamp = (value: number, min: number, max: number) =>
    Math.max(min, Math.min(value, max));

  // Calculate clamped initial position
  const getInitialPosition = () => {
    if (initialPosition) {
      return {
        x: clamp(initialPosition.x, minX, maxX),
        y: clamp(initialPosition.y, minY, maxY),
      };
    }
    // Default position: bottom-right corner, respecting boundaries
    return {
      x: maxX,
      y: clamp(SCREEN_HEIGHT - bottomBoundary - size - 20, minY, maxY),
    };
  };

  const initialPos = getInitialPosition();

  // Position animation
  const pan = useRef(new Animated.ValueXY(initialPos)).current;

  // Track current position for menu direction
  const currentPosition = useRef(initialPos);

  // Track last position for drag detection
  const dragStartPosition = useRef({ x: 0, y: 0 });
  const hasMoved = useRef(false);

  // Calculate menu direction based on position
  const updateMenuDirection = (y: number) => {
    const middleY = SCREEN_HEIGHT / 2;
    setMenuDirection(y < middleY ? 'down' : 'up');
  };

  // Initialize animation values for actions
  useEffect(() => {
    if (actions && actions.length > 0) {
      actions.forEach((_, index) => {
        if (!actionsAnim[index]) {
          actionsAnim[index] = new Animated.Value(0);
        }
      });
    }
  }, [actions, actionsAnim]);

  // Adjust FAB position when boundaries change
  useEffect(() => {
    const currentX = (pan.x as any)._value;
    const currentY = (pan.y as any)._value;

    // Clamp current position to new boundaries
    const clampedX = Math.max(minX, Math.min(currentX, maxX));
    const clampedY = Math.max(minY, Math.min(currentY, maxY));

    // If position needs adjustment, animate to new clamped position
    if (clampedX !== currentX || clampedY !== currentY) {
      currentPosition.current = { x: clampedX, y: clampedY };
      updateMenuDirection(clampedY);

      Animated.spring(pan, {
        toValue: { x: clampedX, y: clampedY },
        useNativeDriver: false,
        friction: 7,
        tension: 40,
      }).start();
    }
  }, [minX, maxX, minY, maxY]);

  // Snap to nearest edge
  const snapToNearestEdge = (x: number, y: number) => {
    if (!snapToEdge) return;

    // Use ref to get current boundary values
    const {
      minX: _minX,
      maxX: _maxX,
      minY: _minY,
      maxY: _maxY,
    } = boundariesRef.current;
    const snapX = x < SCREEN_WIDTH / 2 ? _minX : _maxX;
    const clampedY = Math.max(_minY, Math.min(y, _maxY));

    // Update current position
    currentPosition.current = { x: snapX, y: clampedY };
    updateMenuDirection(clampedY);

    Animated.spring(pan, {
      toValue: { x: snapX, y: clampedY },
      useNativeDriver: false,
      friction: 7,
      tension: 40,
    }).start();
  };

  // Pan responder for dragging
  const panResponder = useRef(
    PanResponder.create({
      onStartShouldSetPanResponder: () => draggable,
      onMoveShouldSetPanResponder: (_, gestureState) => {
        return (
          draggable &&
          (Math.abs(gestureState.dx) > 5 || Math.abs(gestureState.dy) > 5)
        );
      },
      onPanResponderGrant: () => {
        dragStartPosition.current = {
          x: (pan.x as any)._value,
          y: (pan.y as any)._value,
        };
        hasMoved.current = false;
        setIsDragging(true);

        // Close menu when start dragging
        if (isExpanded) {
          toggleExpand();
        }

        // Visual feedback - scale up
        Animated.spring(scaleAnim, {
          toValue: 1.1,
          useNativeDriver: false,
          friction: 3,
        }).start();

        pan.setOffset({
          x: (pan.x as any)._value,
          y: (pan.y as any)._value,
        });
        pan.setValue({ x: 0, y: 0 });
      },
      onPanResponderMove: (_, gestureState) => {
        if (Math.abs(gestureState.dx) > 5 || Math.abs(gestureState.dy) > 5) {
          hasMoved.current = true;
        }

        const newX = dragStartPosition.current.x + gestureState.dx;
        const newY = dragStartPosition.current.y + gestureState.dy;

        // Clamp to boundaries - use ref to get current boundary values
        const {
          minX: _minX,
          maxX: _maxX,
          minY: _minY,
          maxY: _maxY,
        } = boundariesRef.current;
        const clampedX = Math.max(_minX, Math.min(newX, _maxX));
        const clampedY = Math.max(_minY, Math.min(newY, _maxY));

        // Update current position for menu direction
        currentPosition.current = { x: clampedX, y: clampedY };

        pan.setOffset({ x: 0, y: 0 });
        pan.setValue({ x: clampedX, y: clampedY });
      },
      onPanResponderRelease: () => {
        pan.flattenOffset();
        setIsDragging(false);

        // Reset scale
        Animated.spring(scaleAnim, {
          toValue: 1,
          useNativeDriver: false,
          friction: 3,
        }).start();

        const finalX = (pan.x as any)._value;
        const finalY = (pan.y as any)._value;

        // Snap to edge
        snapToNearestEdge(finalX, finalY);

        // If barely moved, treat as tap
        if (!hasMoved.current) {
          handlePress();
        }
      },
      onPanResponderTerminate: () => {
        pan.flattenOffset();
        setIsDragging(false);

        Animated.spring(scaleAnim, {
          toValue: 1,
          useNativeDriver: false,
          friction: 3,
        }).start();
      },
    }),
  ).current;

  const handlePress = () => {
    if (disabled || isDragging) return;

    // Update menu direction before expanding
    updateMenuDirection(currentPosition.current.y);

    if (actions && actions.length > 0) {
      toggleExpand();
    } else if (onPress) {
      Animated.sequence([
        Animated.timing(scaleAnim, {
          toValue: 0.9,
          duration: 100,
          useNativeDriver: false,
        }),
        Animated.timing(scaleAnim, {
          toValue: 1,
          duration: 100,
          useNativeDriver: false,
        }),
      ]).start();
      onPress();
    }
  };

  const toggleExpand = () => {
    const toValue = isExpanded ? 0 : 1;

    Animated.timing(rotateAnim, {
      toValue,
      duration: 200,
      easing: Easing.ease,
      useNativeDriver: false,
    }).start();

    if (actions) {
      actions.forEach((_, index) => {
        Animated.timing(actionsAnim[index], {
          toValue,
          duration: 200,
          delay: isExpanded ? 0 : index * 50,
          easing: Easing.ease,
          useNativeDriver: false,
        }).start();
      });
    }

    setIsExpanded(!isExpanded);
  };

  const handleActionPress = (action: FABAction) => {
    action.onPress();
    toggleExpand();
  };

  const rotate = rotateAnim.interpolate({
    inputRange: [0, 1],
    outputRange: ['0deg', '45deg'],
  });

  // Helper function to render icon based on type
  const renderIcon = (
    iconSource: string | ImageSourcePropType,
    type: IconType,
    iconWidth: number,
    iconHeight: number,
    customStyle?: StyleProp<ImageStyle>,
  ) => {
    if (type === 'image') {
      return (
        <Image
          source={
            typeof iconSource === 'string' ? { uri: iconSource } : iconSource
          }
          style={[{ width: iconWidth, height: iconHeight }, customStyle]}
          resizeMode="contain"
        />
      );
    }
    // Default: SVG
    return (
      <SvgXml
        xml={iconSource as string}
        width={iconWidth}
        height={iconHeight}
      />
    );
  };

  // Render main FAB content
  const renderMainFABContent = () => {
    // Custom render function takes priority
    if (renderMainContent) {
      return renderMainContent({ isExpanded, iconSize, iconColor });
    }

    // Determine which icon to show
    if (isExpanded) {
      const closeIconSource = closeIcon || IconClose(iconColor);
      const closeType = closeIcon ? closeIconType : 'svg';
      return renderIcon(
        closeIconSource,
        closeType,
        iconSize,
        iconSize,
        iconStyle,
      );
    }

    const mainIconSource = icon || IconPlus(iconColor);
    const mainType = icon ? iconType : 'svg';
    return renderIcon(mainIconSource, mainType, iconSize, iconSize, iconStyle);
  };

  const renderActions = () => {
    if (!actions || actions.length === 0) return null;

    return actions.map((action, index) => {
      // Calculate offset based on menu direction
      const offset = (index + 1) * (size * 0.8 + 12);
      const translateY = actionsAnim[index]?.interpolate({
        inputRange: [0, 1],
        outputRange: [0, menuDirection === 'up' ? -offset : offset],
      });

      const opacity = actionsAnim[index]?.interpolate({
        inputRange: [0, 1],
        outputRange: [0, 1],
      });

      const actionScale = actionsAnim[index]?.interpolate({
        inputRange: [0, 1],
        outputRange: [0.5, 1],
      });

      const actionIconSize = iconSize * 0.75;

      // Render action button content
      const renderActionContent = () => {
        // Custom render function takes priority
        if (action.renderContent) {
          return action.renderContent({ iconSize: actionIconSize, action });
        }

        // Render based on icon type
        const actionIconType = action.iconType || 'svg';
        return renderIcon(
          action.icon,
          actionIconType,
          actionIconSize,
          actionIconSize,
          action.iconStyle,
        );
      };

      return (
        <Animated.View
          key={index}
          style={[
            styles.actionButton,
            {
              width: size * 0.8,
              height: size * 0.8,
              borderRadius: (size * 0.8) / 2,
              backgroundColor:
                action.backgroundColor || colors.mainColorSecondary,
              transform: [
                { translateY: translateY || 0 },
                { scale: actionScale || 1 },
              ],
              opacity: opacity || 0,
            },
            showShadow && styles.shadow,
          ]}
        >
          <TouchableOpacity
            onPress={() => handleActionPress(action)}
            style={styles.actionTouchable}
            activeOpacity={0.8}
          >
            {renderActionContent()}
          </TouchableOpacity>
        </Animated.View>
      );
    });
  };

  return (
    <Animated.View
      {...panResponder.panHandlers}
      style={[
        styles.draggableContainer,
        {
          left: pan.x,
          top: pan.y,
          transform: [{ scale: scaleAnim }],
        },
        style,
      ]}
    >
      {/* Action buttons */}
      {isExpanded && renderActions()}

      {/* Main FAB */}
      <TouchableOpacity
        onPress={handlePress}
        disabled={disabled || isDragging}
        activeOpacity={1}
        style={[
          styles.fab,
          {
            width: size,
            height: size,
            borderRadius: size / 2,
            backgroundColor: disabled ? colors.grayScale50 : backgroundColor,
          },
          showShadow && styles.shadow,
        ]}
      >
        <Animated.View style={{ transform: [{ rotate }] }}>
          {renderMainFABContent()}
        </Animated.View>
      </TouchableOpacity>
    </Animated.View>
  );
};

export default FloatingActionButton;
