import React from 'react';
import { StyleSheet, View } from 'react-native';
import { Text, Button } from 'tradewize-component';
import { SvgXml } from 'react-native-svg';
import { colors } from '../../../../theme';
import { IconCheck } from '../../../../assets/svg';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import { NavigationService } from '../../../../services/NavigationService';
import {
  ButtonActionGroup,
  EnumProjectReadyFormStatus,
  userRole,
} from '../../../../types/jobDetail.type';
import { SCREEN_ENUM } from '../../../../types/global';
import { dispatch } from '../../../../helper';
import {
  hideAlert,
  showAlert,
} from '../../../../../../Auth/src/redux/features/app/actions';

interface ActionButtonsProps {
  data: ButtonActionGroup | undefined;
}

const ActionButtons: React.FC<ActionButtonsProps> = ({ data }) => {
  const { t } = useAppTranslation();

  const isShowBtnJobStartChecklist =
    data?.roleType === userRole.LEADER && !data?.activityActualStart;

  const isShowBtnJobReady = data?.roleType !== userRole.INSPECTOR;

  const isDoneJobReady =
    data?.readyFormStatus === EnumProjectReadyFormStatus.Ready;

  const isShowBtnVerifyMaterial =
    data?.roleType === userRole.LEADER && data?.needVerifyMaterial;

  const isShowBtnVerifyMaterialVPO = data?.needVerifyVpo?.needVerify;

  const isShowBtnMaterialLeft = data?.isShowMaterialLeft;

  const handleNavigateToJobReady = () => {
    if (data?.scheduleActivityId) {
      NavigationService.navigate(SCREEN_ENUM.JobReadyChecklistScreen, {
        scheduleActivityId: data?.scheduleActivityId,
        workOrderId: data?.id,
      });
    }
  };

  return (
    <View style={styles.container}>
      {isShowBtnMaterialLeft && (
        <Button
          variant="secondary"
          style={styles.jobStartButton}
          onPress={() => {}}
        >
          <Text style={styles.jobStartButtonText}>{t('MATERIAL_LEFT')}</Text>
        </Button>
      )}

      <View style={styles.buttonJob}>
        {isShowBtnJobReady && (
          <Button
            variant="primary"
            style={styles.jobReadyButton}
            onPress={handleNavigateToJobReady}
          >
            <View style={styles.buttonContent}>
              <Text style={styles.jobReadyButtonText}>
                {t('JOB_READY_CHECKLIST')}
              </Text>
              {isDoneJobReady && (
                <View style={styles.iconWrapper}>
                  <SvgXml
                    xml={IconCheck(colors.white)}
                    width={20}
                    height={20}
                  />
                </View>
              )}
            </View>
          </Button>
        )}
        {isShowBtnJobStartChecklist && (
          <Button
            variant="secondary"
            style={[
              styles.jobStartButton,
              {
                backgroundColor: !isDoneJobReady
                  ? colors.grayScale50
                  : colors.white,
              },
            ]}
            onPress={() => {
              if (!isDoneJobReady) {
                dispatch(
                  showAlert({
                    type: 'warning',
                    visible: true,
                    title: t('WARNING'),
                    message: t(
                      'PLEASE_FINISH_PROJECT_READINESS_CHECKLIST_FIRST',
                    ),
                    onClose: async () => {
                      dispatch(hideAlert());
                    },
                  }),
                );
                return;
              }
              // Navigate to Job Start Checklist
              if (data?.scheduleActivityId && data?.id) {
                NavigationService.navigate(
                  SCREEN_ENUM.JobStartChecklistScreen,
                  {
                    scheduleActivityId: data.scheduleActivityId,
                    id: data.id,
                  },
                );
              }
            }}
          >
            <Text style={styles.jobStartButtonText}>
              {t('JOB_START_CHECKLIST')}
            </Text>
          </Button>
        )}
      </View>
      {isShowBtnVerifyMaterial && (
        <Button
          variant="secondary"
          style={styles.jobStartButton}
          onPress={() => {
            if (data?.scheduleActivityId && data?.id) {
              NavigationService.navigate(SCREEN_ENUM.JobStartChecklistScreen, {
                scheduleActivityId: data.scheduleActivityId,
                id: data.id,
                isVerifyMaterial: true,
              });
            }
          }}
        >
          <Text style={styles.jobStartButtonText}>{t('VERIFY_MATERIAL')}</Text>
        </Button>
      )}
      {isShowBtnVerifyMaterialVPO && (
        <Button
          variant="secondary"
          style={styles.jobStartButton}
          onPress={() => {}}
        >
          <Text style={styles.jobStartButtonText}>
            {t('VERIFY_MATERIAL_VPO')}
          </Text>
        </Button>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    gap: 8,
    marginBottom: 8,
  },
  buttonJob: {
    flexDirection: 'row',
    gap: 4,
    flex: 1,
  },
  jobReadyButton: {
    flex: 1,
    paddingVertical: 0,
    paddingHorizontal: 4,
    backgroundColor: colors.mainColorPrimary,
  },
  buttonContent: {
    flex: 1,
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
  },
  iconWrapper: {
    flex: 0,
    marginRight: 8,
  },
  jobReadyButtonText: {
    fontSize: 14,
    fontWeight: '600',
    color: colors.white,
    flex: 1,
    textAlign: 'center',
  },
  jobStartButton: {
    flex: 1,
    paddingVertical: 8,
    paddingHorizontal: 4,
    minHeight: 20,
    borderWidth: 1,
    borderColor: colors.mainColorPrimary,
  },
  jobStartButtonText: {
    fontSize: 14,
    fontWeight: '600',
    color: colors.mainColorPrimary,
    textDecorationLine: 'underline',
  },
});

export default ActionButtons;
