import { call, put, takeEvery } from 'redux-saga/effects';
import {
  CREATE_REVIEW_ASYNC,
  CREATE_REVIEW_FAILED,
  CREATE_REVIEW_PROGRESS,
  CREATE_REVIEW_SUCCESS,
  GET_NETWORK_ASYNC,
  GET_NETWORK_FAILED,
  GET_NETWORK_PROGRESS,
  GET_NETWORK_SUCCESS,
  GET_REVIEWS_ASYNC,
  GET_REVIEWS_FAILED,
  GET_REVIEWS_PROGRESS,
  GET_REVIEWS_SUCCESS,
  UPDATE_DATA_NETWORK,
  USER_SELECTED,
} from './contants';
import { ResponseApi } from '../../store/types';
import {
  fetchCreateReview,
  fetchNetwork,
  fetchReviews,
} from '../../../api/network';
import {
  HIDE_LOADING_OVERLAY,
  SHOW_ALERT,
  SHOW_LOADING_OVERLAY,
} from '../app/constants';
import { logger } from '../../../utils';
import i18n from '../../../i18n';
import { store } from '../..';

const getNetwork = function* (action: {
  type: string;
  payload: {
    keyword?: string;
    page?: number;
    pageSize?: number;
    isLoadMore?: boolean;
    isRefresh?: boolean;
  };
}): Generator<any, void, any> {
  try {
    yield put({ type: GET_NETWORK_PROGRESS, payload: true });
    if (!action.payload.isLoadMore && action.payload.isRefresh) {
      yield put({ type: SHOW_LOADING_OVERLAY });
    }
    const response = (yield call(fetchNetwork, {
      keyword: action.payload.keyword,
      page: action.payload.page,
      pageSize: action.payload.pageSize,
    })) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: GET_NETWORK_FAILED, payload: response.message });
      return;
    }
    if (action.payload.isLoadMore) {
      yield put({
        type: UPDATE_DATA_NETWORK,
        payload: response.data,
      });
    } else {
      yield put({ type: GET_NETWORK_SUCCESS, payload: response.data });
    }
  } catch (error) {
    logger('error getNetwork', error);
  } finally {
    yield put({ type: GET_NETWORK_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const getReviewsAsync = function* (action: {
  type: string;
  payload: { userId: string };
}): Generator<any, void, any> {
  try {
    yield put({ type: GET_REVIEWS_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const response = (yield call(fetchReviews, {
      userId: action.payload.userId,
    })) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: GET_REVIEWS_FAILED, payload: response.message });
      return;
    }

    yield put({ type: GET_REVIEWS_SUCCESS, payload: response.data });
  } catch (error) {
  } finally {
    yield put({ type: GET_REVIEWS_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const createReviewAsync = function* (action: {
  type: string;
  payload: {
    userId: string;
    rating: number;
    comments: string;
    searchText: string;
    refBottomSheetClose: any;
  };
}): Generator<any, void, any> {
  try {
    yield put({ type: CREATE_REVIEW_PROGRESS, payload: true });
    const response = (yield call(fetchCreateReview, {
      userId: action.payload.userId,
      rating: action.payload.rating,
      comments: action.payload.comments,
    })) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: CREATE_REVIEW_FAILED, payload: response.message });
      yield put({
        type: SHOW_ALERT,
        payload: {
          title: i18n.t('ERROR'),
          message: response.message,
          type: 'error',
          buttonText: i18n.t('OK'),
        },
      });
      return;
    }
    const listReviews = yield call(fetchReviews, {
      userId: action.payload.userId,
    });
    if (listReviews.status !== 200) {
      yield put({ type: CREATE_REVIEW_FAILED, payload: listReviews.message });
      yield put({
        type: SHOW_ALERT,
        payload: {
          title: i18n.t('ERROR'),
          message: listReviews.message,
          type: 'error',
          buttonText: i18n.t('OK'),
        },
      });
      return;
    }
    const storeNetwork = store.getState().network.network;
    if (storeNetwork?.data) {
      const page = storeNetwork?.data.pageIndex;
      const pageSize = storeNetwork?.data.pageSize;
      const listUserNetwork = yield call(fetchNetwork, {
        page: 1,
        pageSize: pageSize * page,
        keyword: action.payload.searchText,
      });
      if (listUserNetwork.status !== 200) {
        const userSelected = storeNetwork?.data?.items?.find(
          (item: any) => item.id === action.payload.userId,
        );
        yield put({
          type: USER_SELECTED,
          payload: { ...userSelected, isCrewMember: false },
        });
        return;
      }
      const newUserSelected = listUserNetwork?.data?.items.find(
        (item: any) => item.id === action.payload.userId,
      );
      yield put({ type: USER_SELECTED, payload: newUserSelected });
      const newNetwork = {
        ...storeNetwork.data,
        items: listUserNetwork?.data?.items || [],
      };
      yield put({
        type: GET_NETWORK_SUCCESS,
        payload: newNetwork,
      });
    }

    if (typeof action.payload.refBottomSheetClose === 'function') {
      yield call(action.payload.refBottomSheetClose);
    }
    yield put({ type: CREATE_REVIEW_SUCCESS, payload: listReviews.data });
  } catch (error) {
    logger('error createReviewAsync', error);
  } finally {
    yield put({ type: CREATE_REVIEW_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

export default function* networkSaga() {
  yield takeEvery(GET_NETWORK_ASYNC, getNetwork);
  yield takeEvery(GET_REVIEWS_ASYNC, getReviewsAsync);
  yield takeEvery(CREATE_REVIEW_ASYNC, createReviewAsync);
}
