import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { View, ScrollView } from 'react-native';
import { BaseContainer, HeaderBase, Text, Button } from 'tradewize-component';
import { useDispatch, useSelector } from 'react-redux';
import { RootState } from '../../../../Auth/src/redux/store/types';
import { actionJobDetail } from '../../../../Auth/src/redux/features/jobDetail/actions';
import { colors } from '../../theme';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { useRoute } from '@react-navigation/native';
import { NavigationService } from '../../services/NavigationService';
import { mapJobDetail } from '../../helper/jobDetail.helpter';
import { areAllChecklistsCompleted } from '../../helper/checkList.helpter';
import {
  showAlertAsync,
  hideAlertAsync,
} from '../../../../Auth/src/redux/features/app/actions';
import { actionMyJobs } from '../../../../Auth/src/redux/features/myjob/actions';
import { STATUS_MAP, STATUS_SORT_BY } from '../../helper/myJob.helpter';
import TaskInformation from './components/jobInfomation';
import Materials from './components/materials';
import OptionData from './components/optionData';
import JobChatGroup from './components/jobChatGroup';
import ActionButtons from './components/actionButtons';
import Checklist from '../../components/Checklist';
import { SCREEN_ENUM } from '../../types/global';
import { SvgXml } from 'react-native-svg';
import { IconArrowDown2 } from '../../assets/svg';
import styles from './styles';
import CommentChecklist from '../../components/CommentChecklist';

const JobDetailScreen = () => {
  const { t } = useAppTranslation();
  const route: any = useRoute();
  const [isTaskInfoExpanded, setIsTaskInfoExpanded] = useState(true);

  const dispatch = useDispatch();
  const jobDetailState = useSelector((state: RootState) => state.jobDetail);

  const workOrderData = jobDetailState?.workOrder?.data ?? null;
  const isLoadingWorkOrder = jobDetailState?.workOrder?.isLoading ?? false;
  const checklists =
    jobDetailState?.checklists?.[SCREEN_ENUM.JobDetailScreen]?.data ?? [];
  const lastFilterParams = useSelector(
    (state: RootState) => state.myjob.lastFilterParams
  );

  const { id, scheduleActivityId } = route.params || {};

  // Helper to build params for refetching jobs
  const buildMyJobsParams = useCallback(() => {
    const defaultTabIndex = 0;
    const tabIndex = lastFilterParams?.tabIndex ?? defaultTabIndex;
    const filter = lastFilterParams?.filter ?? {};

    // Map tabIndex to status
    const statusKeys = [1, 0, 2]; // IN_PROGRESS=1, NOT_STARTED=0, COMPLETED=2
    const sortByKeys = ['StartDateDesc', 'StartDateAsc', 'EndDateDesc'];

    return {
      Status: statusKeys[tabIndex] ?? 1,
      SortBy: sortByKeys[tabIndex] ?? 'StartDateDesc',
      PageIndex: 1,
      ...(filter.CommunityId && { CommunityId: filter.CommunityId }),
      ...(filter.LotNumber && { LotNumber: filter.LotNumber }),
      ...(filter.StartDate && { StartDate: filter.StartDate }),
    };
  }, [lastFilterParams]);

  const fetchJobDetail = useCallback(() => {
    if (id) {
      dispatch(
        actionJobDetail.getWorkOrderDetailAsync({
          id,
          screenKey: SCREEN_ENUM.JobDetailScreen,
        }),
      );
    }
  }, [dispatch, id]);

  const fetchChatGroup = useCallback(() => {
    if (scheduleActivityId) {
      dispatch(
        actionJobDetail.getChatGroupAsync({
          scheduleActivityId,
        }),
      );
    }
  }, [dispatch, scheduleActivityId]);

  useEffect(() => {
    fetchJobDetail();
    fetchChatGroup();
    return () => {
      dispatch(actionJobDetail.clearWorkOrderDetail());
    };
  }, [fetchJobDetail, fetchChatGroup, dispatch]);

  const handleGoBack = useCallback(() => {
    dispatch(actionJobDetail.clearWorkOrderDetail());
    NavigationService.goBack();
  }, [dispatch]);

  // Map data through helper function
  const mappedData = useMemo(() => {
    if (!workOrderData) return null;
    return mapJobDetail(workOrderData as any);
  }, [workOrderData]);

  // Check if all checklists are completed to enable/disable complete button
  const isCompleteButtonDisabled = useMemo(() => {
    return !areAllChecklistsCompleted(checklists as any);
  }, [checklists]);

  // Check if job can be updated
  const canUpdateJob = useMemo(() => {
    return (workOrderData as any)?.canUpdateChecklist?.canUpdate ?? true;
  }, [workOrderData]);

  const showReadOnlyAlert = useCallback(() => {
    dispatch(
      showAlertAsync({
        visible: true,
        title: t('WARNING'),
        type: 'warning',
        buttonText: t('OK'),
        message:
          (workOrderData as any)?.canUpdateChecklist?.reason || t('CHECKLIST_READ_ONLY'),
        onClose: () => {
          dispatch(hideAlertAsync());
        },
      }),
    );
  }, [dispatch, t, workOrderData]);

  const handleCompleteJob = useCallback(
    (isSaveOnly: boolean) => {
      if (!mappedData?.id) return;

      // Check if user can update - if not, show alert with reason
      if (!canUpdateJob) {
        showReadOnlyAlert();
        return;
      }

      // For complete action, check if all checklists are completed
      if (!isSaveOnly && isCompleteButtonDisabled) {
        return;
      }

      dispatch(
        actionJobDetail.saveWorkOrderChecklistAsync({
          id: mappedData.id,
          isCompleted: !isSaveOnly,
          onSuccess: () => {
            // Navigate back and refetch jobs with saved filter params
            NavigationService.goBack();
            const params = buildMyJobsParams();
            dispatch(actionMyJobs.getMyJobsAsync(params));
          },
        }),
      );
    },
    [
      dispatch,
      mappedData?.id,
      canUpdateJob,
      showReadOnlyAlert,
      isCompleteButtonDisabled,
      buildMyJobsParams,
    ],
  );

  if (isLoadingWorkOrder || !mappedData) {
    return (
      <BaseContainer>
        <HeaderBase
          title={t('JOB_DETAIL')}
          onPressBack={handleGoBack}
          backgroundColor={colors.white}
        />
      </BaseContainer>
    );
  }

  return (
    <BaseContainer>
      <HeaderBase
        title={t('JOB_DETAIL')}
        onPressBack={handleGoBack}
        backgroundColor={colors.white}
      />

      <ScrollView
        style={styles.container}
        contentContainerStyle={styles.contentContainer}
        showsVerticalScrollIndicator={false}
      >
        {/* Task Information Section with Header */}
        <View style={styles.taskInfoSection}>
          <Button
            style={styles.taskInfoHeader}
            onPress={() => setIsTaskInfoExpanded(!isTaskInfoExpanded)}
            activeOpacity={0.7}
          >
            <Text style={styles.taskInfoHeaderText}>
              {t('TASK_INFOMATION')}
            </Text>

            {isTaskInfoExpanded ? (
              <SvgXml
                xml={IconArrowDown2(colors.black)}
                width={16}
                height={16}
              />
            ) : (
              <SvgXml
                xml={IconArrowDown2(colors.black)}
                style={{ transform: [{ rotate: '180deg' }] }}
                width={16}
                height={16}
              />
            )}
          </Button>

          {isTaskInfoExpanded && (
            <View style={styles.taskInfoContent}>
              {/* Task Information Data */}
              <TaskInformation
                data={mappedData.taskInfomationGroup || {}}
                onPress={() => {}}
              />

              {/* Materials Section */}
              <View style={styles.materialsWrapper}>
                <Materials
                  scheduleActivityId={mappedData.scheduleActivityId || ''}
                />
              </View>

              {/* Option Cards: Crew Members, Tools, House Plan */}
              <OptionData data={mappedData.optionDataGroup} />
            </View>
          )}
        </View>

        {/* Job Chat Group */}
        <JobChatGroup />

        {/* Action Buttons */}
        <ActionButtons data={mappedData.buttonActionGroup} />

        {/* Role Checklist */}
        <Checklist screenKey={SCREEN_ENUM.JobDetailScreen} />

        {/* Bottom Action Buttons */}
        {canUpdateJob && (
          <View style={styles.bottomButtons}>
            <Button
              variant="ghost"
              style={styles.saveButton}
              onPress={() => handleCompleteJob(true)}
            >
              <Text style={styles.saveButtonText}>{t('SAVE_PROGRESS')}</Text>
            </Button>

            <Button
              variant="primary"
              style={[
                styles.completeButton,
                isCompleteButtonDisabled && styles.completeButtonDisabled,
              ]}
              onPress={() => handleCompleteJob(false)}
              disabled={isCompleteButtonDisabled}
            >
              <Text
                style={[
                  styles.completeButtonText,
                  isCompleteButtonDisabled && styles.completeButtonTextDisabled,
                ]}
              >
                {t('COMPLETE_JOB')}
              </Text>
            </Button>
          </View>
        )}
      </ScrollView>
      {/* comment modal */}
      <CommentChecklist />
    </BaseContainer>
  );
};

export default JobDetailScreen;
