import { useEffect, useState, useCallback, useMemo, useRef } from 'react';
import { useSelector } from 'react-redux';
import { ScrollView, LayoutChangeEvent, View } from 'react-native';
import Toast from 'react-native-toast-message';
import { dispatch } from '../helper';
import { RootState } from '../../../Auth/src/redux/store/types';
import {
  DeliveryStatus,
  MaterialStatusOption,
  JobStartJobCategory,
} from '../types/jobStart.type';
import {
  groupMaterialsByType,
  validateReceivedQuantities,
  validateChecklistsChecked,
  hasMissingMaterials,
  getMaterialReceivedPayload,
  isDeliveryIncomplete,
  isDeliveryPending,
  generateQuantityOptions,
} from '../helper/jobStart.helper';
import type { BottomSelectorOption } from 'tradewize-component';
import { NavigationService } from '../services/NavigationService';
import { useRoute } from '@react-navigation/native';
import { useAppTranslation } from './useAppTranslation';

// Layout positions for scroll-to-error
interface LayoutPositions {
  optionsSection: number;
  materialSection: number;
  checklistSection: number;
}

// Error state for highlighting
interface ValidationErrors {
  optionError: boolean;
  materialErrors: string[]; // Array of material IDs with errors
  checklistErrors: string[]; // Array of unchecked checklist item IDs
}
export const useJobStartChecklist = () => {
  const route: any = useRoute();

  const { scheduleActivityId, id, isVerifyMaterial } = route.params;
  const { t } = useAppTranslation();
  // Redux state
  const jobStartData = useSelector(
    (state: RootState) => state.jobDetail?.jobStartData?.data,
  );
  const isLoading = useSelector(
    (state: RootState) => state.jobDetail?.jobStartData?.isLoading ?? false,
  );
  const isSubmitting = useSelector(
    (state: RootState) => state.jobDetail?.submitJobStart?.isLoading ?? false,
  );

  // Local state
  const [selectedOption, setSelectedOption] =
    useState<MaterialStatusOption | null>(null);
  const [otherReason, setOtherReason] = useState('');

  // Validation error state
  const [validationErrors, setValidationErrors] = useState<ValidationErrors>({
    optionError: false,
    materialErrors: [],
    checklistErrors: [],
  });

  // BottomSelector state
  const [isSelectorVisible, setIsSelectorVisible] = useState(false);
  const [selectedMaterialId, setSelectedMaterialId] = useState<string | null>(
    null,
  );
  const [quantityOptions, setQuantityOptions] = useState<
    BottomSelectorOption[]
  >([]);

  // Scroll ref for validation scrolling
  const scrollViewRef = useRef<ScrollView>(null);

  // Layout positions for scroll-to-error
  const layoutPositions = useRef<LayoutPositions>({
    optionsSection: 0,
    materialSection: 0,
    checklistSection: 0,
  });

  // Per-item View refs for on-demand measurement
  const materialItemRefs = useRef<Record<string, View | null>>({});

  // Ref to section wrapper View (for relative position measurement)
  const materialSectionRef = useRef<View>(null);

  // Derived values from Redux
  const deliveryStatus =
    jobStartData?.deliveryStatus ?? DeliveryStatus.Undelivered;
  const materialChecklists = jobStartData?.materialChecklists ?? [];
  const jobStartChecklist = jobStartData?.jobStartChecklist ?? [];
  const purchaseOrderId = jobStartData?.purchaseOrderId ?? '';
  const jobCategory =
    jobStartData?.jobCategory ?? JobStartJobCategory.LaborAndMaterial;

  // UI flags
  const isLaborSKUOnly = jobCategory === JobStartJobCategory.LaborSKUOnly;
  const isIncomplete = isDeliveryIncomplete(deliveryStatus);
  const isDisabled = isDeliveryPending(deliveryStatus) && !isLaborSKUOnly;

  // Show material + checklist sections when delivery is not pending (or labor SKU only)
  const isShowChecklist =
    (deliveryStatus !== DeliveryStatus.Undelivered &&
      deliveryStatus !== DeliveryStatus.OnDelivery) ||
    isLaborSKUOnly;

  // Show job start checklist section based on isFilled from API
  // Show job start checklist section: original = !isFilled (show when NOT yet filled)
  const isShowJobStartChecklist = !(jobStartData?.isFilled ?? true);

  // Group materials by type
  const groupedMaterials = useMemo(
    () => groupMaterialsByType(materialChecklists),
    [materialChecklists],
  );

  // ============================================================================
  // Clear errors when user makes changes
  // ============================================================================

  // Clear option error when user selects an option
  useEffect(() => {
    if (selectedOption !== null && validationErrors.optionError) {
      setValidationErrors(prev => ({ ...prev, optionError: false }));
    }
  }, [selectedOption, validationErrors.optionError]);

  // ============================================================================
  // Layout handlers for scroll-to-error
  // ============================================================================

  const handleOptionsSectionLayout = useCallback((event: LayoutChangeEvent) => {
    layoutPositions.current.optionsSection = event.nativeEvent.layout.y;
  }, []);

  const handleMaterialSectionLayout = useCallback(
    (event: LayoutChangeEvent) => {
      layoutPositions.current.materialSection = event.nativeEvent.layout.y;
    },
    [],
  );

  const handleChecklistSectionLayout = useCallback(
    (event: LayoutChangeEvent) => {
      layoutPositions.current.checklistSection = event.nativeEvent.layout.y;
    },
    [],
  );

  /**
   * Get IDs of unchecked checklist items
   */
  const getUncheckedChecklistIds = useCallback(() => {
    return jobStartChecklist
      .filter(item => !item.isChecked)
      .map(item => item.id);
  }, [jobStartChecklist]);

  /**
   * Clear specific checklist item from error state (when user checks it)
   */
  const handleClearChecklistInvalid = useCallback((itemId: string) => {
    setValidationErrors(prev => ({
      ...prev,
      checklistErrors: prev.checklistErrors.filter(id => id !== itemId),
    }));
  }, []);

  /**
   * Store ref for a material item (called from MaterialItem's ref callback)
   */
  const handleMaterialItemRef = useCallback(
    (materialId: string, ref: View | null) => {
      materialItemRefs.current[materialId] = ref;
    },
    [],
  );

  /**
   * Scroll to a specific Y position
   */
  const scrollToPosition = useCallback((y: number) => {
    scrollViewRef.current?.scrollTo({
      y: Math.max(0, y - 50), // Offset for better visibility
      animated: true,
    });
  }, []);

  /**
   * Scroll to the first material item that has an error.
   *
   * Uses measureInWindow on both the error item and the section wrapper.
   * Since both Views are inside the same ScrollView content,
   * (itemScreenY - sectionScreenY) = item's offset within the section
   * — this value is constant regardless of current scroll position.
   *
   * Final: contentY = sectionY + (itemScreenY - sectionScreenY)
   */
  const scrollToFirstErrorMaterial = useCallback(
    (errorIds: string[]) => {
      if (errorIds.length === 0) return;

      const sectionNode = materialSectionRef.current;
      if (!sectionNode) {
        scrollToPosition(layoutPositions.current.materialSection);
        return;
      }

      // Find first error item with a valid ref
      for (const id of errorIds) {
        const itemRef = materialItemRefs.current[id];
        if (itemRef) {
          // Measure both Views' screen position via measureInWindow
          itemRef.measureInWindow((_ix: number, itemScreenY: number) => {
            sectionNode.measureInWindow(
              (_sx: number, sectionScreenY: number) => {
                // Relative Y within section (scroll-independent)
                const relativeY = itemScreenY - sectionScreenY;
                // Absolute Y in ScrollView content
                const contentY =
                  layoutPositions.current.materialSection + relativeY;
                scrollToPosition(contentY);
              },
            );
          });
          return; // Only scroll to the first one found
        }
      }

      // No refs found - fallback
      scrollToPosition(layoutPositions.current.materialSection);
    },
    [scrollToPosition],
  );

  // ============================================================================
  // Fetch data on mount
  // ============================================================================
  useEffect(() => {
    const fetchData = async () => {
      const redux = await import('auth/redux');
      dispatch(
        redux.actionContainer.getJobStartDataAsync({ scheduleActivityId }),
      );
    };
    fetchData();
  }, [scheduleActivityId]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      const cleanup = async () => {
        const redux = await import('auth/redux');
        dispatch(redux.actionContainer.clearJobStartData());
      };
      cleanup();
    };
  }, []);

  // ============================================================================
  // Action handlers
  // ============================================================================

  /**
   * Update material received quantity in Redux
   * Also clear error for this material
   */
  const handleQuantityChange = useCallback(
    (materialId: string, quantity: number) => {
      // Clear error for this material
      setValidationErrors(prev => ({
        ...prev,
        materialErrors: prev.materialErrors.filter(id => id !== materialId),
      }));

      const updateQuantity = async () => {
        const redux = await import('auth/redux');
        dispatch(
          redux.actionContainer.updateMaterialReceived({
            id: materialId,
            quantity,
          }),
        );
      };
      updateQuantity();
    },
    [],
  );

  /**
   * Update checklist toggle (Yes/No) in Redux
   */
  const handleChecklistToggle = useCallback(
    (itemId: string, isChecked: boolean) => {
      const updateToggle = async () => {
        const redux = await import('auth/redux');
        dispatch(
          redux.actionContainer.updateJobStartChecklistToggle({
            id: itemId,
            isChecked,
          }),
        );
      };
      updateToggle();
    },
    [],
  );

  /**
   * Open quantity selector for a material
   */
  const openQuantitySelector = useCallback(
    (materialId: string, maxQuantity: number) => {
      const options = generateQuantityOptions(maxQuantity);
      setQuantityOptions(options);
      setSelectedMaterialId(materialId);
      setIsSelectorVisible(true);
    },
    [],
  );

  /**
   * Handle select quantity from BottomSelector
   * Close selector before dispatching to avoid UI flicker during animation
   */
  const handleSelectQuantity = useCallback(
    (option: BottomSelectorOption) => {
      const materialId = selectedMaterialId;
      const quantity = Number(option.value);

      // Close selector first to avoid re-render during animation
      setIsSelectorVisible(false);
      setSelectedMaterialId(null);

      // Delay dispatch to allow selector close animation to complete (300ms)
      if (materialId) {
        setTimeout(() => {
          handleQuantityChange(materialId, quantity);
        }, 300);
      }
    },
    [selectedMaterialId, handleQuantityChange],
  );

  // ============================================================================
  // Get materials without received quantity
  // ============================================================================
  const getMaterialsWithoutQuantity = useCallback(() => {
    return materialChecklists
      .filter(
        item => item.quantitySave === null || item.quantitySave === undefined,
      )
      .map(item => item.id);
  }, [materialChecklists]);

  /**
   * Handle form submission with ordered validation
   * 1) isVerifyMaterial → skip option/checklist, validate quantities only
   * 2) Incomplete fields (option → quantities → checklist)
   * 3) Business logic (missing materials, reason)
   * 4) Auto-convert START_JOB → START_JOB_WITH_MISSING if missing items exist
   * 5) Show confirm modal → dispatch submit
   */
  const handleSubmit = useCallback(async () => {
    const redux = await import('auth/redux');

    // ========================================================================
    // isVerifyMaterial mode: skip option & checklist, validate quantities only
    // ========================================================================
    if (isVerifyMaterial) {
      if (!isIncomplete && !validateReceivedQuantities(materialChecklists)) {
        const errorMaterialIds = getMaterialsWithoutQuantity();
        setValidationErrors(prev => ({
          ...prev,
          materialErrors: errorMaterialIds,
        }));
        scrollToFirstErrorMaterial(errorMaterialIds);
        dispatch(
          redux.actionContainer.showAlert({
            title: t('PLEASE_SELECT_ALL_RECEIVED_NUMBER'),
            visible: true,
            type: 'warning',
          }),
        );
        return;
      }

      // Check for materials with null statusIsMissing (same as original code)
      const hasNullMaterial = materialChecklists.some(
        item => item.statusIsMissing === 'null',
      );
      if (hasNullMaterial) {
        dispatch(
          redux.actionContainer.showAlert({
            title: t('PLEASE_VERIFY_ALL_MATERIALS'),
            visible: true,
            type: 'warning',
          }),
        );
        return;
      }

      // Verify material payload
      setValidationErrors({
        optionError: false,
        materialErrors: [],
        checklistErrors: [],
      });
      const materialReceived = isIncomplete
        ? []
        : getMaterialReceivedPayload(materialChecklists);

      dispatch(
        redux.actionContainer.submitJobStartAsync({
          optionType: MaterialStatusOption.VERIFY_MATERIAL,
          reason: '',
          purchaseOrderId,
          scheduleActivityId,
          materialReceived,
          isNewVersion: true,
          onSuccess: () => {
            Toast.show({
              type: 'success',
              text1: t('SUCCESS'),
              text2: t('VERIFY_MATERIAL_SUCCESSFULLY'),
            });
            dispatch(redux.actionContainer.getWorkOrderDetailAsync({ id }));
            NavigationService.goBack();
          },
          onError: (err: any) => {
            console.log('Submit Verify Material error:', err);
          },
        }),
      );
      return;
    }

    // ========================================================================
    // Normal Job Start flow
    // ========================================================================
    const isCantStart =
      selectedOption === MaterialStatusOption.CANT_START_MISSING ||
      selectedOption === MaterialStatusOption.CANT_START_OTHER;

    // Step 1: Option not selected
    if (selectedOption === null) {
      setValidationErrors(prev => ({ ...prev, optionError: true }));
      scrollToPosition(layoutPositions.current.optionsSection);
      dispatch(
        redux.actionContainer.showAlert({
          title: t('PLEASE_SELECT_AN_OPTION'),
          visible: true,
          type: 'warning',
        }),
      );
      return;
    }

    // Step 2: Received quantities not filled
    // Skip if: isCantStart, incomplete delivery, OR isLaborSKUOnly (no materials)
    if (
      !isCantStart &&
      !isIncomplete &&
      !isLaborSKUOnly &&
      !validateReceivedQuantities(materialChecklists)
    ) {
      const errorMaterialIds = getMaterialsWithoutQuantity();
      setValidationErrors(prev => ({
        ...prev,
        materialErrors: errorMaterialIds,
      }));
      scrollToFirstErrorMaterial(errorMaterialIds);
      dispatch(
        redux.actionContainer.showAlert({
          title: t('PLEASE_SELECT_ALL_RECEIVED_NUMBER'),
          visible: true,
          type: 'warning',
        }),
      );
      return;
    }

    // Step 3: Checklist items not checked (skip if isCantStart)
    if (!isCantStart && !validateChecklistsChecked(jobStartChecklist)) {
      const uncheckedIds = getUncheckedChecklistIds();
      setValidationErrors(prev => ({
        ...prev,
        checklistErrors: uncheckedIds,
      }));
      scrollToPosition(layoutPositions.current.checklistSection);
      dispatch(
        redux.actionContainer.showAlert({
          title: t('PLEASE_CHECK_ALL_MATERIAL_CHECKLIST'),
          visible: true,
          type: 'warning',
        }),
      );
      return;
    }

    // Step 4: "Can't start - missing" must have missing materials
    // Skip if isLaborSKUOnly (this option is hidden in UI anyway)
    if (
      !isLaborSKUOnly &&
      selectedOption === MaterialStatusOption.CANT_START_MISSING &&
      !hasMissingMaterials(materialChecklists)
    ) {
      dispatch(
        redux.actionContainer.showAlert({
          title: t('THERE_IS_NO_MISSING_MATERIAL'),
          visible: true,
          type: 'warning',
        }),
      );
      return;
    }

    // Step 5: "Can't start - other" must have reason
    if (
      selectedOption === MaterialStatusOption.CANT_START_OTHER &&
      !otherReason.trim()
    ) {
      dispatch(
        redux.actionContainer.showAlert({
          title: t('PLEASE_FILL_THE_REASON'),
          visible: true,
          type: 'warning',
        }),
      );
      return;
    }

    // ========================================================================
    // All validations passed → build payload and show confirm
    // ========================================================================
    setValidationErrors({
      optionError: false,
      materialErrors: [],
      checklistErrors: [],
    });

    // materialReceived: empty for incomplete, cantStart, or isLaborSKUOnly
    const materialReceived =
      isIncomplete || isCantStart || isLaborSKUOnly
        ? []
        : getMaterialReceivedPayload(materialChecklists);

    // Auto-convert: if START_JOB but has missing items → START_JOB_WITH_MISSING
    // Skip auto-convert for isLaborSKUOnly (no materials to check)
    let finalOptionType = selectedOption;
    if (
      !isLaborSKUOnly &&
      selectedOption === MaterialStatusOption.START_JOB &&
      hasMissingMaterials(materialChecklists)
    ) {
      finalOptionType = MaterialStatusOption.START_JOB_WITH_MISSING;
    }

    // Build payload based on option type
    const payload =
      finalOptionType === MaterialStatusOption.CANT_START_OTHER
        ? {
            optionType: finalOptionType,
            reason: otherReason,
            purchaseOrderId,
            scheduleActivityId,
          }
        : {
            optionType: finalOptionType,
            reason: otherReason,
            purchaseOrderId,
            scheduleActivityId,
            materialReceived,
            isNewVersion: true,
          };

    console.log('payload', payload);

    // Build confirm message
    let confirmDescription = '';
    let confirmTitle = t('ARE_YOU_SURE');
    if (finalOptionType === MaterialStatusOption.START_JOB_WITH_MISSING) {
      confirmDescription = t(
        'ARE_YOU_SURE_YOU_WANT_TO_START_THE_JOB_WITH_MISSING_MATERIALS',
      );
      confirmTitle = t('START_THIS_JOB');
    } else if (finalOptionType === MaterialStatusOption.START_JOB) {
      confirmDescription = t('ARE_YOU_SURE_YOU_WANT_TO_START_THE_JOB');
      confirmTitle = t('START_THIS_JOB');
    }

    // Show confirm modal
    dispatch(
      redux.actionContainer.showConfirmModal({
        visible: true,
        title: confirmTitle,
        description: confirmDescription,
        confirmText: t('OK'),
        cancelText: t('CANCEL'),
        isShowIcon: true,
        onConfirm: () => {
          dispatch(redux.actionContainer.hideConfirmModal());
          dispatch(
            redux.actionContainer.submitJobStartAsync({
              ...payload,
              isNewVersion: true,
              onSuccess: () => {
                Toast.show({
                  type: 'success',
                  text1: t('SUCCESS'),
                  text2: t('SUBMITTED_SUCCESSFULLY'),
                });
                dispatch(redux.actionContainer.getWorkOrderDetailAsync({ id }));
                NavigationService.goBack();
              },
              onError: (err: any) => {
                console.log('Submit Job Start error:', err);
              },
            }),
          );
        },
        onCancel: () => {
          dispatch(redux.actionContainer.hideConfirmModal());
        },
      }),
    );
  }, [
    selectedOption,
    otherReason,
    purchaseOrderId,
    scheduleActivityId,
    materialChecklists,
    jobStartChecklist,
    isIncomplete,
    isVerifyMaterial,
    isLaborSKUOnly,
    id,
    scrollToPosition,
    getMaterialsWithoutQuantity,
  ]);

  /**
   * Handle material comment press - open comment modal with noS3 flow
   * Material checklist uses FormData (no S3 presigned URL)
   */
  const handleMaterialCommentPress = useCallback(async (item: any) => {
    const redux = await import('auth/redux');
    dispatch(
      redux.actionContainer.showCommentChecklistModal({
        visible: true,
        item: {
          id: item.id,
          name: item.materialName || item.name,
          responses: item.responses || [],
          files: item.files || [],
          leaderComment: item.leaderComment,
        },
        folderName: 'materialChecklist',
        screenKey: 'MaterialChecklistScreen',
        notS3: true, // noS3 - files go directly via FormData
      }),
    );
  }, []);

  /**
   * Handle go back - cleanup and navigate
   */
  const handleGoBack = useCallback(async () => {
    NavigationService.goBack();
    const redux = await import('auth/redux');
    dispatch(redux.actionContainer.clearJobStartData());
  }, []);

  return {
    // State
    isLoading,
    isSubmitting,
    deliveryStatus,
    materialChecklists,
    jobStartChecklist,
    groupedMaterials,
    selectedOption,
    otherReason,
    isLaborSKUOnly,
    isShowChecklist,
    isShowJobStartChecklist,
    isIncomplete,
    isDisabled,
    isVerifyMaterial,

    // Validation errors for highlighting
    validationErrors,

    // Refs
    scrollViewRef,

    // BottomSelector
    isSelectorVisible,
    quantityOptions,
    setIsSelectorVisible,

    // Layout handlers
    handleOptionsSectionLayout,
    handleMaterialSectionLayout,
    handleChecklistSectionLayout,
    handleMaterialItemRef,
    handleClearChecklistInvalid,
    materialSectionRef,

    // Actions
    setSelectedOption,
    setOtherReason,
    handleQuantityChange,
    openQuantitySelector,
    handleSelectQuantity,
    handleSubmit,
    handleGoBack,
    handleMaterialCommentPress,
  };
};
