import { FileSetting, Response } from './jobDetail.type';

// ============================================================================
// Enums
// ============================================================================

/**
 * Delivery status from API
 * Determines UI behavior and available options
 */
export enum DeliveryStatus {
  Undelivered = 0,
  OnDelivery = 1,
  InComplete = 2, // Material verified, readonly mode
  Delivered = 3,
}

/**
 * Options for job start submission
 */
export enum MaterialStatusOption {
  START_JOB_WITH_MISSING = 0,
  START_JOB = 1,
  CANT_START_MISSING = 2,
  CANT_START_OTHER = 3,
  VERIFY_MATERIAL = 4, // Used for isVerifyMaterial mode
}

/**
 * Leader verification status for material
 */
export enum LeaderVerifyStatus {
  NotVerified = 0,
  Verified = 1,
}

/**
 * Job category type
 */
export enum JobStartJobCategory {
  LaborAndMaterial = 0,
  LaborSKUOnly = 1,
}

// ============================================================================
// Material Checklist Item (noS3 case - uses multipart/form-data for comment)
// ============================================================================

export interface MaterialChecklistItem {
  id: string;
  colorId: string;
  materialId: string;
  materialTypeId: string;
  materialTypeName: string;
  materialCategoryName: string;
  leaderVerifyStatus: LeaderVerifyStatus;
  name: string; // "Material: Vip - Color: test0107 - Quantity: 2.5 - U/M: test1"
  colorName: string;
  colorCode: string;
  materialName: string;
  unitTypeName: string;
  unitTypeCode: string;
  size: string;
  measurements: string | null;
  quantity: number;
  verifyMaterial: number;
  quantityMissing: number | null;
  receivedQuantity: number | null;
  quantitySave: number | null;
  leaderComment: string | null;
  leaderFileIds: string[];
  files: any[];
  responses: Response[];
  statusIsMissing?: string | null;
}

// ============================================================================
// Job Start Checklist Item (S3 case - uses presigned URL for file upload)
// ============================================================================

export interface JobStartChecklistFile {
  fileId: string;
  name: string;
  key?: string;
  url: string;
  fileExtension: string;
  isPublic?: boolean;
  createdAt?: string;
}

export interface JobStartChecklistItem {
  id: string;
  scheduleActivityId: string;
  jobStartChecklistId: string;
  category: number;
  categoryName: string; // "Materials"
  orderNumber: number;
  description: string; // "Delivery location guideline 3"
  translations: {
    en: { description: string };
  };
  selectedOption: number;
  isChecked: boolean | null; // null = not selected, true = Yes, false = No
  selectedOptionName: string;
  responses: Response[];
  fileSettings: FileSetting[];
  systemFiles: JobStartChecklistFile[];
}

// ============================================================================
// API Response Data
// ============================================================================

export interface JobStartChecklistData {
  purchaseOrderId: string;
  deliveryStatus: DeliveryStatus;
  status: number;
  materialChecklists: MaterialChecklistItem[];
  jobStartChecklist: JobStartChecklistItem[];
  guidelineChecklist: any[];
  isFilled: boolean;
  verifyMaterialsOnly: boolean;
  jobCategory: JobStartJobCategory;
}

// ============================================================================
// Action Payloads
// ============================================================================

export interface GetJobStartDataPayload {
  scheduleActivityId: string;
}

export interface UpdateMaterialReceivedPayload {
  id: string;
  quantity: number;
}

export interface UpdateChecklistTogglePayload {
  id: string;
  isChecked: boolean;
}

export interface SubmitJobStartPayload {
  optionType: MaterialStatusOption;
  reason: string;
  purchaseOrderId: string;
  scheduleActivityId: string;
  materialReceived?: { id: string; quantity: number }[];
  isNewVersion: boolean;
  onSuccess?: () => void;
  onError?: (error: any) => void;
}

