import React, { useCallback } from 'react';
import { View, Text } from 'react-native';
import { styles } from './styles';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import { Button } from 'tradewize-component';
import { MaterialTopTabBarProps } from '@react-navigation/material-top-tabs';
import { PlatformPressable } from '@react-navigation/elements';
import { dispatch } from '../../../../helper';
import { logger } from '../../../../utils';
import { useSelector } from 'react-redux';

const lowercaseFirst = (str: string): string => {
  if (!str) return str;
  return str.charAt(0).toLowerCase() + str.slice(1);
};

// Map tab name to category: Jobs = 1, Payments = 2, Others = 0
const TAB_CATEGORY_MAP: Record<string, number> = {
  JobsTab: 1,
  PaymentsTab: 2,
  OthersTab: 0,
};

// interface TabbarProps {
//   activeTab: number;
//   onTabPress: (category: number) => void;
//   unreadCounts: UnreadCount[];
//   onMarkAllRead: () => void;
// }

const Tabbar: React.FC<MaterialTopTabBarProps> = ({
  // unreadCounts,
  // onMarkAllRead,
  state,
  descriptors,
  navigation,
  position,
}) => {
  const { t } = useAppTranslation();

  //   const getUnreadCount = (category: number): number => {
  //     const unread = unreadCounts.find(item => item.category === category);
  //     return unread?.unreadCount || 0;
  //   };
  const notiState = useSelector((state: any) => state.notification);

  const onMarkAllRead = useCallback(async () => {
    try {
      const currentTab = state.routes[state.index].name;
      const redux = await import('auth/redux');
      dispatch(
        redux.actionContainer.markAllReadAsync({
          category: TAB_CATEGORY_MAP[currentTab] ?? 0,
          categoryName: currentTab,
        }),
      );
    } catch (error) {
      logger('error onMarkAllRead', error);
    }
  }, [state.index, state.routes]);

  return (
    <>
      <View style={styles.tabContainer}>
        <View style={styles.tabs}>
          {state.routes.map((route: any, index: number) => {
            const { options } = descriptors[route.key];
            const label =
              options.tabBarLabel !== undefined
                ? options.tabBarLabel
                : options.title !== undefined
                ? options.title
                : route.name;

            const isFocused = state.index === index;

            const onPress = () => {
              const event = navigation.emit({
                type: 'tabPress',
                target: route.key,
                canPreventDefault: true,
              });

              if (!isFocused && !event.defaultPrevented) {
                navigation.navigate(route.name, route.params);
              }
            };

            const onLongPress = () => {
              navigation.emit({
                type: 'tabLongPress',
                target: route.key,
              });
            };

            const category = TAB_CATEGORY_MAP[route.name];
            const key = lowercaseFirst(route.name);
            const unReadArr = notiState[key]?.data?.unRead || [];
            const unreadCount =
              unReadArr.find((item: any) => item.category === category)
                ?.unreadCount || 0;

            return (
              <PlatformPressable
                key={route.key}
                style={[styles.tab, isFocused && styles.tabActive]}
                onPress={onPress}
                onLongPress={onLongPress}
              >
                <View style={styles.tabTextContainer}>
                  <Text
                    style={[styles.tabText, isFocused && styles.tabTextActive]}
                  >
                    {label}
                  </Text>
                  {unreadCount > 0 && (
                    <View
                      style={[
                        styles.tabBadge,
                        isFocused && styles.tabBadgeActive,
                      ]}
                    >
                      <Text
                        style={[
                          styles.tabBadgeText,
                          isFocused && styles.tabBadgeTextActive,
                        ]}
                      >
                        {unreadCount}
                      </Text>
                    </View>
                  )}
                </View>
              </PlatformPressable>
            );
          })}
        </View>
      </View>
      <Button
        onPress={onMarkAllRead}
        variant="ghost"
        title={t('MARK_ALL_AS_READ')}
        textStyle={styles.markAllReadText}
        style={styles.markAllReadButton}
      />
    </>
  );
};

export default Tabbar;
