import {
  ActivityIndicator,
  Image,
  StatusBar,
  Text as RNText,
  View,
} from 'react-native';
import Header from './components/Header';
import { styles } from './styles';
import { Marker, PROVIDER_GOOGLE } from 'react-native-maps';
import { colors } from '../../theme';
import { ListJobsRef } from './components/ListJobs';
import { Button } from 'tradewize-component';
import { logoExtra, playInstructionalVideos } from '../../assets/images';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import React, {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { useJobBoard } from '../../hooks/useJobBoard';
import { useDispatch, useSelector } from 'react-redux';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { ShadowedView } from 'react-native-fast-shadow';
import { shadowGlobal } from '../../types/global';
import MapView from 'react-native-map-clustering';
import { formatDateToMMDD, logger } from '../../utils';
import RNMapView from 'react-native-maps';
import {
  GooglePlaceData,
  GooglePlaceDetail,
} from 'react-native-google-places-autocomplete';
import Filter from './components/Filter';
import { FilterRef } from './components/Filter/types';
import { handleRegister } from '../../helper/JobsBoard';

import ListJobs from './components/ListJobs';
import CalenderPicker from './components/CalenderPicker';

// Mức zoom mà tại đó tất cả marker sẽ được tách ra riêng lẻ
const SPLIT_ZOOM_THRESHOLD = 14;

// Giới hạn số lượng marker riêng lẻ để tránh lag
const MAX_VISIBLE_MARKERS = 50;

// Debounce delay cho region change (ms)
const REGION_CHANGE_DEBOUNCE = 150;

// Tính zoom level từ region
const getZoomLevel = (region: any): number => {
  if (!region || !region.longitudeDelta) return 0;
  return Math.round(Math.log(360 / region.longitudeDelta) / Math.LN2);
};

// Memoized marker component - tránh re-render không cần thiết
const JobMarker = React.memo(
  ({
    markerKey,
    coordinate,
    jobs,
    logoSource,
    formatDate,
    jobsLabel,
  }: {
    markerKey: string;
    coordinate: { latitude: number; longitude: number };
    jobs: any[];
    logoSource: any;
    formatDate: (date: string) => string;
    jobsLabel: string;
  }) => {
    const firstJob = jobs[0];
    // Android: cần tracksViewChanges=true cho đến khi image load xong
    // để marker không bị snapshot trống
    const [imageLoaded, setImageLoaded] = useState(false);
    return (
      <Marker
        key={markerKey}
        coordinate={coordinate}
        tracksViewChanges={!imageLoaded}
      >
        <View style={styles.markerContainer}>
          <Image
            source={logoSource}
            style={styles.markerImage}
            resizeMode="contain"
            onLoad={() => setImageLoaded(true)}
          />
          <RNText style={styles.timeMarker}>
            {jobs.length === 1 && firstJob?.estStartDate
              ? formatDate(firstJob.estStartDate)
              : `${jobs.length} ${jobsLabel}`}
          </RNText>
        </View>
      </Marker>
    );
  },
);

const JobBoardScreen = () => {
  const { t } = useAppTranslation();
  const insets = useSafeAreaInsets();
  const dispatch = useDispatch();

  const mapRef = useRef<RNMapView>(null);
  const filterRef = useRef<FilterRef>(null);
  const listJobsRef = useRef<ListJobsRef>(null);

  const [headerHeight, setHeaderHeight] = useState(0);
  const [region, setRegion] = useState(null);
  const [zoomLevel, setZoomLevel] = useState(0);
  const regionDebounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const isLoadingFav = useSelector(
    (state: any) => state.jobBoard.houseHasJobWorker.isLoading,
  );
  const allJobs = useSelector(
    (state: any) => state.jobBoard.houseHasJobWorker.data || [],
  );
  const isLoading = useSelector((state: any) => state.app.loadingOverlay);
  const dataMedia = useSelector((state: any) => state.app.dataMedia);
  const language = useSelector((state: any) => state.app.language);

  const [isFocused, setIsFocused] = useState(false);
  const [isFocusedFilter, setIsFocusedFilter] = useState(false);
  const [isFocusedCalendar, setIsFocusedCalendar] = useState(false);
  const [rangeDate, setRangeDate] = useState<{
    startDate: string;
    endDate: string;
  }>({
    startDate: '',
    endDate: '',
  });

  const { currentLocation, filter, setFilter } = useJobBoard({
    mapRef: mapRef as React.RefObject<RNMapView>,
  });

  const shouldSplitMarkers = zoomLevel >= SPLIT_ZOOM_THRESHOLD;

  // Chỉ render markers trong viewport và giới hạn số lượng
  const visibleMarkers = useMemo(() => {
    if (!region || !allJobs.length) return [];

    const { latitude, longitude, latitudeDelta, longitudeDelta } = region;

    // Lọc jobs trong viewport
    const jobsInView = allJobs.filter((job: any) => {
      if (!job.location?.latitude || !job.location?.longitude) return false;

      const lat = job.location.latitude;
      const lng = job.location.longitude;

      const inLatRange =
        lat >= latitude - latitudeDelta / 2 &&
        lat <= latitude + latitudeDelta / 2;

      const inLngRange =
        lng >= longitude - longitudeDelta / 2 &&
        lng <= longitude + longitudeDelta / 2;

      return inLatRange && inLngRange;
    });

    // Khi zoom đủ gần (shouldSplitMarkers) và có job được chọn tại 1 location có nhiều job
    // -> chỉ giữ lại các job đã chọn tại location đó
    // Khi zoom ra hoặc bỏ chọn hết -> hiển thị lại tất cả
    let filteredJobs: any[] = jobsInView;

    if (shouldSplitMarkers) {
      const groupedByCoord = new Map<string, any[]>();
      jobsInView.forEach((job: any) => {
        const key = `${job.location.latitude}-${job.location.longitude}`;
        if (!groupedByCoord.has(key)) {
          groupedByCoord.set(key, []);
        }
        groupedByCoord.get(key)!.push(job);
      });

      // Lọc: nếu location có ít nhất 1 job isChecked -> chỉ giữ checked jobs
      const result: any[] = [];
      groupedByCoord.forEach(jobs => {
        const checkedJobs = jobs.filter((j: any) => j.isChecked);
        if (checkedJobs.length > 0) {
          // Có job được chọn -> chỉ hiển thị job đã chọn
          result.push(...checkedJobs);
        } else {
          // Không có job nào được chọn -> hiển thị tất cả
          result.push(...jobs);
        }
      });
      filteredJobs = result;
    }

    // Khi zoom đủ lớn -> tách từng marker riêng lẻ
    if (shouldSplitMarkers) {
      // Giới hạn số lượng marker để tránh lag
      const limitedJobs = filteredJobs.slice(0, MAX_VISIBLE_MARKERS);

      // Đếm số job tại mỗi toạ độ để tính offset
      const coordCount = new Map<string, number>();
      const coordIndex = new Map<string, number>();

      limitedJobs.forEach((job: any) => {
        const key = `${job.location.latitude}-${job.location.longitude}`;
        coordCount.set(key, (coordCount.get(key) || 0) + 1);
      });

      return limitedJobs.map((job: any) => {
        const key = `${job.location.latitude}-${job.location.longitude}`;
        const total = coordCount.get(key) || 1;
        const index = coordIndex.get(key) || 0;
        coordIndex.set(key, index + 1);

        let offsetLat = 0;
        let offsetLng = 0;

        // Nếu có nhiều job cùng toạ độ -> xoè ra hình tròn
        if (total > 1) {
          const angle = (2 * Math.PI * index) / total;
          // Offset tỷ lệ với latitudeDelta để phù hợp với mức zoom
          const offsetRadius = latitudeDelta * 0.03;
          offsetLat = offsetRadius * Math.cos(angle);
          offsetLng = offsetRadius * Math.sin(angle);
        }

        return {
          key: `${job.id || key}-${index}`,
          location: {
            latitude: job.location.latitude + offsetLat,
            longitude: job.location.longitude + offsetLng,
          },
          jobs: [job], // Mỗi marker chỉ chứa 1 job
        };
      });
    }

    // Khi zoom nhỏ -> group theo location như cũ
    const map = new Map<string, any[]>();

    filteredJobs.forEach((job: any) => {
      const key = `${job.location.latitude}-${job.location.longitude}`;

      if (!map.has(key)) {
        map.set(key, []);
      }

      map.get(key)!.push(job);
    });

    // convert sang array để render
    return Array.from(map.entries()).map(([key, jobs]) => ({
      key, // dùng làm React key
      location: jobs[0].location,
      jobs,
    }));
  }, [region, allJobs, shouldSplitMarkers]);

  const isDisabledButtonRegister = useMemo(() => {
    return !allJobs?.some((job: any) => job?.isChecked);
  }, [allJobs]);

  // Lưu region trước khi zoom để hoàn trả khi bỏ chọn
  const previousRegionRef = useRef<any>(null);

  // Danh sách các job đang được chọn
  const checkedJobs = useMemo(() => {
    return allJobs.filter((job: any) => job?.isChecked);
  }, [allJobs]);

  // Zoom map khi có job được chọn
  useEffect(() => {
    if (checkedJobs.length > 0) {
      // Lưu region hiện tại trước khi zoom (chỉ lưu lần đầu chọn)
      if (!previousRegionRef.current && region) {
        previousRegionRef.current = region;
      }

      const validJobs = checkedJobs.filter(
        (job: any) => job.location?.latitude && job.location?.longitude,
      );

      if (validJobs.length === 0) return;

      if (validJobs.length === 1) {
        // 1 job -> zoom gần nhất có thể tới vị trí đó
        mapRef.current?.animateToRegion(
          {
            latitude: validJobs[0].location.latitude,
            longitude: validJobs[0].location.longitude,
            latitudeDelta: 0.005,
            longitudeDelta: 0.005,
          },
          800,
        );
      } else {
        // Nhiều jobs -> fitToCoordinates để hiển thị tất cả
        const coordinates = validJobs.map((job: any) => ({
          latitude: job.location.latitude,
          longitude: job.location.longitude,
        }));

        mapRef.current?.fitToCoordinates(coordinates, {
          edgePadding: { top: 100, right: 50, bottom: 200, left: 50 },
          animated: true,
        });
      }
    } else {
      // Bỏ chọn hết -> hoàn trả region cũ
      if (previousRegionRef.current) {
        mapRef.current?.animateToRegion(previousRegionRef.current, 800);
        previousRegionRef.current = null;
      }
    }
  }, [checkedJobs.length]);

  const onRegionChangeComplete = useCallback((newRegion: any) => {
    // Debounce để tránh tính toán lại quá nhiều khi kéo map
    if (regionDebounceRef.current) {
      clearTimeout(regionDebounceRef.current);
    }
    regionDebounceRef.current = setTimeout(() => {
      setRegion(newRegion);
      setZoomLevel(getZoomLevel(newRegion));
    }, REGION_CHANGE_DEBOUNCE);
  }, []);

  const onSelectLocationSearch = useCallback(
    (_data: GooglePlaceData, details: GooglePlaceDetail | null) => {
      try {
        const lat = details?.geometry?.location?.lat;
        const lng = details?.geometry?.location?.lng;
        if (lat && lng) {
          mapRef.current?.animateToRegion(
            {
              latitude: lat,
              longitude: lng,
              latitudeDelta: 0.5,
              longitudeDelta: 0.5,
            },
            1500,
          );
        }
      } catch (error) {
        logger('error onSelectLocationSearch', error);
      }
    },
    [],
  );

  const handlePressFilter = useCallback(() => {
    try {
      listJobsRef?.current?.snapToIndex(0);
      setTimeout(() => {
        filterRef?.current?.open();
      }, 250);
      setIsFocusedFilter(true);
    } catch (error) {
      logger('error handlePressFilter', error);
    }
  }, [filterRef]);

  useEffect(() => {
    if (isFocused) {
      filterRef?.current?.close();
    }
  }, [isFocused]);

  return (
    <View style={styles.container}>
      <StatusBar barStyle="dark-content" backgroundColor={'transparent'} />
      <MapView
        ref={mapRef}
        style={styles.map}
        provider={PROVIDER_GOOGLE}
        loadingEnabled={true}
        initialRegion={currentLocation}
        onRegionChangeComplete={onRegionChangeComplete}
        // Clustering config - tối ưu cho nhiều markers
        clusterColor={colors.mainColorPrimary}
        clusterTextColor="#FFFFFF"
        clusterFontFamily="System"
        radius={50}
        maxZoom={SPLIT_ZOOM_THRESHOLD}
        minZoom={1}
        minPoints={5}
        extent={512}
        nodeSize={64}
        spiralEnabled={true}
        preserveClusterPressBehavior={true}
        // Performance optimization
        moveOnMarkerPress={false}
        showsCompass={false}
        showsScale={false}
        pitchEnabled={false}
        rotateEnabled={false}
        renderCluster={cluster => {
          const points = cluster.properties.point_count ?? 0;

          return (
            <Marker
              key={cluster.id}
              coordinate={{
                latitude: cluster.geometry.coordinates[1],
                longitude: cluster.geometry.coordinates[0],
              }}
            >
              <View style={styles.clusterMarker}>
                <RNText style={styles.clusterText}>
                  {points > 99 ? '99+' : `${points}`}
                  {'\n'}
                  {t('ADDRS')}
                </RNText>
              </View>
            </Marker>
          );
        }}
      >
        {visibleMarkers.map(group => (
          <JobMarker
            key={group.key}
            markerKey={group.key}
            coordinate={{
              latitude: group.location.latitude,
              longitude: group.location.longitude,
            }}
            jobs={group.jobs}
            logoSource={logoExtra}
            formatDate={formatDateToMMDD}
            jobsLabel={t('JOBS')}
          />
        ))}

        {currentLocation?.latitude && currentLocation?.longitude && (
          <Marker
            coordinate={{
              latitude: currentLocation?.latitude || 0,
              longitude: currentLocation?.longitude || 0,
            }}
          />
        )}
      </MapView>

      <Header
        onLayout={e => {
          setHeaderHeight(e.nativeEvent.layout.height);
        }}
        setIsFocused={setIsFocused}
        isFocused={isFocused}
        onSelectLocationSearch={onSelectLocationSearch}
        handlePressFilter={handlePressFilter}
      />

      <ListJobs isFocusedSearch={isFocused} ref={listJobsRef} />

      {!isFocused && !isFocusedFilter && (
        <Button
          onPress={async () => {
            try {
              const redux = await import('auth/redux');
              dispatch(
                redux.actionContainer.showVideoModal({
                  initialSubtitle: language || 'en',
                  visible: true,
                  source: dataMedia?.JOB_BOARD_SCREEN?.url || {},
                  subtitle: dataMedia?.JOB_BOARD_SCREEN?.subtitle || {},
                  onClose: () => {
                    dispatch(redux.actionContainer.hideVideoModal());
                  },
                }),
              );
            } catch (error) {
              logger('error onPressPlayIcon', error);
            }
          }}
          style={[
            styles.playIconButton,
            { top: insets.top + headerHeight + 16 },
          ]}
        >
          <Image source={playInstructionalVideos} style={styles.playIcon} />
        </Button>
      )}

      <ShadowedView
        style={[
          styles.footerContainer,
          shadowGlobal,
          { paddingBottom: insets.bottom },
        ]}
      >
        <Button
          onPress={() =>
            handleRegister({
              isDisabledButtonRegister,
              allJobs,
            })
          }
          fullWidth
          style={[
            styles.btnRegister,
            isDisabledButtonRegister && styles.disabledButtonRegister,
          ]}
          title={t('REGISTER')}
          textStyle={
            isDisabledButtonRegister && styles.disabledButtonRegisterText
          }
          isDisabled={isDisabledButtonRegister}
        />
      </ShadowedView>

      <Filter
        ref={filterRef}
        onClose={() => setIsFocusedFilter(false)}
        filter={filter}
        setFilter={setFilter}
        moveToLocation={(location: {
          latitude: number;
          longitude: number;
          latitudeDelta: number;
          longitudeDelta: number;
        }) => {
          mapRef.current?.animateToRegion(location);
        }}
        selectDateRange={() => {
          setIsFocusedCalendar(true);
        }}
      />

      {isLoadingFav && !isLoading?.isVisible && (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color={colors.mainColorPrimary} />
        </View>
      )}

      {isFocusedCalendar && (
        <CalenderPicker
          rangeDate={rangeDate}
          setRangeDate={setRangeDate}
          setIsFocusedCalendar={setIsFocusedCalendar}
          setFilter={setFilter}
        />
      )}
    </View>
  );
};

export default JobBoardScreen;
