import { useRoute } from '@react-navigation/native';
import { useSelector } from 'react-redux';
import { useMemo, useState, useCallback } from 'react';
import { dispatch } from '../helper';
import { logger } from '../utils';

// Helper function to lowercase first character: JobsTab -> jobsTab
const lowercaseFirst = (str: string): string => {
  if (!str) return str;
  return str.charAt(0).toLowerCase() + str.slice(1);
};

// Map tab name to category: Jobs = 1, Payments = 2, Others = 0
const TAB_CATEGORY_MAP: Record<string, number> = {
  JobsTab: 1,
  PaymentsTab: 2,
  OthersTab: 0,
};

const PAGE_SIZE = 20;

interface TabNotificationData {
  data: any;
  isLoading: boolean;
  error: any;
  isRefreshing: boolean;
  isLoadingMore: boolean;
  hasMore: boolean;
  isMarkingAllRead: boolean;
  markingAsReadId: string | null;
  onRefresh: () => void;
  onLoadMore: () => void;
}

/**
 * Hook to get notification state based on current tab route name
 * Automatically converts route name (JobsTab) to state key (jobsTab)
 */
export const useTabNotification = (): TabNotificationData => {
  const route = useRoute();
  const tabName = route.name; // e.g., "JobsTab", "PaymentsTab", "OthersTab"
  const [isRefreshing, setIsRefreshing] = useState(false);

  const notificationState = useSelector((state: any) => {
    const stateKey = lowercaseFirst(tabName); // JobsTab -> jobsTab
    return state.notification?.[stateKey];
  });
  // Lấy loading mark all read and mark as read
  const isMarkingAllRead = notificationState?.isMarkingAllRead;
  const markingAsReadId = notificationState?.markingAsReadId;

  const onRefresh = useCallback(async () => {
    try {
      setIsRefreshing(true);
      const redux = await import('auth/redux');
      dispatch(
        redux.actionContainer.getNotificationAsync({
          page: 1,
          pageSize: PAGE_SIZE,
          category: TAB_CATEGORY_MAP[tabName] ?? 0,
          categoryName: tabName,
        }),
      );
    } catch (error) {
      logger('error onRefresh notification', error);
    } finally {
      setIsRefreshing(false);
    }
  }, [tabName]);

  const onLoadMore = useCallback(async () => {
    // Don't load more if already loading or no more data
    if (notificationState?.isLoadingMore || !notificationState?.hasMore) {
      return;
    }

    try {
      const redux = await import('auth/redux');
      const nextPage = (notificationState?.currentPage || 1) + 1;
      dispatch(
        redux.actionContainer.loadMoreNotificationAsync({
          page: nextPage,
          pageSize: PAGE_SIZE,
          category: TAB_CATEGORY_MAP[tabName] ?? 0,
          categoryName: tabName,
        }),
      );
    } catch (error) {
      logger('error onLoadMore notification', error);
    }
  }, [
    tabName,
    notificationState?.isLoadingMore,
    notificationState?.hasMore,
    notificationState?.currentPage,
  ]);

  return useMemo(
    () => ({
      data: notificationState?.data || null,
      isLoading: notificationState?.isLoading || false,
      error: notificationState?.error || null,
      isRefreshing,
      isLoadingMore: notificationState?.isLoadingMore || false,
      hasMore: notificationState?.hasMore ?? true,
      isMarkingAllRead,
      markingAsReadId,
      onRefresh,
      onLoadMore,
    }),
    [notificationState, isRefreshing, onRefresh, onLoadMore],
  );
};
