import React, { useState, useCallback } from 'react';
import {
  View,
  TextInput,
  StyleSheet,
  ActivityIndicator,
} from 'react-native';
import { Button, Text, SCREEN_WIDTH } from 'tradewize-component';
import { ShadowedView } from 'react-native-fast-shadow';
import { colors } from '../../theme';
import { shadowGlobal } from '../../../../Auth/src/types/global';

interface CancelJobModalContentProps {
  title: string;
  description: string;
  placeholder: string;
  confirmText: string;
  cancelText: string;
  errorMessage: string;
  onConfirm: (reason: string) => Promise<void>;
  onCancel: () => void;
}

const CancelJobModalContent: React.FC<CancelJobModalContentProps> = ({
  title,
  description,
  placeholder,
  confirmText,
  cancelText,
  errorMessage,
  onConfirm,
  onCancel,
}) => {
  const [reason, setReason] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleConfirm = useCallback(async () => {
    if (!reason.trim()) {
      setError(errorMessage);
      return;
    }

    setIsLoading(true);
    try {
      await onConfirm(reason.trim());
    } finally {
      setIsLoading(false);
    }
  }, [reason, errorMessage, onConfirm]);

  const handleChangeText = useCallback((text: string) => {
    setReason(text);
    if (text.trim()) {
      setError('');
    }
  }, []);

  return (
    <View style={styles.overlay}>
      <ShadowedView style={[styles.container, shadowGlobal]}>
        {/* Close Button */}
        <Button onPress={onCancel} style={styles.closeButton} variant="ghost">
          <Text style={styles.closeButtonText}>✕</Text>
        </Button>

        {/* Title */}
        <Text style={styles.title}>{title}</Text>

        {/* Description */}
        <Text style={styles.description}>{description}</Text>

        {/* Input */}
        <View style={styles.inputContainer}>
          <TextInput
            value={reason}
            onChangeText={handleChangeText}
            placeholder={placeholder}
            placeholderTextColor={colors.grayScale50}
            style={styles.input}
            multiline
            textAlignVertical="top"
          />
          {error ? <Text style={styles.errorText}>{error}</Text> : null}
        </View>

        {/* Buttons */}
        <View style={styles.buttonContainer}>
          <Button
            variant="secondary"
            style={[styles.button, styles.btnCancel]}
            onPress={onCancel}
            disabled={isLoading}
          >
            <Text style={styles.btnCancelText}>{cancelText}</Text>
          </Button>
          <Button
            variant="primary"
            style={[styles.button, styles.btnConfirm]}
            onPress={handleConfirm}
            disabled={isLoading}
          >
            {isLoading ? (
              <ActivityIndicator size="small" color={colors.white} />
            ) : (
              <Text style={styles.btnConfirmText}>{confirmText}</Text>
            )}
          </Button>
        </View>
      </ShadowedView>
    </View>
  );
};

const styles = StyleSheet.create({
  overlay: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    paddingHorizontal: SCREEN_WIDTH * 0.05,
  },
  container: {
    width: '100%',
    backgroundColor: colors.white,
    borderRadius: 16,
    padding: SCREEN_WIDTH * 0.05,
    paddingTop: SCREEN_WIDTH * 0.1,
  },
  closeButton: {
    position: 'absolute',
    top: 12,
    right: 12,
    zIndex: 1,
    padding: 8,
    minWidth: 0,
    minHeight: 0,
  },
  closeButtonText: {
    fontSize: 18,
    color: colors.grayScale70,
  },
  title: {
    fontSize: 18,
    fontWeight: '600',
    color: colors.black,
    textAlign: 'center',
    marginBottom: 8,
  },
  description: {
    fontSize: 14,
    color: colors.grayScale70,
    textAlign: 'center',
    marginBottom: 16,
  },
  inputContainer: {
    marginBottom: 16,
  },
  input: {
    borderWidth: 1,
    borderColor: colors.grayScale30,
    borderRadius: 8,
    width: '100%',
    minHeight: 100,
    paddingHorizontal: 12,
    paddingVertical: 10,
    fontSize: 14,
    color: colors.black,
    backgroundColor: colors.white,
    textAlignVertical: 'top',
  },
  errorText: {
    color: colors.alertColorError,
    fontSize: 12,
    marginTop: 4,
  },
  buttonContainer: {
    flexDirection: 'row',
    gap: 12,
  },
  button: {
    flex: 1,
    paddingVertical: 12,
    borderRadius: 8,
  },
  btnCancel: {
    backgroundColor: colors.white,
    borderWidth: 1,
    borderColor: colors.grayScale30,
  },
  btnCancelText: {
    color: colors.grayScale70,
    fontSize: 14,
    fontWeight: '500',
  },
  btnConfirm: {
    backgroundColor: colors.mainColorPrimary,
  },
  btnConfirmText: {
    color: colors.white,
    fontSize: 14,
    fontWeight: '500',
  },
});

export default CancelJobModalContent;
