import {
  ChecklistItem,
  ChecklistMode,
  FileSetting,
  FileType,
  JobReadyOption,
  VideoType,
  userRole,
} from '../types/jobDetail.type';

/**
 * JobReady option configuration (labels use i18n keys)
 */
export const JOB_READY_OPTIONS = [
  { key: JobReadyOption.COMPLETE, labelKey: 'COMPLETE', value: JobReadyOption.COMPLETE },
  { key: JobReadyOption.IN_PROGRESS, labelKey: 'IN_PROGRESS', value: JobReadyOption.IN_PROGRESS },
  { key: JobReadyOption.NOT_START, labelKey: 'NOT_START', value: JobReadyOption.NOT_START },
  { key: JobReadyOption.NOT_RELEVANT, labelKey: 'NOT_RELEVANT', value: JobReadyOption.NOT_RELEVANT },
];

/**
 * Clean checklist item name/description by removing leading pipe characters
 * API sometimes returns description with "|" prefix - this cleans it
 * @param text - The item name or description
 */
export const cleanChecklistItemName = (text: string | undefined | null): string => {
  if (!text) return '';
  // Remove leading "|" and whitespace
  return text.replace(/^\s*\|\s*/, '').trim();
};

/**
 * Validates if a checklist item meets file requirements based on fileSettings.
 *
 * Logic:
 * 1. Check if need new comment (isNeedComment)
 * 2. If first comment (no responses yet) → validate by fileSettings (min/max)
 * 3. If not first comment but need reply → validate at least 1 photo or video
 * 4. If no need for new comment → pass
 *
 * @param checklistItem - The original checklist item from Redux store
 * @param localItem - Optional local item containing user's new files/updates (from comment modal)
 */
export const isPassValidateFilesByFileSetting = (
  checklistItem: ChecklistItem | null | undefined,
  localItem?: { fileEntities?: any[]; comment?: string } | null,
): boolean => {
  if (!checklistItem) {
    return false;
  }

  const fileSettings = checklistItem.fileSettings || [];
  const [photoSetting, videoSetting] = parserFilesSetting(fileSettings);

  // Get responses (support both response and responses fields)
  const responseArray = checklistItem.response || [];
  const responsesArray = checklistItem.responses || [];
  const responses = responseArray.length > 0 ? responseArray : responsesArray;

  // Check if last response is from current user (need new comment)
  const isNeedComment =
    responses.length === 0 ||
    responses[responses.length - 1]?.isExMyResponse === false;

  // Helper to check if file is photo
  const isPhoto = (file: any): boolean => {
    if (file?.type?.includes('image')) return true;
    if (file?.fileExtension && !VideoType?.includes(file.fileExtension))
      return true;
    return false;
  };

  // Helper to check if file is video
  const isVideo = (file: any): boolean => {
    if (file?.type?.includes('video')) return true;
    if (file?.fileExtension && VideoType?.includes(file.fileExtension))
      return true;
    return false;
  };

  // Local files being uploaded (from UI state)
  // Prioritize localItem.fileEntities if provided (from comment modal)
  const localFiles =
    localItem?.fileEntities || checklistItem.fileEntities || [];
  const localPhotos = localFiles.filter(isPhoto);
  const localVideos = localFiles.filter(isVideo);

  // ========== VALIDATION LOGIC ==========

  // No need for new comment → pass validation
  if (!isNeedComment) {
    return true;
  }

  // First comment (no responses yet) → validate by fileSettings
  if (responses.length === 0) {
    const hasPhotoRequirement = photoSetting && photoSetting.minFiles > 0;
    const hasVideoRequirement = videoSetting && videoSetting.minFiles > 0;
    const hasFileRequirement = hasPhotoRequirement || hasVideoRequirement;

    // Has file requirement → validate min/max
    if (hasFileRequirement) {
      return validateFileRequirements(
        localPhotos.length,
        localVideos.length,
        photoSetting,
        videoSetting,
      );
    }

    // No file requirement → pass
    return true;
  }

  // From 2nd comment onwards (need reply to others) → validate at least 1 photo or video
  const hasNewFiles = localPhotos.length > 0 || localVideos.length > 0;
  return hasNewFiles;
};

// validateFileRequirements is now exported at the bottom of this file

export const parserFilesSetting = (fileSettings: FileSetting[]) => {
  const photoSetting = fileSettings.find(
    item => item.fileType === FileType.PHOTO,
  );
  const videoSetting = fileSettings.find(
    item => item.fileType === FileType.VIDEO,
  );
  return [photoSetting, videoSetting];
};

/**
 * Validates if all checklist items have been completed (isChecked or isNA is not null)
 * Used before allowing user to complete the job
 */
export const areAllChecklistsCompleted = (
  checklists: ChecklistItem[] | null | undefined,
): boolean => {
  // Safety check: ensure checklists is an array
  if (!Array.isArray(checklists) || checklists.length === 0) {
    return true; // No checklists means nothing to complete
  }

  return checklists.every(
    item => item.isChecked !== null || item.isNA !== null,
  );
};

/**
 * Gets the count of incomplete checklist items
 */
export const getIncompleteChecklistsCount = (
  checklists: ChecklistItem[] | null | undefined,
): number => {
  if (!checklists || checklists.length === 0) {
    return 0;
  }

  return checklists.filter(
    item => item.isChecked === null && item.isNA === null,
  ).length;
};

/**
 * Detects the checklist mode based on item data or array of items
 * - JOB_START: item has truthy jobStartChecklistId field
 * - JOB_READY: item has truthy projectReadyChecklistId field
 * - QI: item.userRole is INSPECTOR
 * - DEFAULT: all other cases
 *
 * @param input - Single ChecklistItem or array of ChecklistItem
 */
export const detectChecklistMode = (
  input: ChecklistItem | ChecklistItem[] | null | undefined,
): ChecklistMode => {
  // Handle null/undefined
  if (!input) {
    return ChecklistMode.DEFAULT;
  }

  // Handle array input - use first item
  if (Array.isArray(input)) {
    if (input.length === 0) {
      return ChecklistMode.DEFAULT;
    }
    return detectChecklistMode(input[0]);
  }

  // Handle single item
  const item = input as any;

  // JobStart: has truthy jobStartChecklistId field (not null/undefined)
  if (item.jobStartChecklistId) {
    return ChecklistMode.JOB_START;
  }
  // JobReady: has truthy projectReadyChecklistId field (not null/undefined)
  if (item.projectReadyChecklistId) {
    return ChecklistMode.JOB_READY;
  }
  // QI: userRole is INSPECTOR
  if (item.userRole === userRole.INSPECTOR) {
    return ChecklistMode.QI;
  }
  // Default: all other cases
  return ChecklistMode.DEFAULT;
};

/**
 * @deprecated Use detectChecklistMode() instead - it now accepts both single item and array
 */
export const detectChecklistModeFromItems = detectChecklistMode;

// ============================================================================
// JobReady Validation Functions
// ============================================================================

/**
 * Validates JobReady item when user clicks an option (outside modal).
 * Returns true if validation passes, false if should open modal for more input.
 *
 * Rules:
 * 1. No comments yet + has fileSettings → FAIL (need to open modal)
 * 2. No comments yet + no fileSettings + option is IN_PROGRESS/NOT_START → FAIL (need comment/file)
 * 3. Other cases → PASS
 *
 * @param item - The checklist item
 * @param selectedOption - The option user selected
 */
export const isPassValidateJobReady = (
  item: ChecklistItem | null | undefined,
  selectedOption: JobReadyOption,
): boolean => {
  if (!item) {
    return false;
  }

  // Get responses (support both response and responses fields)
  const responseArray = item.response || [];
  const responsesArray = item.responses || [];
  const responses = responseArray.length > 0 ? responseArray : responsesArray;
  const hasResponses = responses.length > 0;

  // If already has responses, pass validation (no need to re-enter)
  if (hasResponses) {
    return true;
  }

  // No responses yet - check conditions
  const fileSettings = item.fileSettings || [];
  const hasFileSettings = fileSettings.length > 0;

  // Rule 1: No comments + has fileSettings → FAIL
  if (hasFileSettings) {
    return false;
  }

  // Rule 2: No comments + no fileSettings + IN_PROGRESS/NOT_START → FAIL
  const requiresCommentOptions = [
    JobReadyOption.IN_PROGRESS,
    JobReadyOption.NOT_START,
  ];
  if (requiresCommentOptions.includes(selectedOption)) {
    return false;
  }

  // Other cases (COMPLETE, NOT_RELEVANT without fileSettings) → PASS
  return true;
};

/**
 * Validates JobStart (Material Checklist) item when user clicks Yes/No toggle.
 * Returns true if validation passes, false if should open modal for files.
 *
 * SIMPLER than JobReady - Only validates fileSettings, no comment requirement.
 *
 * Rules:
 * 1. Already has responses → PASS (no need to re-enter)
 * 2. No responses + has fileSettings with minFiles > 0 → FAIL (need to upload files)
 * 3. Other cases → PASS
 *
 * @param item - The checklist item
 */
export const isPassValidateJobStart = (
  item: ChecklistItem | null | undefined,
): boolean => {
  if (!item) {
    return false;
  }

  // Get responses (support both response and responses fields)
  const responseArray = item.response || [];
  const responsesArray = item.responses || [];
  const responses = responseArray.length > 0 ? responseArray : responsesArray;
  const hasResponses = responses.length > 0;

  // If already has responses, pass validation (no need to re-enter)
  if (hasResponses) {
    return true;
  }

  // No responses yet - check if has file requirements
  const fileSettings = item.fileSettings || [];

  // Check if any file setting has minFiles > 0 (required files)
  const hasRequiredFiles = fileSettings.some(
    (setting: any) => setting.minFiles && setting.minFiles > 0,
  );

  if (hasRequiredFiles) {
    return false;
  }

  // No required files → PASS
  return true;
};

/**
 * Validates JobReady item inside CommentChecklist modal when saving.
 * Returns true if validation passes, false if more files/comment needed.
 *
 * Rules:
 * 1. Has fileSettings → validate by fileSettings (normal logic)
 * 2. No fileSettings + IN_PROGRESS/NOT_START → require at least 1 photo OR 1 video
 * 3. No fileSettings + COMPLETE/NOT_RELEVANT → no file requirement
 *
 * @param item - The original checklist item
 * @param localItem - Local item with user's new files/comment
 * @param selectedOption - The selected option
 */
export const isPassValidateJobReadyInModal = (
  item: ChecklistItem | null | undefined,
  localItem: { fileEntities?: any[]; comment?: string } | null,
  selectedOption: JobReadyOption,
): boolean => {
  if (!item) {
    return false;
  }

  // Check if item already has responses - if yes, skip validation
  const existingResponses = item.responses || item.response || [];
  const hasExistingResponses = existingResponses.length > 0;

  if (hasExistingResponses) {
    return true;
  }

  const fileSettings = item.fileSettings || [];
  const hasFileSettings = fileSettings.length > 0;

  // Helper to check if file is photo
  const isPhoto = (file: any): boolean => {
    if (file?.type?.includes('image')) return true;
    if (file?.fileExtension && !VideoType?.includes(file.fileExtension))
      return true;
    return false;
  };

  // Helper to check if file is video
  const isVideo = (file: any): boolean => {
    if (file?.type?.includes('video')) return true;
    if (file?.fileExtension && VideoType?.includes(file.fileExtension))
      return true;
    return false;
  };

  // Local files being uploaded
  const localFiles = localItem?.fileEntities || [];
  const localPhotos = localFiles.filter(isPhoto);
  const localVideos = localFiles.filter(isVideo);

  // Rule 1: Has fileSettings → validate by fileSettings (reuse existing logic)
  if (hasFileSettings) {
    const [photoSetting, videoSetting] = parserFilesSetting(fileSettings);
    return validateFileRequirements(
      localPhotos.length,
      localVideos.length,
      photoSetting,
      videoSetting,
    );
  }

  // Rule 2: No fileSettings + IN_PROGRESS/NOT_START → require at least 1 photo OR 1 video
  const requiresFileOptions = [
    JobReadyOption.IN_PROGRESS,
    JobReadyOption.NOT_START,
  ];
  if (requiresFileOptions.includes(selectedOption)) {
    const hasAtLeastOneFile = localPhotos.length > 0 || localVideos.length > 0;
    return hasAtLeastOneFile;
  }

  // Rule 3: COMPLETE/NOT_RELEVANT without fileSettings → no file requirement, pass
  return true;
};

/**
 * Helper function to validate file counts against requirements
 * (Made public for reuse in JobReady validation)
 */
export const validateFileRequirements = (
  photoCount: number,
  videoCount: number,
  photoSetting: FileSetting | undefined,
  videoSetting: FileSetting | undefined,
): boolean => {
  // Validate photo requirements
  if (photoSetting && photoSetting.minFiles > 0) {
    // Only check min > max when maxFiles > 0 (has max limit)
    if (
      photoSetting.maxFiles > 0 &&
      photoSetting.minFiles > photoSetting.maxFiles
    ) {
      return false;
    }
    if (photoCount < photoSetting.minFiles) {
      return false;
    }
    // Only check max when maxFiles > 0
    if (photoSetting.maxFiles > 0 && photoCount > photoSetting.maxFiles) {
      return false;
    }
  }

  // Validate video requirements
  if (videoSetting && videoSetting.minFiles > 0) {
    // Only check min > max when maxFiles > 0 (has max limit)
    if (
      videoSetting.maxFiles > 0 &&
      videoSetting.minFiles > videoSetting.maxFiles
    ) {
      return false;
    }
    if (videoCount < videoSetting.minFiles) {
      return false;
    }
    // Only check max when maxFiles > 0
    if (videoSetting.maxFiles > 0 && videoCount > videoSetting.maxFiles) {
      return false;
    }
  }

  return true;
};
