import React, { useCallback, useEffect } from 'react';
import { ScrollView, StyleSheet, View } from 'react-native';
import { useRoute } from '@react-navigation/native';
import { BaseContainer, HeaderBase, Text, Button } from 'tradewize-component';
import { colors } from '../../theme';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { useJobReadyChecklist } from '../../hooks/useJobReadyChecklist';
import { NavigationService } from '../../services/NavigationService';
import SubmitModal from './components/SubmitModal';
import Checklist from '../../components/Checklist';
import { SCREEN_ENUM } from '../../types/global';
import { dispatch } from '../../helper';
import CommentChecklist from '../../components/CommentChecklist';

const JobReadyChecklistScreen: React.FC = () => {
  const { t } = useAppTranslation();
  const [showSubmitModal, setShowSubmitModal] = React.useState(false);

  const {
    isReady,
    isViewOnly,
    isLoading,
    isLaborSKUOnly,
    handleSubmit,
    formattedDeliveryDates,
    scrollY,
    invalidItemIds,
    clearInvalidItem,
    scrollViewRef,
    validateChecklists,
    findFirstUnselectedItem,
  } = useJobReadyChecklist();

  const handleGoBack = useCallback(async () => {
    NavigationService.goBack();
    const redux = await import('auth/redux');
    dispatch(
      redux.actionContainer.clearChecklist(SCREEN_ENUM.JobReadyChecklistScreen),
    );
  }, []);

  // Cleanup JobReady checklist on unmount
  useEffect(() => {
    return () => {
      const cleanup = async () => {
        const redux = await import('auth/redux');
        dispatch(
          redux.actionContainer.clearChecklist(
            SCREEN_ENUM.JobReadyChecklistScreen,
          ),
        );
      };
      cleanup();
    };
  }, []);

  const handleOpenSubmitModal = () => {
    // Validate all checklists have selection before opening modal
    if (!validateChecklists()) {
      // Scroll to first unselected item
      const firstUnselected = findFirstUnselectedItem();
      if (firstUnselected && scrollViewRef.current) {
        // Scroll to the item
        scrollViewRef.current.scrollTo({ y: 0, animated: true });
      }
      return;
    }
    setShowSubmitModal(true);
  };

  const handleCloseSubmitModal = () => {
    setShowSubmitModal(false);
  };

  // Handle Proceed with Delivery button
  const handleProceed = useCallback(() => {
    handleSubmit(false);
  }, [handleSubmit]);

  // Handle Reschedule from modal
  const handleRescheduleSubmit = useCallback(
    (values: { dateSchedule: { dateDelivery: string }; reason: string }) => {
      handleSubmit(true, values, handleCloseSubmitModal);
    },
    [handleSubmit],
  );

  return (
    <BaseContainer>
      <HeaderBase
        title={t('JOB_READY_CHECKLIST')}
        onPressBack={handleGoBack}
        backgroundColor={colors.white}
      />

      {/* Hide content during loading */}
      {!isLoading && (
        <ScrollView
          ref={scrollViewRef}
          style={styles.container}
          contentContainerStyle={styles.contentContainer}
          onScroll={event => {
            scrollY.current = event.nativeEvent.contentOffset.y;
          }}
          scrollEventThrottle={16}
          showsVerticalScrollIndicator={false}
        >
          {/* Status Header - only show when isReady (view-only mode) */}
          {isReady && (
            <Text style={styles.statusText}>
              {t('STATUS')}: {t('READY')}
            </Text>
          )}

          {/* Checklist */}
          <Checklist
            screenKey={SCREEN_ENUM.JobReadyChecklistScreen}
            invalidItemIds={invalidItemIds}
            onClearInvalid={clearInvalidItem}
          />

          {/* Bottom padding for button */}
          <View style={styles.bottomPadding} />
        </ScrollView>
      )}

      {/* Bottom Action Buttons - only show when NOT loading, NOT view-only and NOT ready */}
      {!isLoading && !isViewOnly && !isReady && (
        <View style={styles.buttonContainer}>
          <Button
            variant="ghost"
            style={styles.rescheduleButton}
            onPress={handleOpenSubmitModal}
          >
            <Text style={styles.rescheduleButtonText}>
              {!isLaborSKUOnly
                ? t('RESCHEDULE_DELIVERY')
                : t('RESCHEDULE_INSTALLATION')}
            </Text>
          </Button>

          <Button
            variant="primary"
            style={styles.readyButton}
            onPress={handleProceed}
          >
            <Text style={styles.readyButtonText}>
              {!isLaborSKUOnly
                ? t('PROCEED_WITH_DELIVERY')
                : t('PROCEED_WITH_INSTALLATION')}
            </Text>
          </Button>
        </View>
      )}

      {/* Submit/Reschedule Modal */}
      <SubmitModal
        visible={showSubmitModal}
        onClose={handleCloseSubmitModal}
        onSubmit={handleRescheduleSubmit}
        deliveryDates={formattedDeliveryDates}
        isLaborSKUOnly={isLaborSKUOnly}
      />
      <CommentChecklist />
    </BaseContainer>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.white,
  },
  contentContainer: {
    paddingHorizontal: 16,
    paddingTop: 16,
  },
  statusText: {
    fontSize: 16,
    fontWeight: '600',
    color: colors.mainColorPrimary,
    marginBottom: 16,
  },
  bottomPadding: {
    height: 100,
  },
  buttonContainer: {
    flexDirection: 'row',
    gap: 12,
    paddingHorizontal: 16,
    paddingVertical: 16,
    backgroundColor: colors.white,
    borderTopWidth: 1,
    borderTopColor: colors.grayScale30,
  },
  rescheduleButton: {
    flex: 1,
    paddingVertical: 12,
    borderWidth: 1,
    borderColor: colors.mainColorPrimary,
    backgroundColor: colors.white,
    borderRadius: 8,
  },
  rescheduleButtonText: {
    color: colors.mainColorPrimary,
    fontWeight: '600',
    fontSize: 14,
  },
  readyButton: {
    flex: 1,
    paddingVertical: 12,
    backgroundColor: colors.mainColorPrimary,
    borderRadius: 8,
  },
  readyButtonText: {
    color: colors.white,
    fontWeight: '600',
    fontSize: 14,
  },
});

export default JobReadyChecklistScreen;
