import { useCallback, useEffect, useRef } from 'react';
import { useDispatch } from 'react-redux';
import { logger } from '../utils';

export const useNetwork = () => {
  const dispatch = useDispatch();
  const savedKeyword = useRef('');

  const fetchGetNetwork = useCallback(async () => {
    try {
      const redux = await import('auth/redux');
      dispatch(
        redux.actionContainer.getNetworkAsync({
          keyword: '',
          page: 1,
          isRefresh: true,
        }),
      );
    } catch (error) {
      console.log(error);
    }
  }, [dispatch]);

  const onLoadMore = useCallback(
    async (pageNumber: number, keyword?: string) => {
      try {
        const redux = await import('auth/redux');
        dispatch(
          redux.actionContainer.getNetworkAsync({
            keyword,
            page: pageNumber,
            isLoadMore: true,
            isRefresh: false,
          }),
        );
        savedKeyword.current = keyword || '';
      } catch (error) {
        console.log(error);
      }
    },
    [dispatch],
  );

  const onSearch = useCallback(
    async (searchText?: string) => {
      try {
        if (searchText === savedKeyword.current) {
          return;
        }
        const redux = await import('auth/redux');
        dispatch(
          redux.actionContainer.getNetworkAsync({
            keyword: searchText,
            page: 1,
            isRefresh: true,
            isLoadMore: false,
          }),
        );
        savedKeyword.current = searchText || '';
      } catch (error) {
        logger('error onSearch', error);
      }
    },
    [dispatch],
  );

  const onRefresh = useCallback(
    async (keyword?: string) => {
      try {
        const redux = await import('auth/redux');
        dispatch(
          redux.actionContainer.getNetworkAsync({
            keyword: keyword,
            page: 1,
            isRefresh: true,
            isLoadMore: false,
          }),
        );
        savedKeyword.current = keyword || '';
      } catch (error) {
        logger('error onRefresh', error);
      }
    },
    [dispatch],
  );

  useEffect(() => {
    fetchGetNetwork();
  }, [fetchGetNetwork]);

  return {
    onLoadMore,
    onRefresh,
    onSearch,
  };
};
