import React from 'react';
import { View, FlatList } from 'react-native';
import { BaseContainer, HeaderBase, Text } from 'tradewize-component';
import { styles } from './styles';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { NavigationService } from '../../services/NavigationService';
import { useRoleType } from '../../hooks/useRoleType';
import { RoleTypeItem } from '../../components/RoleTypeItem';
import { useSelector } from 'react-redux';

export default function RoleTypeScreen() {
  const { t } = useAppTranslation();
  const { data: roleTypeData } = useSelector((state: any) => state.roleType);
  const isLoadingOverlay = useSelector(
    (state: any) => state.app?.loadingOverlay?.isVisible,
  );

  useRoleType();

  const renderEmpty = () => {
    if (isLoadingOverlay) {
      return;
    }
    return (
      <View style={styles.emptyContainer}>
        <Text style={styles.emptyText}>{t('NO_DATA_AVAILABLE')}</Text>
      </View>
    );
  };

  return (
    <BaseContainer style={styles.container}>
      <HeaderBase
        title={t('ROLE_TYPE_AND_SCOPE')}
        onPressBack={() => {
          NavigationService.goBack();
        }}
      />
      <FlatList
        data={roleTypeData || []}
        renderItem={({ item }) => <RoleTypeItem item={item} />}
        keyExtractor={(item, index) => `${item.id}-${index}`}
        contentContainerStyle={styles.listContent}
        ListEmptyComponent={renderEmpty}
        showsVerticalScrollIndicator={false}
      />
    </BaseContainer>
  );
}
