import type { BottomSelectorOption } from 'tradewize-component';
import {
  DeliveryStatus,
  DELIVERY_STATUS_MAP,
  MaterialChecklistItem,
  JobStartChecklistItem,
} from '../types/jobStart.type';

// ============================================================================
// Delivery Status Helpers
// ============================================================================

/**
 * Get translation key for delivery status
 */
export const getDeliveryStatusKey = (status: DeliveryStatus): string => {
  return DELIVERY_STATUS_MAP[status] || 'DELIVERY_STATUS_UNDELIVERED';
};

/**
 * Check if delivery status allows starting job
 */
export const canStartJob = (status: DeliveryStatus): boolean => {
  return (
    status !== DeliveryStatus.Undelivered &&
    status !== DeliveryStatus.OnDelivery
  );
};

/**
 * Check if delivery is incomplete (readonly mode)
 */
export const isDeliveryIncomplete = (status: DeliveryStatus): boolean => {
  return status === DeliveryStatus.InComplete;
};

/**
 * Check if delivery status disables options
 */
export const isDeliveryPending = (status: DeliveryStatus): boolean => {
  return (
    status === DeliveryStatus.Undelivered ||
    status === DeliveryStatus.OnDelivery
  );
};

// ============================================================================
// Quantity Options Helpers
// ============================================================================

/**
 * Generate quantity options for BottomSelector (0 to maxQuantity)
 * Supports decimal values if maxQuantity has decimals
 */
export const generateQuantityOptions = (
  maxQuantity: number,
): BottomSelectorOption[] => {
  const options: BottomSelectorOption[] = [];
  const hasDecimal = maxQuantity % 1 !== 0;

  if (hasDecimal) {
    // Generate with 0.5 increments
    for (let i = 0; i <= maxQuantity; i += 0.5) {
      const value = Number(i.toFixed(1));
      options.push({
        label: value.toString(),
        value: value.toString(),
      });
    }
    // Ensure max value is included
    if (!options.find(o => o.value === maxQuantity.toString())) {
      options.push({
        label: maxQuantity.toString(),
        value: maxQuantity.toString(),
      });
    }
  } else {
    // Generate whole numbers
    for (let i = 0; i <= maxQuantity; i++) {
      options.push({
        label: i.toString(),
        value: i.toString(),
      });
    }
  }

  return options;
};

// ============================================================================
// Material Grouping Helpers
// ============================================================================

/**
 * Group materials by materialTypeId
 * Returns object with typeId as key and array of materials as value
 */
export const groupMaterialsByType = (
  materials: MaterialChecklistItem[],
): Record<string, MaterialChecklistItem[]> => {
  return materials.reduce(
    (acc, item) => {
      const key = item.materialTypeId || 'unknown';
      if (!acc[key]) {
        acc[key] = [];
      }
      acc[key].push(item);
      return acc;
    },
    {} as Record<string, MaterialChecklistItem[]>,
  );
};

/**
 * Get type name from grouped materials
 */
export const getTypeName = (items: MaterialChecklistItem[]): string => {
  return items[0]?.materialTypeName || 'Unknown Type';
};

// ============================================================================
// File Settings Helpers
// ============================================================================

/**
 * Get required files text from fileSettings
 * e.g., "Required: 1 Photo, 2 Videos"
 */
export const getRequiredFilesText = (
  fileSettings: { minFiles: number; fileType: number }[] | undefined,
): string | null => {
  if (!fileSettings || fileSettings.length === 0) return null;

  const parts: string[] = [];
  fileSettings.forEach(setting => {
    if (setting.minFiles && setting.minFiles > 0) {
      // fileType: 0 = Photo, 1 = Video
      const type = setting.fileType === 0 ? 'Photo' : 'Video';
      const plural = setting.minFiles > 1 ? 's' : '';
      parts.push(`${setting.minFiles} ${type}${plural}`);
    }
  });

  return parts.length > 0 ? parts.join(', ') : null;
};

// ============================================================================
// Validation Helpers
// ============================================================================

/**
 * Check if all materials have received quantity filled
 */
export const validateReceivedQuantities = (
  materials: MaterialChecklistItem[],
): boolean => {
  return materials.every(
    item => item.quantitySave !== null && item.quantitySave !== undefined,
  );
};

/**
 * Check if all checklists have been checked (not null)
 */
export const validateChecklistsChecked = (
  checklists: JobStartChecklistItem[],
): boolean => {
  return checklists.every(item => item.isChecked !== null);
};

/**
 * Check if there are any missing materials
 */
export const hasMissingMaterials = (
  materials: MaterialChecklistItem[],
): boolean => {
  return materials.some(
    item => item.quantityMissing !== null && item.quantityMissing > 0,
  );
};

/**
 * Get list of missing material IDs
 */
export const getMissingMaterialIds = (
  materials: MaterialChecklistItem[],
): string[] => {
  return materials
    .filter(item => item.quantityMissing !== null && item.quantityMissing > 0)
    .map(item => item.id);
};

/**
 * Get materials with received quantities for submission
 */
export const getMaterialReceivedPayload = (
  materials: MaterialChecklistItem[],
): { id: string; quantity: number }[] => {
  return materials
    .filter(
      item => item.quantitySave !== null && item.quantitySave !== undefined,
    )
    .map(item => ({
      id: item.id,
      quantity: item.quantitySave!,
    }));
};

// ============================================================================
// Missing Quantity Calculator
// ============================================================================

/**
 * Calculate missing quantity based on verifyMaterial and quantitySave
 */
export const calculateMissingQuantity = (
  verifyMaterial: number,
  quantitySave: number | null,
): number | null => {
  if (quantitySave === null || quantitySave === undefined) {
    return null;
  }
  const missing = verifyMaterial - quantitySave;
  return missing > 0 ? Number(missing.toFixed(1)) : null;
};
