export interface Role {
  id: string;
  code: string;
  scope: string | null;
  level: number | null;
  name: string;
  roleType: number;
  isMyRole: boolean;
}

export enum CompanyRegistrationStatusEnum {
  NotRegistered = 0, // chưa đăng kí
  UnDoneOnboardingTest = 1, // chưa làm onboarding test
  DoneOnboardingTest = 2, // đã làm onboarding test
  PendingApproval = 3, // chờ admin approval
  PendingInterview = 4, // chờ phỏng vấn sau khi được approval
  InterviewFailed = 5, // false phỏng vấn
  InterviewPassed = 6, // pass phỏng vấn
}

export interface Company {
  companyId: string;
  companyName: string;
  companyRegistrationStatus: CompanyRegistrationStatusEnum;
  canRegister?: boolean;
  roles: Role[];
}

export interface CompanyAndRoleData {
  data: Company[];
  loading?: boolean;
}

export interface CompanyRegistrationStatus {
  label?: string;
  statusName?: string;
  message?: string;
  color: string;
}
