import { ActivityIndicator, LayoutChangeEvent, View } from 'react-native';
import { Button, SCREEN_WIDTH, Text } from 'tradewize-component';
import { styles } from './styles.ts';
import { useSelector } from 'react-redux';
import { useCallback, useEffect, useMemo, useState } from 'react';
import FastImage from 'react-native-fast-image';
import { colors } from '../../../../theme/index.tsx';
import { IconClock, IconLocation } from '../../../../assets/svg/index.ts';
import { SvgXml } from 'react-native-svg';
import React from 'react';
import BoxCheckIn from './BoxCheckIn.tsx';
import { useAppTranslation } from '../../../../hooks/useAppTranslation.ts';
import { NavigationService } from '../../../../services/NavigationService.ts';
import {
  AUTO_CHECK_IN_DISTANCE,
  SCREEN_ENUM,
} from '../../../../types/global.ts';
import { logger } from '../../../../utils/index.tsx';
import { getCurrentLocation } from '../../../../helper/index.tsx';
import { calculateDistanceInMeters } from '../../../YourLocation/utils.ts';
import dayjs from 'dayjs';
import { checkInLocation } from '../../../../api/endpoint.ts';
import Toast from 'react-native-toast-message';
import { useDispatch } from 'react-redux';

const JobsToday = () => {
  const { t } = useAppTranslation();
  const dispatch = useDispatch();

  const myJobsToday = useSelector((state: any) => state.home.myJobsToday?.data);
  const arrayJobs = useMemo(() => myJobsToday?.myJobToday || [], [myJobsToday]);
  const isLoading = useSelector<any, boolean>(
    (state: any) => state.home.myJobsToday?.isLoading,
  );

  const [titleWidth, setTitleWidth] = useState(0);

  const handleLayout = (event: LayoutChangeEvent) => {
    setTitleWidth(
      event?.nativeEvent?.layout?.width ? event?.nativeEvent?.layout?.width : 0,
    );
  };

  const estTimeCompletion = React.useCallback(() => {
    if (arrayJobs[0]?.estFinish) {
      return `${new Date(arrayJobs[0]?.estFinish).toLocaleDateString('en-US', {
        month: 'short',
      })} ${new Date(arrayJobs[0]?.estFinish).getDate()}, ${new Date(
        arrayJobs[0]?.estFinish,
      ).getFullYear()}`;
    }
    return '';
  }, [arrayJobs]);

  const getFormattedAddress = (job: any) => {
    const parts = [];
    if (job?.lotNumber) parts.push(`${t('LOT')} ${job.lotNumber}`);
    if (job?.address) parts.push(job.address);
    return parts.join(' - ') || job?.communityName || '';
  };

  const autoCheckIn = useCallback(async () => {
    try {
      const redux = await import('auth/redux');
      const client = await import('auth/api');
      if (arrayJobs?.length > 0) {
        const jobsCanCheckIn = arrayJobs[0];
        if (jobsCanCheckIn?.needCheckin && !jobsCanCheckIn?.checkInOn) {
          const currentLocation = await getCurrentLocation();
          const jobLocation = jobsCanCheckIn?.location;

          // Kiểm tra null TRƯỚC khi tính toán
          if (!currentLocation || !jobLocation) {
            return;
          }

          const distanceCheckIn =
            calculateDistanceInMeters(
              currentLocation.latitude,
              currentLocation.longitude,
              jobLocation.latitude,
              jobLocation.longitude,
            ) / 0.9144;

          if (distanceCheckIn > AUTO_CHECK_IN_DISTANCE) {
            return;
          }
          const body = {
            location: {
              latitude: currentLocation.latitude,
              longitude: currentLocation.longitude,
            },
            locationTimestamp: dayjs().toISOString(),
            purchaseOrderId: jobsCanCheckIn?.id,
          };
          const response = await client.postRequest(checkInLocation, body);
          if (response?.code === 200) {
            Toast.show({
              type: 'success',
              text1: t('CHECKED_IN_SUCCESSFULLY'),
            });
            dispatch(redux.actionContainer.getMyJobsTodayAsync());
          }
        }
      }
    } catch (error) {
      logger('auToCheckIn', error);
    }
  }, [arrayJobs, dispatch, t]);

  useEffect(() => {
    // Gọi ngay lần đầu khi mount
    autoCheckIn();

    // Thiết lập interval gọi lại mỗi 60 giây
    const intervalId = setInterval(() => {
      autoCheckIn();
    }, 60000);

    // Cleanup interval khi component unmount
    return () => {
      clearInterval(intervalId);
    };
  }, [autoCheckIn]);

  return (
    <View style={styles.container}>
      <View style={[styles.line, { width: titleWidth }]} />
      <Text style={styles.title} onLayout={handleLayout}>
        {t('TODAY_JOBS')}:
      </Text>

      {isLoading ? (
        <View style={styles.containerSkeleton}>
          <ActivityIndicator size={24} color={colors.mainColorPrimary} />
        </View>
      ) : (
        <View style={styles.contentContainer}>
          {myJobsToday?.totalJobToday > 0 ? (
            <View>
              <View style={[styles.jobContainer, { paddingHorizontal: 8 }]}>
                <View style={styles.jobInfoContainer}>
                  <View style={styles.rowText}>
                    <Text style={styles.activityName} numberOfLines={2}>
                      {arrayJobs?.[0]?.activityName}
                    </Text>

                    <Text
                      style={[
                        styles.time,
                        { backgroundColor: colors.additionalSecondary },
                      ]}
                      numberOfLines={1}
                    >
                      08:00 AM
                    </Text>
                  </View>

                  <View style={styles.rowText}>
                    <SvgXml
                      xml={IconLocation(colors.red)}
                      width={SCREEN_WIDTH * 0.04}
                      height={SCREEN_WIDTH * 0.05}
                    />

                    <Text style={styles.location} numberOfLines={2}>
                      {getFormattedAddress(arrayJobs[0])}
                    </Text>
                  </View>

                  <View style={styles.rowText}>
                    <SvgXml
                      xml={IconClock(colors.black)}
                      width={SCREEN_WIDTH * 0.04}
                      height={SCREEN_WIDTH * 0.05}
                    />

                    <Text
                      style={[styles.location, { lineHeight: 24 }]}
                      numberOfLines={2}
                    >
                      {t('EST_COMPLETION')}:{' '}
                      <Text style={styles.estTimeCompletion}>
                        {estTimeCompletion()}
                      </Text>
                    </Text>
                  </View>

                  {arrayJobs[0]?.weatherData && (
                    <View style={styles.weatherContainer}>
                      <FastImage
                        source={{
                          uri: `https:${arrayJobs[0]?.weatherData?.current?.condition?.icon}`,
                        }}
                        style={styles.weatherIcon}
                      />
                      <Text style={styles.weatherText}>
                        {arrayJobs[0]?.weatherData?.current?.tempF}°F
                      </Text>
                    </View>
                  )}
                </View>
              </View>
              <View style={{ paddingHorizontal: 16 }}>
                <BoxCheckIn job={arrayJobs[0]} />
              </View>

              {arrayJobs?.length > 1 && (
                <View style={styles.checkInButtonContainer}>
                  <Button
                    onPress={() =>
                      NavigationService.navigate(SCREEN_ENUM.TodayJobsScreen)
                    }
                    variant="secondary"
                    style={styles.checkInButton}
                    title={`${t('VIEW_MORE_JOBS')} (${arrayJobs?.length})`}
                    textStyle={styles.seeMoreText}
                  />
                </View>
              )}
            </View>
          ) : (
            <View style={styles.emptyContainer}>
              <Text style={styles.emptyText}>{t('NO_JOBS_TODAY')}</Text>
            </View>
          )}
        </View>
      )}
    </View>
  );
};

export default JobsToday;
