import { StyleSheet, Text, View } from 'react-native';
import { IJobToday } from '../types';
import { colors } from '../../../theme';
import FastImage from 'react-native-fast-image';
import { headerCheckIn } from '../../../assets/images';
import { SCREEN_HEIGHT, SCREEN_WIDTH } from 'tradewize-component';
import { SvgXml } from 'react-native-svg';
import { IconClock, IconLocation } from '../../../assets/svg';
import { useAppTranslation } from '../../../hooks/useAppTranslation';
import { useCallback } from 'react';
import BoxCheckIn from '../../Home/components/JobsToday/BoxCheckIn';

interface ICardItem {
  item: IJobToday;
}

const CardItem = ({ item }: ICardItem) => {
  const { t } = useAppTranslation();

  const estTimeCompletion = useCallback(() => {
    if (item?.estFinish) {
      return `${new Date(item?.estFinish).toLocaleDateString('en-US', {
        month: 'short',
      })} ${new Date(item?.estFinish).getDate()}, ${new Date(
        item?.estFinish,
      ).getFullYear()}`;
    }
    return '';
  }, [item]);

  return (
    <View style={styles.container}>
      <FastImage source={headerCheckIn} style={styles.mapGraphic} />
      <View style={styles.content}>
        <View style={styles.row}>
          <Text style={styles.activityName}>{item?.activityName}</Text>
          <Text style={styles.time}>8:00 AM</Text>
        </View>

        <View style={[styles.row, styles.infoRow, { marginTop: 16 }]}>
          <SvgXml
            xml={IconLocation(colors.red)}
            width={SCREEN_WIDTH * 0.04}
            height={SCREEN_WIDTH * 0.05}
          />
          <Text style={styles.address}>
            {t('LOT')} {item?.lotNumber} - {item?.address}
          </Text>
        </View>

        <View style={[styles.row, styles.infoRow]}>
          <SvgXml
            xml={IconClock(colors.black)}
            width={SCREEN_WIDTH * 0.04}
            height={SCREEN_WIDTH * 0.05}
          />
          <Text style={styles.address}>
            {t('EST_COMPLETION')}: {estTimeCompletion()}
          </Text>
        </View>

        <BoxCheckIn job={item} />
      </View>

      {item?.weatherData && (
        <View style={styles.weatherBadge}>
          <FastImage
            source={{
              uri: `https:${item?.weatherData?.current?.condition?.icon}`,
            }}
            style={styles.weatherIconSmall}
          />
          <Text style={styles.weatherText}>
            {item?.weatherData?.current?.tempF}°F
          </Text>
        </View>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    backgroundColor: colors.white,
    borderRadius: 12,
    borderWidth: 1,
    borderColor: colors.grayScale70,
  },
  content: {
    padding: 16,
  },
  mapGraphic: {
    width: '100%',
    height: SCREEN_HEIGHT * 0.1,
    borderTopLeftRadius: 12,
    borderTopRightRadius: 12,
  },
  row: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  activityName: {
    fontSize: 16,
    fontWeight: 'bold',
    color: colors.black,
  },
  time: {
    fontSize: 14,
    fontWeight: '500',
    color: colors.mainColorPrimary,
    backgroundColor: colors.mainColorQuaternary,
    paddingHorizontal: 8,
    paddingVertical: 4,
    borderRadius: 16,
  },
  infoRow: {
    gap: 8,
    justifyContent: 'flex-start',
  },
  address: {
    fontSize: 14,
    fontWeight: '500',
    color: colors.black,
    flex: 1,
  },
  weatherBadge: {
    position: 'absolute',
    top: 12,
    right: 12,
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: colors.overlayWhite09,
    paddingHorizontal: 8,
    paddingVertical: 4,
    borderRadius: 12,
    gap: 4,
  },
  weatherIconSmall: {
    width: SCREEN_WIDTH * 0.05,
    height: SCREEN_WIDTH * 0.05,
  },
  weatherText: {
    color: colors.black,
    fontSize: 14,
    fontWeight: '500',
  },
});

export default CardItem;
