import {
  ActivityIndicator,
  FlatList,
  RefreshControl,
  Text,
  View,
} from 'react-native';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import { useTabNotification } from '../../../../hooks/useTabNotification';
import { useCallback } from 'react';
import { NotificationItem } from '../../types';
import ItemNotification from '../ItemNotification';
import { colors } from '../../../../theme';
import styles from './styles';

const NotificationTabContent = () => {
  const { t } = useAppTranslation();
  const {
    data,
    isLoading,
    isRefreshing,
    isLoadingMore,
    isMarkingAllRead,
    markingAsReadId,
    onRefresh,
    onLoadMore,
  } = useTabNotification();

  const renderItem = useCallback(
    ({ item }: { item: NotificationItem }) => (
      <ItemNotification item={item} markingAsReadId={markingAsReadId} />
    ),
    [markingAsReadId],
  );

  const items = data?.notifications?.items || [];

  const renderEmpty = useCallback(() => {
    if (isLoading || items.length > 0) {
      return null;
    }
    return (
      <View style={styles.emptyContainer}>
        <Text style={styles.notiEmptyText}>{t('NOTIFICATION_NOT_FOUND')}</Text>
      </View>
    );
  }, [isLoading, items.length, t]);

  const renderFooter = useCallback(() => {
    if (!isLoadingMore) {
      return null;
    }
    return (
      <View style={styles.footerLoading}>
        <ActivityIndicator size="small" color={colors.mainColorPrimary} />
      </View>
    );
  }, [isLoadingMore]);

  const keyExtractor = useCallback((item: NotificationItem) => item.id, []);

  return (
    <View style={styles.container}>
      <FlatList
        data={items}
        renderItem={renderItem}
        keyExtractor={keyExtractor}
        contentContainerStyle={styles.listContent}
        showsVerticalScrollIndicator={false}
        style={styles.list}
        ListEmptyComponent={renderEmpty}
        ListFooterComponent={renderFooter}
        onEndReached={onLoadMore}
        onEndReachedThreshold={0.5}
        refreshControl={
          <RefreshControl
            refreshing={isRefreshing}
            onRefresh={onRefresh}
            colors={[colors.mainColorPrimary]}
            tintColor={colors.mainColorPrimary}
          />
        }
      />

      {(isLoading || isMarkingAllRead) && (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size={'small'} color={colors.mainColorPrimary} />
        </View>
      )}
    </View>
  );
};

export default NotificationTabContent;
