import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { View } from 'react-native';
import { BaseContainer, Button, HeaderBase, Text } from 'tradewize-component';
import { ShadowedView } from 'react-native-fast-shadow';
import { useRoute, RouteProp } from '@react-navigation/native';
import MapView, { Marker, Polyline } from 'react-native-maps';

import { styles } from './styles';
import {
  calculateDistanceInMeters,
  calculateMapRegion,
  DEFAULT_LOCATION,
  formatDistance,
  getMidpoint,
  metersToYards,
  Location,
  Region,
  Coordinates,
} from './utils';
import { shadowGlobal } from '../../../../Auth/src/types/global';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { NavigationService } from '../../services/NavigationService';
import { IJobToday } from '../TodayJobs/types';
import { colors } from '../../theme';
import { AUTO_CHECK_IN_DISTANCE, logger } from '../../utils';
import { getCurrentLocation } from '../../helper';
import dayjs from 'dayjs';
import { useDispatch } from 'react-redux';
import { checkInLocation } from '../../api/endpoint';
import Toast from 'react-native-toast-message';

// Type-safe route params
type YourLocationRouteParams = {
  YourLocation: {
    job: IJobToday;
  };
};

// Component for displaying job info row
const InfoRow = ({
  label,
  value,
  valueStyle,
}: {
  label: string;
  value: string;
  valueStyle?: object;
}) => (
  <View style={styles.row}>
    <Text style={styles.text}>{label}:</Text>
    <Text style={[styles.textContent, valueStyle]}>{value}</Text>
  </View>
);

// Map markers component
const MapMarkers = ({
  jobLocation,
  jobAddress,
  currentLocation,
  yourLocationText,
}: {
  jobLocation: Coordinates | undefined;
  jobAddress: string;
  currentLocation: Location;
  yourLocationText: string;
}) => (
  <>
    {jobLocation && (
      <Marker
        coordinate={jobLocation}
        title={jobAddress || 'Job Location'}
        pinColor={colors.success}
      />
    )}
    {currentLocation.latitude !== 0 && (
      <Marker
        coordinate={currentLocation}
        title={yourLocationText}
        pinColor={colors.mainColorPrimary}
      />
    )}
  </>
);

// Distance line with midpoint marker
const DistanceLine = ({
  currentLocation,
  jobLocation,
  midpoint,
  distanceText,
}: {
  currentLocation: Location;
  jobLocation: Coordinates;
  midpoint: Coordinates;
  distanceText: string;
}) => (
  <>
    <Polyline
      coordinates={[currentLocation, jobLocation]}
      strokeColor={colors.success}
      strokeWidth={3}
    />
    <Marker coordinate={midpoint} anchor={{ x: 0.5, y: 0.5 }}>
      <View style={styles.distanceMarker}>
        <Text style={styles.distanceMarkerText}>{distanceText}</Text>
      </View>
    </Marker>
  </>
);

const YourLocation = () => {
  const route = useRoute<RouteProp<YourLocationRouteParams, 'YourLocation'>>();
  const jobsInfo = route?.params?.job;
  const jobLocation = jobsInfo?.location;
  const dispatch = useDispatch();
  const { t } = useAppTranslation();

  const mapRef = useRef<MapView>(null);
  const [currentLocation, setCurrentLocation] =
    useState<Location>(DEFAULT_LOCATION);
  const [region, setRegion] = useState<Region | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  // Check if current location is valid (not default)
  const hasValidCurrentLocation = currentLocation.latitude !== 0;

  // Memoized distance calculations
  const distanceData = useMemo(() => {
    if (!hasValidCurrentLocation || !jobLocation) {
      return null;
    }

    const distanceInMeters = calculateDistanceInMeters(
      currentLocation.latitude,
      currentLocation.longitude,
      jobLocation.latitude,
      jobLocation.longitude,
    );

    const distanceInYards = metersToYards(distanceInMeters);
    const isWithinCheckInRange = distanceInYards <= AUTO_CHECK_IN_DISTANCE;

    return {
      distanceInMeters,
      distanceInYards,
      distanceText: formatDistance(distanceInMeters, t('MILES'), t('YARDS')),
      isWithinCheckInRange,
      midpoint: getMidpoint(currentLocation, jobLocation),
    };
  }, [currentLocation, jobLocation, hasValidCurrentLocation, t]);

  // Memoized info strings
  const houseInfo = useMemo(() => {
    const communityName = jobsInfo?.communityName || '-';
    const lotNumber = jobsInfo?.lotNumber ? `-${jobsInfo.lotNumber}` : '';
    return `${communityName}${lotNumber}`;
  }, [jobsInfo?.communityName, jobsInfo?.lotNumber]);

  // Fetch current location
  const getLocation = useCallback(async () => {
    try {
      const location = await getCurrentLocation();
      setCurrentLocation(location);
    } catch (error) {
      logger('getCurrentLocation', error);
    }
  }, []);

  const handleCheckIn = async () => {
    try {
      const redux = await import('auth/redux');
      const client = await import('auth/api');
      if (!currentLocation || !jobLocation) return;

      const distanceCheckIn =
        calculateDistanceInMeters(
          currentLocation.latitude,
          currentLocation.longitude,
          jobLocation.latitude,
          jobLocation.longitude,
        ) / 0.9144;

      if (distanceCheckIn > AUTO_CHECK_IN_DISTANCE) {
        return dispatch(
          redux.actionContainer.showAlert({
            type: 'warning',
            title: t('WARNING'),
            message: t('MOVE_CLOSER_TO_CHECK_IN'),
            buttonText: t('OK'),
            onClose: () => {
              dispatch(redux.actionContainer.hideAlert());
            },
          }),
        );
      }

      const id = jobsInfo?.id;
      if (!id) {
        return dispatch(
          redux.actionContainer.showAlert({
            title: t('ERROR'),
            message: t('JOB_ID_IS_MISSING'),
            buttonText: t('OK'),
            onClose: () => {
              dispatch(redux.actionContainer.hideAlert());
            },
          }),
        );
      }

      try {
        setIsLoading(true);
        const body = {
          location: {
            latitude: currentLocation.latitude,
            longitude: currentLocation.longitude,
          },
          locationTimestamp: dayjs().toISOString(),
          purchaseOrderId: id,
        };

        const response = await client.postRequest(checkInLocation, body);
        if (response?.code !== 200) {
          return dispatch(
            redux.actionContainer.showAlert({
              type: 'error',
              title: t('ERROR'),
              message: t('UNABLE_TO_CHECK_IN'),
              buttonText: t('OK'),
              onClose: () => {
                dispatch(redux.actionContainer.hideAlert());
              },
            }),
          );
        }
        dispatch(redux.actionContainer.getMyJobsTodayAsync());
        Toast.show({
          text1: t('CHECKED_IN_SUCCESSFULLY'),
          type: 'success',
        });
        NavigationService.goBack();
      } catch (error) {
        dispatch(
          redux.actionContainer.showAlert({
            type: 'error',
            title: t('ERROR'),
            message: t('UNABLE_TO_CHECK_IN_PLEASE_TRY_AGAIN'),
            buttonText: t('OK'),
            onClose: () => {
              dispatch(redux.actionContainer.hideAlert());
            },
          }),
        );
      } finally {
        setIsLoading(false);
      }
    } catch (error) {
      logger('handleCheckIn', error);
    }
  };

  // Initial load and periodic update every 60 seconds
  useEffect(() => {
    // Get location immediately on mount
    getLocation();

    // Set up interval to update location every 60 seconds
    const intervalId = setInterval(() => {
      getLocation();
    }, 60000); // 60000ms = 60 seconds

    // Cleanup interval on unmount
    return () => {
      clearInterval(intervalId);
    };
  }, [getLocation]);

  // Update region when location data changes
  useEffect(() => {
    if (hasValidCurrentLocation || jobLocation) {
      const newRegion = calculateMapRegion(
        hasValidCurrentLocation ? currentLocation : null,
        jobLocation || null,
      );
      setRegion(newRegion);
    }
  }, [currentLocation, jobLocation, hasValidCurrentLocation]);

  const handleGoBack = useCallback(() => {
    NavigationService.goBack();
  }, []);

  return (
    <BaseContainer style={styles.container}>
      <HeaderBase onPressBack={handleGoBack} title={t('YOUR_LOCATION')} />

      <ShadowedView style={[styles.shadowedView, shadowGlobal]}>
        <InfoRow label={t('ADDRESS')} value={jobsInfo?.address || '-'} />
        <InfoRow label={t('HOUSE')} value={houseInfo} />
        <InfoRow
          label={t('DISTANCE')}
          value={`${distanceData?.distanceText || '-'} ${
            distanceData ? t('AWAY') : ''
          }`}
          valueStyle={{ color: colors.alertColorSuccess }}
        />
      </ShadowedView>

      <View style={styles.mapContainer}>
        {region && (
          <MapView
            ref={mapRef}
            style={styles.map}
            showsUserLocation={true}
            region={region}
            initialRegion={region}
            provider="google"
            showsMyLocationButton={false}
          >
            <MapMarkers
              jobLocation={jobLocation}
              jobAddress={jobsInfo?.address || ''}
              currentLocation={currentLocation}
              yourLocationText={t('YOUR_LOCATION')}
            />
            {distanceData && jobLocation && (
              <DistanceLine
                currentLocation={currentLocation}
                jobLocation={jobLocation}
                midpoint={distanceData.midpoint}
                distanceText={distanceData.distanceText}
              />
            )}
          </MapView>
        )}
      </View>

      <Button
        style={[
          styles.checkinButton,
          isLoading && styles.checkinButtonDisabled,
        ]}
        onPress={handleCheckIn}
        disabled={isLoading}
      >
        <Text style={styles.checkinText}>{t('CHECKIN')}</Text>
      </Button>
    </BaseContainer>
  );
};

export default YourLocation;
