/**
 * Utility functions for YourLocation screen
 * Contains geo calculations that can be reused across the app
 */

export interface Coordinates {
  latitude: number;
  longitude: number;
}

export interface Location extends Coordinates {
  latitudeDelta: number;
  longitudeDelta: number;
}

export type Region = Location;

// Earth radius in meters
const EARTH_RADIUS_METERS = 6371e3;
const METERS_PER_MILE = 1609.34;
const METERS_PER_YARD = 0.9144;
const YARDS_PER_MILE = 1760;

/**
 * Convert degrees to radians
 */
const toRadians = (degrees: number): number => (degrees * Math.PI) / 180;

/**
 * Convert radians to degrees
 */
const toDegrees = (radians: number): number => (radians * 180) / Math.PI;

/**
 * Calculate the geographic midpoint between two coordinates
 * using spherical trigonometry
 */
export const getMidpoint = (p1: Coordinates, p2: Coordinates): Coordinates => {
  const lat1 = toRadians(p1.latitude);
  const lon1 = toRadians(p1.longitude);
  const lat2 = toRadians(p2.latitude);
  const lon2 = toRadians(p2.longitude);

  const dLon = lon2 - lon1;

  const Bx = Math.cos(lat2) * Math.cos(dLon);
  const By = Math.cos(lat2) * Math.sin(dLon);

  const lat3 = Math.atan2(
    Math.sin(lat1) + Math.sin(lat2),
    Math.sqrt((Math.cos(lat1) + Bx) ** 2 + By ** 2),
  );
  const lon3 = lon1 + Math.atan2(By, Math.cos(lat1) + Bx);

  return {
    latitude: toDegrees(lat3),
    longitude: toDegrees(lon3),
  };
};

/**
 * Calculate the distance between two coordinates using the Haversine formula
 * @returns Distance in meters
 */
export const calculateDistanceInMeters = (
  lat1: number,
  lon1: number,
  lat2: number,
  lon2: number,
): number => {
  const φ1 = toRadians(lat1);
  const φ2 = toRadians(lat2);
  const Δφ = toRadians(lat2 - lat1);
  const Δλ = toRadians(lon2 - lon1);

  const a =
    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  return EARTH_RADIUS_METERS * c;
};

/**
 * Convert meters to miles
 */
export const metersToMiles = (meters: number): number =>
  meters / METERS_PER_MILE;

/**
 * Convert meters to yards
 */
export const metersToYards = (meters: number): number =>
  meters / METERS_PER_YARD;

/**
 * Convert yards to miles
 */
export const yardsToMiles = (yards: number): number => yards / YARDS_PER_MILE;

/**
 * Format distance to human-readable string
 * Returns miles if >= 1 mile, otherwise yards
 */
export const formatDistance = (
  distanceInMeters: number,
  milesLabel: string,
  yardsLabel: string,
): string => {
  const distanceInMiles = metersToMiles(distanceInMeters);
  const distanceInYards = metersToYards(distanceInMeters);

  if (distanceInMiles >= 1) {
    return `${distanceInMiles.toFixed(2)} ${milesLabel}`;
  }
  return `${distanceInYards.toFixed(0)} ${yardsLabel}`;
};

/**
 * Calculate the initial region to display both points on the map
 */
export const calculateMapRegion = (
  currentLocation: Coordinates | null,
  jobLocation: Coordinates | null,
  defaultDelta = 0.02,
): Region => {
  if (currentLocation && jobLocation) {
    const latDelta =
      Math.abs(currentLocation.latitude - jobLocation.latitude) * 2.5;
    const lngDelta =
      Math.abs(currentLocation.longitude - jobLocation.longitude) * 2.5;
    return {
      latitude: (currentLocation.latitude + jobLocation.latitude) / 2,
      longitude: (currentLocation.longitude + jobLocation.longitude) / 2,
      latitudeDelta: Math.max(latDelta, defaultDelta),
      longitudeDelta: Math.max(lngDelta, defaultDelta),
    };
  }

  if (jobLocation) {
    return {
      ...jobLocation,
      latitudeDelta: defaultDelta,
      longitudeDelta: defaultDelta,
    };
  }

  if (currentLocation) {
    return {
      ...currentLocation,
      latitudeDelta: defaultDelta,
      longitudeDelta: defaultDelta,
    };
  }

  // Default fallback location (San Francisco)
  return {
    latitude: 37.78825,
    longitude: -122.4324,
    latitudeDelta: defaultDelta,
    longitudeDelta: defaultDelta,
  };
};

/**
 * Default empty location
 */
export const DEFAULT_LOCATION: Location = {
  latitude: 0,
  longitude: 0,
  latitudeDelta: 0,
  longitudeDelta: 0,
};
