import React, { forwardRef, useImperativeHandle, useMemo, useRef } from 'react';
import { Button, Text } from 'tradewize-component';
import { StyleSheet, View } from 'react-native';
import BottomSheet, {
  BottomSheetBackdrop,
  BottomSheetBackdropProps,
  BottomSheetHandleProps,
  BottomSheetScrollView,
} from '@gorhom/bottom-sheet';
import { colors } from '../../../theme';
import { IconCheck, IconClose, IconStar } from '../../../assets/svg';
import { SvgXml } from 'react-native-svg';
import { useAppTranslation } from '../../../hooks/useAppTranslation';

export interface BottomSheetRef {
  open: () => void;
  close: () => void;
}

export interface BottomSheetProps {
  onClose?: () => void;
}

interface CustomHandleProps extends BottomSheetHandleProps {
  onClose?: () => void;
}

const CustomHandle: React.FC<CustomHandleProps> = ({ onClose }) => {
  const { t } = useAppTranslation();
  return (
    <View style={styles.indicatorContainer}>
      <Text style={styles.indicatorText}>{t('ABOUT_THE_SCORE')}</Text>
      <Button style={styles.closeButton} onPress={onClose}>
        <SvgXml xml={IconClose(colors.white)} width={24} height={24} />
      </Button>
    </View>
  );
};

const AboutYourScore = forwardRef<BottomSheetRef, BottomSheetProps>(
  (props, ref) => {
    const snapPoints = useMemo(() => ['85%'], []);
    const bottomSheetRef = useRef<BottomSheet>(null);
    const { t } = useAppTranslation();

    useImperativeHandle(ref, () => ({
      open: () => {
        bottomSheetRef?.current?.snapToIndex(0);
      },
      close: () => {
        bottomSheetRef?.current?.close();
      },
    }));

    const handleClose = () => {
      bottomSheetRef?.current?.close();
      props?.onClose?.();
    };

    return (
      <BottomSheet
        ref={bottomSheetRef}
        index={-1}
        animateOnMount={true}
        enableContentPanningGesture={true}
        enableHandlePanningGesture={true}
        enablePanDownToClose={false}
        enableDynamicSizing={false}
        containerStyle={styles.containerPosition}
        keyboardBehavior="interactive"
        keyboardBlurBehavior="restore"
        snapPoints={snapPoints}
        style={styles.container}
        // eslint-disable-next-line react/no-unstable-nested-components, @typescript-eslint/no-shadow
        backdropComponent={(props: BottomSheetBackdropProps) => (
          <BottomSheetBackdrop
            {...props}
            opacity={0.5}
            appearsOnIndex={0}
            disappearsOnIndex={-1}
            pressBehavior="close"
          />
        )}
        // eslint-disable-next-line react/no-unstable-nested-components, @typescript-eslint/no-shadow
        handleComponent={(props: BottomSheetHandleProps) => (
          <CustomHandle {...props} onClose={handleClose} />
        )}
        bottomInset={24}
        enableOverDrag={false}
      >
        <BottomSheetScrollView contentContainerStyle={styles.contentContainer}>
          {/* On-Time Start */}
          <View style={styles.kpiItem}>
            <Text style={styles.kpiTitle}>{t('1. ON_TIME_START')}</Text>
            <View style={styles.kpiDescriptionRow}>
              <SvgXml
                xml={IconCheck(colors.color2E7D32)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiDescription}>
                {t('THIS_SHOWS_HOW_OFTEN_YOU_START_YOUR_JOB_ON_TIME')}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('IF_YOU_CHECK_IN_LATE_→_YOUR_SCORE_GOES_DOWN')}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('IF_YOU_START_ON_TIME_→_YOUR_SCORE_GOES_UP')}
              </Text>
            </View>
          </View>

          {/* Days Worked per Month */}
          <View style={styles.kpiItem}>
            <Text style={styles.kpiTitle}>{t('2. DAYS_WORKED_PER_MONTH')}</Text>
            <View style={styles.kpiDescriptionRow}>
              <SvgXml
                xml={IconCheck(colors.color2E7D32)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiDescription}>
                {t('THE_NUMBER_OF_DAYS_YOU_WORKED_THIS_MONTH')}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('MORE_DAYS_WORKED_→_HIGHER_SCORE')}
              </Text>
            </View>
          </View>

          {/* No Show to Job */}
          <View style={styles.kpiItem}>
            <Text style={styles.kpiTitle}>{t('3. NO_SHOW_TO_JOB')}</Text>
            <View style={styles.kpiDescriptionRow}>
              <SvgXml
                xml={IconCheck(colors.color2E7D32)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiDescription}>
                {t('HOW_MANY_TIMES_YOU_WERE_SCHEDULED_BUT_DID_NOT_SHOW_UP')}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('NO_SHOWS_REDUCE_YOUR_SCORE')}
              </Text>
            </View>
          </View>

          {/* On-Time Complete */}
          <View style={styles.kpiItem}>
            <Text style={styles.kpiTitle}>{t('4. ON_TIME_COMPLETE')}</Text>
            <View style={styles.kpiDescriptionRow}>
              <SvgXml
                xml={IconCheck(colors.color2E7D32)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiDescription}>
                {t('HOW_OFTEN_YOU_FINISH_YOUR_JOB_ON_TIME')}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('FINISHING_LATE_WILL_LOWER_THE_SCORE')}
              </Text>
            </View>
          </View>

          {/* Average Peer Score */}
          <View style={styles.kpiItem}>
            <Text style={styles.kpiTitle}>{t('5. AVERAGE_PEER_SCORE')}</Text>
            <View style={styles.kpiDescriptionRow}>
              <SvgXml
                xml={IconCheck(colors.color2E7D32)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiDescription}>
                {t('YOUR_RATING_FROM_CO_WORKERS_OR_SUPERVISORS')}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('HIGHER_RATINGS_MEAN_A_BETTER_SCORE')}
              </Text>
            </View>
          </View>

          {/* New Mem Referral */}
          <View style={styles.kpiItem}>
            <Text style={styles.kpiTitle}>{t('6. NEW_MEM_REFERRAL')}</Text>
            <View style={styles.kpiDescriptionRow}>
              <SvgXml
                xml={IconCheck(colors.color2E7D32)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiDescription}>
                {t('POINTS_YOU_EARN_WHEN_SOMEONE_YOU_REFER_JOINS_SUCCESSFULLY')}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('MORE_SUCCESSFUL_REFERRALS_→_MORE_POINTS')}
              </Text>
            </View>
          </View>

          {/* Average Checklist Score */}
          <View style={styles.kpiItem}>
            <Text style={styles.kpiTitle}>
              {t('7. AVERAGE_CHECKLIST_SCORE')}
            </Text>
            <View style={styles.kpiDescriptionRow}>
              <SvgXml
                xml={IconCheck(colors.color2E7D32)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiDescription}>
                {t(
                  'POINTS_YOU_GET_BASED_ON_THE_AVERAGE_QUALITY_INSPECTIONS_SCORES_FOR_A_SPECIFIC_JOB',
                )}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('MORE_QUALITY_JOBS_→_MORE_SCORES')}
              </Text>
            </View>
          </View>

          <View style={styles.kpiItem}>
            <Text style={styles.kpiTitle}>{t('8. BONUS_POINTS')}</Text>
            <View style={styles.kpiDescriptionRow}>
              <SvgXml
                xml={IconCheck(colors.color2E7D32)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiDescription}>
                {t('POINTS_AWARDED_FOR_EXCELLENT_PERFORMANCE')}
              </Text>
            </View>
            <View style={styles.kpiRuleRow}>
              <SvgXml
                xml={IconStar(colors.colorFFD700, 20, 20)}
                width={20}
                height={20}
              />
              <Text style={styles.kpiRule}>
                {t('HIGHER_THE_QUALITY_OF_YOUR_WORK_→_BETTER_YOUR_SCORE')}
              </Text>
            </View>
          </View>
        </BottomSheetScrollView>
      </BottomSheet>
    );
  },
);

