import React from 'react';
import { View } from 'react-native';
import { Button, Text } from 'tradewize-component';
import { SvgXml } from 'react-native-svg';
import { colors } from '../../../../theme';
import {
  IconArrowRight,
  IconPlay,
  IconCheck,
  IconClock,
  IconCalendar,
  IconCompany,
} from '../../../../assets/svg';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import {
  checklistCategory,
  ChecklistItem,
  ChecklistMode,
} from '../../../../types/jobDetail.type';
import ChecklistItemContent from '../ChecklistItemContent';
import { styles } from './styles';

interface CategorySectionProps {
  categoryKey: string;
  categoryEnum: checklistCategory;
  items: ChecklistItem[] | any;
  expandedCategories: { [key: string]: boolean };
  toggleCategory: (key: string) => void;
  mode?: ChecklistMode;
  invalidItemIds?: string[];
  onClearInvalid?: (itemId: string) => void;
  /** Override the category label (used for JOB_START mode) */
  customLabel?: string;
}

const CategoryConfig = {
  [checklistCategory.JobStart]: {
    color: colors.mainColorPrimary,
    icon: IconPlay,
    label: 'JOB_START',
  },
  [checklistCategory.General]: {
    color: colors.mainColorPrimary,
    icon: IconCheck,
    label: 'GENERAL',
  },
  [checklistCategory.EndOfDay]: {
    color: colors.mainColorPrimary,
    icon: IconClock,
    label: 'END_OF_DAY',
  },
  [checklistCategory.Material]: {
    color: colors.mainColorPrimary,
    icon: IconCalendar,
    label: 'MATERIAL',
  },
  [checklistCategory.MaterialDelivery]: {
    color: colors.mainColorPrimary,
    icon: IconCompany,
    label: 'MATERIAL_DELIVERY',
  },
};

const CategorySection: React.FC<CategorySectionProps> = ({
  categoryKey,
  categoryEnum,
  items,
  expandedCategories,
  toggleCategory,
  mode = ChecklistMode.DEFAULT,
  invalidItemIds,
  onClearInvalid,
  customLabel,
}) => {
  const { t } = useAppTranslation();
  const config = CategoryConfig[categoryEnum];

  // Only return null if no config AND no customLabel (allows JOB_START mode)
  if (!config && !customLabel) return null;

  // Safety check: ensure items is an array
  const safeItems = Array.isArray(items) ? items : [];
  const isExpanded = expandedCategories[categoryKey] || false;

  // Determine the label to display
  // Priority: customLabel > categoryName (JOB_READY) > config.label
  const getCategoryLabel = () => {
    // Use customLabel if provided (for JOB_START mode)
    if (customLabel) {
      return t(customLabel);
    }
    // In JOB_READY mode, use categoryName from the first item
    if (mode === ChecklistMode.JOB_READY && safeItems.length > 0) {
      const categoryName = safeItems[0]?.categoryName;
      if (categoryName) {
        return t(categoryName);
      }
    }
    return config?.label ? t(config.label) : t('CHECKLIST');
  };

  return (
    <View style={styles.categoryWrapper}>
      <Button
        variant="ghost"
        style={styles.categoryHeader}
        onPress={() => toggleCategory(categoryKey)}
        activeOpacity={0.7}
      >
        <View style={styles.categoryTitleContainer}>
          <Text
            style={[
              styles.categoryLabel,
              { color: config?.color || colors.mainColorPrimary },
            ]}
          >
            {getCategoryLabel()}
          </Text>
          <View style={[styles.countBadge]}>
            <Text
              style={[
                styles.countText,
                { color: config?.color || colors.mainColorPrimary },
              ]}
            >
              ({safeItems.length})
            </Text>
          </View>
        </View>
        <SvgXml
          xml={IconArrowRight(colors.black)}
          width={16}
          height={16}
          style={isExpanded ? styles.iconRotated : {}}
        />
      </Button>

      {isExpanded && (
        <View style={styles.categoryContent}>
          {safeItems.map(item => (
            <ChecklistItemContent
              key={item.id}
              item={item}
              isInvalid={invalidItemIds?.includes(item.id)}
              onClearInvalid={onClearInvalid}
            />
          ))}
        </View>
      )}
    </View>
  );
};

export default CategorySection;
