import React from 'react';
import { StyleSheet, View } from 'react-native';
import { Button, SCREEN_HEIGHT, SCREEN_WIDTH, Text } from 'tradewize-component';
import { JobToday } from '../../../../types/jobToday.ts';
import { colors } from '../../../../theme/index.tsx';
import { getTimeString } from '../../../../helper/HomeScreen.helper.ts';
import { useAppTranslation } from '../../../../hooks/useAppTranslation.ts';
import { SvgXml } from 'react-native-svg';
import { IconCheck } from '../../../../assets/svg/index.ts';
import { NavigationService } from '../../../../services/NavigationService.ts';
import { SCREEN_ENUM } from '../../../../types/global.ts';

type BoxCheckInProps = {
  job: JobToday;
};

const HEIGHT_BUTTON = SCREEN_HEIGHT * 0.05;

const BoxCheckIn = (props: BoxCheckInProps) => {
  const { t } = useAppTranslation();
  const { job } = props;

  // 1. Nếu không có job
  if (!job || (!job?.needCheckin && !job?.checkInOn)) {
    return null;
  }

  // 2. Nếu đã check-in
  if (job?.checkInOn) {
    return (
      <View style={styles.containerCheckInPass}>
        <View style={styles.checkInButton}>
          <SvgXml
            xml={IconCheck(colors.white)}
            width={SCREEN_WIDTH * 0.04}
            height={SCREEN_WIDTH * 0.04}
          />
          <Text style={[styles.checkInText, styles.checkInTextSuccess]}>
            {t('CHECKIN_SUCCESS')} {getTimeString(job?.checkInOn)}
          </Text>
        </View>
        <Button
          onPress={() =>
            NavigationService.navigate(SCREEN_ENUM.JobDetailScreen, {
              id: job?.id,
              scheduleActivityId: job?.scheduleActivityId,
            })
          }
          style={styles.buttonDetail}
          title={t('DETAILS')}
          textStyle={styles.buttonDetailText}
        />
      </View>
    );
  }

  // 3. Nếu đang check-in (loading)
  //   if (isCheckingIn) {
  //     return <ActivityIndicator size="small" color={colors.mainColorPrimary} />;
  //   }

  //4. Hiển thị nút check-in
  return (
    <View style={styles.containerCheckIn}>
      <Button
        onPress={() =>
          NavigationService.navigate(SCREEN_ENUM.YourLocationScreen, {
            job,
          })
        }
        style={styles.giftImageContainer}
      >
        <Text style={[styles.checkInText, { color: colors.white }]}>
          {t('CHECK_IN')}
        </Text>
      </Button>
      <Button
        style={[styles.buttonDetail, { flex: 1 }]}
        title={t('DETAILS')}
        textStyle={styles.buttonDetailText}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  giftImageContainer: {
    flex: 3,
    height: HEIGHT_BUTTON,
    minHeight: 0,
    paddingVertical: 0,
    backgroundColor: colors.alertColorSuccess,
  },
  giftImage: {
    width: SCREEN_WIDTH * 0.1,
    height: SCREEN_WIDTH * 0.1,
  },
  checkInText: {
    fontSize: 14,
    fontWeight: '500',
    color: colors.black,
    lineHeight: 20,
    letterSpacing: -0.1,
  },
  containerCheckInPass: {
    alignItems: 'center',
    flexDirection: 'row',
    gap: 12,
    marginTop: 12,
  },
  checkInButton: {
    backgroundColor: colors.grayScale60,
    paddingHorizontal: 24,
    borderRadius: 8,
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'center',
    gap: 8,
    flex: 1,
    height: HEIGHT_BUTTON,
  },
  checkInTextSuccess: {
    color: colors.white,
    fontSize: 14,
    fontWeight: '500',
  },
  buttonDetail: {
    backgroundColor: colors.mainColorPrimary,
    height: HEIGHT_BUTTON,
    minHeight: 0,
    paddingVertical: 0,
    paddingHorizontal: 24,
  },
  buttonDetailText: {
    lineHeight: 20,
    fontSize: 14,
    fontWeight: '500',
    color: colors.white,
  },
  containerCheckIn: {
    alignItems: 'center',
    flexDirection: 'row',
    gap: 12,
    marginTop: 12,
  },
});

export default BoxCheckIn;
