import { RouteProp, useRoute } from '@react-navigation/native';
import { useMemo } from 'react';
import { useReferFriendJobDetail } from '../../hooks/useReferFriendJobDetail';
import { BaseContainer, HeaderBase, Text } from 'tradewize-component';
import { useAppTranslation } from '../../hooks/useAppTranslation';
import { styles } from './styles';
import { useDispatch, useSelector } from 'react-redux';
import { FlatList, View } from 'react-native';
import CardItem from './components/CardItem';
import {
  ReferralDetail,
  TransformedJob,
  ReferalCompleteJobDetailParams,
} from './types';
import { NavigationService } from '../../services/NavigationService';
import { logger } from '../../utils';

const transformJobsWithWorkerInfo = (
  details: ReferralDetail[] | undefined,
): TransformedJob[] => {
  if (!details) return [];

  const allJobs: TransformedJob[] = [];

  details.forEach((detail, workerIndex) => {
    detail.jobs.forEach((job, jobIndex) => {
      allJobs.push({
        ...job,
        workerName: detail.name || `Worker ${workerIndex + 1}`,
        uniqueKey: `job-${workerIndex}-${jobIndex}`,
        jobNumber: jobIndex + 1,
      });
    });
  });

  return allJobs;
};

const ReferalCompleteJobDetail = () => {
  const { t } = useAppTranslation();
  const dispatch = useDispatch();

  const referFriendJobDetail = useSelector(
    (state: any) => state.referFriend.referralDetail,
  );
  const isLoading = useSelector(
    (state: any) => state.app.loadingOverlay.isVisible,
  );

  const { params } =
    useRoute<
      RouteProp<
        { ReferalCompleteJobDetail: ReferalCompleteJobDetailParams },
        'ReferalCompleteJobDetail'
      >
    >();

  useReferFriendJobDetail({ jobId: params?.jobId || '' });

  const handleBack = async () => {
    try {
      const redux = await import('auth/redux');
      dispatch(redux.actionContainer.getFriendReferralDetailClear());
      NavigationService.goBack();
    } catch (error) {
      logger('ReferalCompleteJobDetail handleBack error', error);
    }
  };

  // Transform data - chỉ tính lại khi referFriendJobDetail thay đổi
  const allJobs = useMemo(
    () => transformJobsWithWorkerInfo(referFriendJobDetail?.data),
    [referFriendJobDetail?.data],
  );

  const renderEmptyComponent = () => {
    if (isLoading) {
      return null;
    }
    return (
      <View style={styles.noDataContainer}>
        <Text style={styles.noDataText}>{t('NO_JOB_DETAILS_AVAILABLE')}</Text>
      </View>
    );
  };

  return (
    <BaseContainer style={styles.container}>
      <HeaderBase
        titleStyle={styles.headerTitleStyle}
        title={`${params?.jobTitle} - ${t('JOBS_COMPLETED_DETAILS')}`}
        onPressBack={handleBack}
      />

      <FlatList
        data={allJobs}
        renderItem={({ item }) => <CardItem job={item} />}
        keyExtractor={item => item.uniqueKey}
        ListEmptyComponent={renderEmptyComponent}
        showsVerticalScrollIndicator={false}
        contentContainerStyle={styles.flatListContent}
      />
    </BaseContainer>
  );
};

export default ReferalCompleteJobDetail;
