import React, { useCallback } from 'react';
import { View, TextInput } from 'react-native';
import { Button, Text, SCREEN_WIDTH } from 'tradewize-component';
import { colors } from '../../../../theme';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import {
  MaterialStatusOption,
  MATERIAL_STATUS_OPTIONS,
} from '../../../../types/jobStart.type';
import { styles } from './styles';

interface OptionsSectionProps {
  selectedOption: MaterialStatusOption | null;
  onSelectOption: (option: MaterialStatusOption) => void;
  otherReason: string;
  onReasonChange: (reason: string) => void;
  isDisabled?: boolean;
  hasError?: boolean;
  /** Callback when user tries to select a blocked option */
  onDisabledPress?: (option: MaterialStatusOption) => void;
}

/**
 * OptionsSection - Select An Option for Job Start
 *
 * When isDisabled (delivery pending):
 * - CANT_START_OTHER: Always allowed
 * - CANT_START_MISSING: Blocked with specific modal
 * - START_JOB / START_JOB_WITH_MISSING: Blocked with specific modal
 */
const OptionsSection: React.FC<OptionsSectionProps> = ({
  selectedOption,
  onSelectOption,
  otherReason,
  onReasonChange,
  isDisabled = false,
  hasError = false,
  onDisabledPress,
}) => {
  const { t } = useAppTranslation();

  const handleSelectOption = useCallback(
    (option: MaterialStatusOption) => {
      if (isDisabled) {
        // CANT_START_OTHER is always allowed even when disabled
        if (option === MaterialStatusOption.CANT_START_OTHER) {
          onSelectOption(option);
          return;
        }
        // Other options are blocked — notify parent to show modal
        onDisabledPress?.(option);
        return;
      }
      onSelectOption(option);
    },
    [isDisabled, onSelectOption, onDisabledPress],
  );

  /**
   * Check if an option should appear visually disabled
   * Only CANT_START_OTHER remains active when isDisabled
   */
  const isOptionVisuallyDisabled = useCallback(
    (optionId: MaterialStatusOption): boolean => {
      if (!isDisabled) return false;
      return optionId !== MaterialStatusOption.CANT_START_OTHER;
    },
    [isDisabled],
  );

  const showReasonInput =
    selectedOption === MaterialStatusOption.CANT_START_OTHER;

  return (
    <View style={[styles.container, hasError && styles.containerError]}>
      {/* Section Title - centered */}
      <Text style={[styles.sectionTitle, hasError && styles.sectionTitleError]}>
        {t('SELECT_AN_OPTION')}
        {hasError && <Text style={styles.requiredAsterisk}> *</Text>}
      </Text>

      {/* Options - simple card style */}
      <View style={styles.optionsContainer}>
        {MATERIAL_STATUS_OPTIONS.map(option => {
          const isSelected = selectedOption === option.id;
          const isVisuallyDisabled = isOptionVisuallyDisabled(option.id);

          return (
            <Button
              key={option.id}
              style={[
                styles.optionButton,
                isSelected && styles.optionButtonSelected,
                isVisuallyDisabled && styles.optionButtonDisabled,
                hasError && !isSelected && styles.optionButtonError,
              ]}
              onPress={() => handleSelectOption(option.id)}
              activeOpacity={0.7}
            >
              <Text
                style={[
                  styles.optionText,
                  isSelected && styles.optionTextSelected,
                  isVisuallyDisabled && styles.optionTextDisabled,
                ]}
              >
                {t(option.labelKey)}
              </Text>
            </Button>
          );
        })}
      </View>

      {/* Other Reason Input */}
      {showReasonInput && (
        <View style={styles.reasonContainer}>
          <TextInput
            style={styles.reasonInput}
            value={otherReason}
            onChangeText={onReasonChange}
            placeholder={t('ENTER_YOUR_REASON') || 'Enter your reason...'}
            placeholderTextColor={colors.grayScale60}
            multiline
            numberOfLines={3}
            textAlignVertical="top"
          />
        </View>
      )}
    </View>
  );
};

export default OptionsSection;
