import React, { useCallback, useState } from 'react';
import { View } from 'react-native';
import { Button, Text, SCREEN_WIDTH } from 'tradewize-component';
import { SvgXml } from 'react-native-svg';
import { colors } from '../../../../theme';
import { IconArrowRight, IconComment } from '../../../../assets/svg';
import { useAppTranslation } from '../../../../hooks/useAppTranslation';
import { MaterialChecklistItem } from '../../../../types/jobStart.type';
import { getTypeName } from '../../../../helper/jobStart.helper';
import {
  FileThumbnail,
  FileInfo,
  FileViewer,
} from '../../../../components/FileViewer';
import { styles } from './styles';

interface MaterialSectionProps {
  groupedMaterials: Record<string, MaterialChecklistItem[]>;
  onQuantityPress: (materialId: string, maxQuantity: number) => void;
  onCommentPress?: (item: MaterialChecklistItem) => void;
  isReadOnly?: boolean;
  errorMaterialIds?: string[];
  onItemRef?: (materialId: string, ref: View | null) => void;
}

const MaterialSection: React.FC<MaterialSectionProps> = ({
  groupedMaterials,
  onQuantityPress,
  onCommentPress,
  isReadOnly = false,
  errorMaterialIds = [],
  onItemRef,
}) => {
  const { t } = useAppTranslation();

  const groupKeys = Object.keys(groupedMaterials);

  if (groupKeys.length === 0) {
    return null;
  }

  return (
    <View style={styles.container}>
      {groupKeys.map(groupId => {
        const items = groupedMaterials[groupId];
        const typeName = getTypeName(items);
        const itemCount = items.length;

        return (
          <View key={groupId} style={styles.groupContainer}>
            {/* Group Header - No toggle, just title */}
            <Text style={styles.groupTitle}>
              {typeName} ({itemCount})
            </Text>

            {/* Group Items */}
            <View style={styles.itemsContainer}>
              {items.map(item => (
                <MaterialItem
                  key={item.id}
                  item={item}
                  onQuantityPress={onQuantityPress}
                  onCommentPress={onCommentPress}
                  isReadOnly={isReadOnly}
                  hasError={errorMaterialIds.includes(item.id)}
                  onItemRef={onItemRef}
                />
              ))}
            </View>
          </View>
        );
      })}
    </View>
  );
};

// ============================================================================
// Material Item Component
// ============================================================================

interface MaterialItemProps {
  item: MaterialChecklistItem;
  onQuantityPress: (materialId: string, maxQuantity: number) => void;
  onCommentPress?: (item: MaterialChecklistItem) => void;
  isReadOnly?: boolean;
  hasError?: boolean;
  onItemRef?: (materialId: string, ref: View | null) => void;
}

const MaterialItem: React.FC<MaterialItemProps> = ({
  item,
  onQuantityPress,
  onCommentPress,
  isReadOnly = false,
  hasError = false,
  onItemRef,
}) => {
  const { t } = useAppTranslation();

  const totalQuantity = item.verifyMaterial;

  const handleQuantityPress = useCallback(() => {
    if (!isReadOnly) {
      onQuantityPress(item.id, totalQuantity);
    }
  }, [isReadOnly, onQuantityPress, item.id, totalQuantity]);

  const handleCommentPress = useCallback(() => {
    if (onCommentPress) {
      onCommentPress(item);
    }
  }, [onCommentPress, item]);

  // Display values
  const materialName = item.materialName || item.name;
  const hasQuantitySave = item.quantitySave !== null && item.quantitySave !== undefined;
  const missingCount = hasQuantitySave
    ? totalQuantity - (item.quantitySave ?? 0)
    : 0;

  // Responses (comment + files history) - same pattern as ChecklistItemContent
  const responsesList = item.responses || [];
  const hasResponses = responsesList.length > 0;
  const [selectedFile, setSelectedFile] = useState<FileInfo | null>(null);

  const handleMediaPress = useCallback((file: FileInfo) => {
    setSelectedFile(file);
  }, []);

  const handleCloseViewer = useCallback(() => {
    setSelectedFile(null);
  }, []);

  // Render responses - identical to ChecklistItemContent
  const renderResponses = () => {
    if (!hasResponses) return null;

    return (
      <View style={styles.responsesContainer}>
        {responsesList.map((response: any, responseIndex: number) => {
          const responseFiles = response.fileEntities || [];

          return (
            <View key={responseIndex} style={styles.responseItem}>
              {/* User name */}
              <Text style={styles.responseUserName}>
                {response.createdName || 'Unknown'}
              </Text>

              {/* Comment text */}
              {response.comment && (
                <Text style={styles.responseComment}>{response.comment}</Text>
              )}

              {/* User's media */}
              {responseFiles.length > 0 && (
                <View style={styles.responseMediaContainer}>
                  {responseFiles.map((file: any, idx: number) => {
                    const fileInfo: FileInfo = {
                      ...file,
                      uri: file.url || file.fileUrl,
                      type: file.fileExtension === '.mp4' ? 'video' : 'file',
                      name: file.fileName || file.name,
                    };

                    return (
                      <FileThumbnail
                        key={`${file.id || idx}`}
                        file={fileInfo}
                        size="medium"
                        onPress={() => handleMediaPress(fileInfo)}
                        readOnly
                      />
                    );
                  })}
                </View>
              )}
            </View>
          );
        })}
      </View>
    );
  };

  // Build info lines like in the design
  const sizeUmLine = `${item.size ? `${t('SIZE')}: ${item.size}` : ''}${item.size && item.unitTypeName ? ' - ' : ''}${item.unitTypeName ? `${t('U_M')}: ${item.unitTypeName}` : ''}`;
  const measurementsLine = item.measurements ? `${t('TRUE_MEASUREMENTS')}: ${item.measurements}` : null;

  // Ref callback to register with parent
  const refCallback = useCallback(
    (node: View | null) => {
      if (onItemRef) {
        onItemRef(item.id, node);
      }
    },
    [onItemRef, item.id],
  );

  return (
    <View ref={refCallback} style={styles.itemContainer}>
      {/* Header row: Material name + Comment icon */}
      <View style={styles.itemHeader}>
        <Text style={styles.materialName} numberOfLines={2}>
          {materialName}
        </Text>
        <Button
          style={styles.commentButton}
          onPress={handleCommentPress}
          activeOpacity={0.7}
        >
          <SvgXml
            xml={IconComment(colors.mainColorPrimary)}
            width={SCREEN_WIDTH * 0.06}
            height={SCREEN_WIDTH * 0.06}
          />
        </Button>
      </View>

      {/* Material Details */}
      <Text style={styles.detailText}>
        <Text style={styles.detailBold}>
          {t('QUANTITY')}: {totalQuantity}
        </Text>
        {item.colorName ? ` - ${t('COLOR')}: ${item.colorName}` : ''}
      </Text>
      {sizeUmLine && <Text style={styles.detailText}>{sizeUmLine}</Text>}
      {measurementsLine && (
        <Text style={styles.detailText}>{measurementsLine}</Text>
      )}

      {/* User Responses */}
      {renderResponses()}

      {/* Received Quantity Selector */}
      <View
        style={[
          styles.receivedContainer,
          hasError && styles.receivedContainerError,
        ]}
      >
        <Text style={styles.receivedLabel}>
          {t('RECEIVED')}
          <Text style={styles.requiredAsterisk}>(*)</Text>
        </Text>
        <Button
          style={[
            styles.receivedButton,
            isReadOnly && styles.receivedButtonReadOnly,
            hasError && styles.receivedButtonError,
          ]}
          onPress={handleQuantityPress}
          disabled={isReadOnly}
          activeOpacity={0.7}
        >
          <Text
            style={[
              styles.receivedButtonText,
              hasQuantitySave && styles.receivedButtonTextSelected,
              hasError && styles.receivedButtonTextError,
            ]}
          >
            {hasQuantitySave
              ? item.quantitySave
              : t('PLEASE_SELECT_RECEIVED_NUMBER')}
          </Text>
          <SvgXml
            xml={IconArrowRight(
              hasError ? colors.alertColorError : colors.grayScale70,
            )}
            width={SCREEN_WIDTH * 0.04}
            height={SCREEN_WIDTH * 0.04}
            style={styles.dropdownIcon}
          />
        </Button>
      </View>

      {/* Missing count - use quantityMissing from API/state directly */}
      {item.quantityMissing !== null &&
        item.quantityMissing !== undefined &&
        item.quantityMissing !== 0 && (
          <Text style={styles.missingText}>
            {t('MISSING')}: {item.quantityMissing}
          </Text>
        )}

      {/* File Viewer */}
      {selectedFile && (
        <FileViewer
          visible={!!selectedFile}
          onClose={handleCloseViewer}
          file={selectedFile}
        />
      )}
    </View>
  );
};

export default MaterialSection;
